async function send(res, status, data, headers = {}) {
  res.writeHead(status, headers);
  res.end(data);
}

/* Ajoute "; Secure" aux cookies uniquement quand la requête est réellement en HTTPS
   (production Vercel via x-forwarded-proto, ou TLS direct) — sinon le navigateur
   refuse purement et simplement de poser le cookie, ce qui casserait la connexion
   en développement local (http://localhost). */
function cookieSecureFlag(req) {
  const proto = req.headers["x-forwarded-proto"] || (req.socket && req.socket.encrypted ? "https" : "http");
  return proto === "https" ? "; Secure" : "";
}

async function sendJSON(res, status, obj, extraHeaders = {}) {
  send(res, status, JSON.stringify(obj), { "Content-Type": "application/json; charset=utf-8", ...extraHeaders });
}

async function readBody(req) {
  // Idempotent : si le corps a déjà été bufferisé (cold-start Vercel), on le retourne directement
  if (req._bodyPromise) return req._bodyPromise;
  // Certains chemins envoient des médias en base64 (atelier, messages vocaux/pièces jointes) → plafond élargi
  const u = req.url || "";
  const bigPath = u.startsWith("/api/atelier/upload") || /^\/api\/conversations\/\d+\/messages$/.test(u);
  const maxBody = bigPath ? (u.includes("/atelier/") ? 300e6 : 25e6) : 1e6;
  req._bodyPromise = new Promise((resolve, reject) => {
    let body = "";
    req.on("data", (chunk) => {
      body += chunk;
      if (body.length > maxBody) req.destroy();
    });
    req.on("end", () => {
      if (!body) return resolve({});
      try { resolve(JSON.parse(body)); } catch (e) { resolve({}); }
    });
    req.on("error", reject);
  });
  return req._bodyPromise;
}

async function getCurrentUser(req) {
  const cookies = parseCookies(req);
  /* 1. Token stateless signé (résiste aux cold starts Vercel) */
  const authCookie = cookies.auth;
  if (authCookie) {
    const payload = verifyAuthToken(authCookie);
    if (payload?.uid) {
      const user = await db.prepare("SELECT id, nom, prenom, email, role, ville, pays, profil_json, photo_url, email_verifie, nb_connexions, temoignage_statut, temoignage_derniere_demande, demo_vue, da_id, identite_verifiee FROM users WHERE id = ?").get(payload.uid);
      if (user) { user.id = Number(user.id); return user; }
    }
  }
  /* 2. Session DB classique (fallback) */
  const sid = cookies.sid;
  if (!sid) return null;
  const session = getSession(sid);
  if (!session) return null;
  const user = await db.prepare("SELECT id, nom, prenom, email, role, ville, pays, profil_json, photo_url, email_verifie, nb_connexions, temoignage_statut, temoignage_derniere_demande, demo_vue, da_id, identite_verifiee FROM users WHERE id = ?").get(session.userId);
  if (user) user.id = Number(user.id);
  return user || null;
}

function publicUser(u) {
  if (!u) return null;
  return { id: Number(u.id), nom: u.nom, prenom: u.prenom, email: u.email, role: u.role, ville: u.ville, pays: u.pays, profil: safeParse(u.profil_json),
    photo_url: u.photo_url || null,
    nb_connexions: u.nb_connexions || 0, temoignage_statut: u.temoignage_statut || 'non_demande', temoignage_derniere_demande: u.temoignage_derniere_demande || null,
    demo_vue: u.demo_vue || 0, da_id: u.da_id || null, email_verifie: !!u.email_verifie, identite_verifiee: !!u.identite_verifiee };
  // NOTE: ds_id est intentionnellement exclu — jamais exposé via cette fonction
}

function safeParse(s) {
  try { return JSON.parse(s || "{}"); } catch (e) { return {}; }
}
function safeJSON(s, fallback) {
  try { return JSON.parse(s || JSON.stringify(fallback)); } catch (e) { return fallback; }
}

