const routes = [];
async function route(method, pattern, handler) {
  const keys = [];
  const regex = new RegExp("^" + pattern.replace(/:[^/]+/g, (m) => { keys.push(m.slice(1)); return "([^/]+)"; }) + "$");
  routes.push({ method, regex, keys, handler });
}

route("POST", "/api/auth/signup", async (req, res, params, body) => {
  /* ── Anti-bot (sans dépendance externe) ──
     1) Honeypot : champ caché "site_perso" que les humains laissent vide.
     2) Délai minimum : un bot remplit/soumet le formulaire en <2s, un humain non.
     3) Rate-limit IP : évite la création de comptes en masse. */
  const ip = SEC.clientIp(req);
  if (body.site_perso) {
    SEC.logSecurity("signup_honeypot", { ip });
    return sendJSON(res, 400, { error: "Requête invalide." });
  }
  const renderedAt = Number(body._form_ts) || 0;
  if (renderedAt && (Date.now() - renderedAt) < 2000) {
    SEC.logSecurity("signup_too_fast", { ip, ms: Date.now() - renderedAt });
    return sendJSON(res, 400, { error: "Veuillez réessayer dans quelques secondes." });
  }
  const ipSignupLimit = SEC.rateLimit(`signup:ip:${ip}`, 5, 3600000);
  if (!ipSignupLimit.allowed) {
    SEC.logSecurity("signup_ratelimited", { ip });
    return sendJSON(res, 429, { error: `Trop d'inscriptions depuis cette connexion. Réessayez dans ${ipSignupLimit.retryAfter}s.` });
  }

  const {
    nom, prenom, email, password, role,
    date_naissance, nationalite1, nationalite2, nationalite3,
    pays, region, departement, ville, adresse, code_postal, telephone,
    centres_interet, situation_pro,
    // initiative
    type_org, description, domaine, objectifs,
    nom_responsable, prenom_responsable, fonction_responsable, email_responsable, tel_responsable,
    site_web, reseaux_sociaux, pays_intervention,
    // collectivite (legacy)
    type_institution, nom_institution, pays_concerne, telephone_pro, site_officiel,
    // collectivite étatique — section 1 (institution)
    type_organisme, sigle_institution, description_institution,
    date_creation_institution, devise_institution, logo_url,
    // collectivite étatique — section 2 (pays d'origine)
    pays_origine_institution, ministere_tutelle, administration_rattachement, region_origine,
    // collectivite étatique — section 3 (pays d'exercice)
    pays_exercice, region_exercice, departement_exercice, ville_exercice,
    adresse_exercice, code_postal_exercice, coordonnees_gps, horaires_ouverture, site_local,
    tel_secondaire, email_officiel, email_secondaire,
    facebook_officiel, twitter_officiel, linkedin_officiel, youtube_officiel, instagram_officiel,
    tiktok_officiel, whatsapp_officiel, telegram_officiel,
    // collectivite étatique — section 4 (responsable)
    nom_responsable_etatique, prenom_responsable_etatique, fonction_responsable_etatique,
    email_responsable_etatique, tel_responsable_etatique,
    service_direction_responsable, adresse_pro_responsable,
    date_prise_fonction, date_fin_mandat,
    declaration_officielle, statut_etatique
  } = body;

  if (!nom || !email || !password || !role) return sendJSON(res, 400, { error: "Champs requis manquants (nom, email, password, role)." });
  /* Sécurité : le rôle "administrateur" ne peut PAS être créé via l'inscription publique.
     Un admin ne peut être promu que manuellement en base (ou par un admin existant). */
  if (!["utilisateur", "initiative", "collectivite"].includes(role)) return sendJSON(res, 400, { error: "Rôle invalide." });
  if (!SEC.isValidEmail(email)) return sendJSON(res, 400, { error: "Adresse e-mail invalide." });
  if (password.length < 8) return sendJSON(res, 400, { error: "Le mot de passe doit comporter au moins 8 caractères." });

  const emailNorm = SEC.normalizeEmail(email);
  /* Anti-doublon insensible à la casse (empêche 2 comptes ne différant que par la casse). */
  const existing = await db.prepare("SELECT id FROM users WHERE LOWER(email) = ?").get(emailNorm);
  if (existing) return sendJSON(res, 409, { error: "Un compte existe déjà avec cet e-mail." });

  const { hash, salt } = hashPassword(password);

  const statutVerif = role === "utilisateur" ? "auto" : "en_attente";

  const id = (await db.prepare(`
    INSERT INTO users (nom, prenom, email, password_hash, password_salt, role,
      ville, pays, region, departement, adresse, code_postal, telephone, date_naissance,
      nationalite1, nationalite2, nationalite3,
      centres_interet, situation_pro, type_institution, statut_verification)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    nom, prenom || null, emailNorm, hash, salt, role,
    ville || null, (role === "collectivite" ? pays_concerne : pays) || null,
    region || null, departement || null,
    adresse || null, code_postal || null, (telephone || telephone_pro) || null,
    date_naissance || null,
    nationalite1 || null, nationalite2 || null, nationalite3 || null,
    JSON.stringify(Array.isArray(centres_interet) ? centres_interet : []),
    situation_pro || null,
    type_institution || null,
    statutVerif
  )).lastInsertRowid;

  // Assigner le DA-ID à l'utilisateur
  try { await db.prepare('UPDATE users SET da_id=? WHERE id=?').run(generateDaId(), id); } catch (_) {}
  // 🥇 Découverte Premium : 30 jours d'accès Premium offerts automatiquement à la création du compte
  await accorderDecouvertePremium(id, role);
  // Réseau Pro : quelques listes par défaut, entièrement modifiables/supprimables ensuite
  try {
    const LISTES_DEFAUT = [
      ["Correspondants", "🤝"], ["Partenaires", "🏢"], ["Prospects", "🎯"], ["Collaborateurs", "👥"],
    ];
    LISTES_DEFAUT.forEach(([nomListe, icone], i) => {
      db.prepare("INSERT INTO listes_diffusion (proprietaire_id, nom, icone, ordre) VALUES (?,?,?,?)").run(id, nomListe, icone, i);
    });
  } catch (_) {}
  // Profil public enrichi : publics/besoins facultatifs du formulaire d'inscription
  try {
    if (Array.isArray(body.publics) && body.publics.length) await db.prepare('UPDATE users SET publics_json=? WHERE id=?').run(JSON.stringify(body.publics), id);
    if (Array.isArray(body.besoins) && body.besoins.length) await db.prepare('UPDATE users SET besoins_json=? WHERE id=?').run(JSON.stringify(body.besoins), id);
  } catch (_) {}

  // Pour un compte Initiative : créer l'enregistrement d'initiative associé
  if (role === "initiative") {
    const slug = nom.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") + "-" + id;
    db.prepare(`
      INSERT INTO initiatives (slug, nom, type, description, domaine, objectifs,
        pays, region, ville, adresse, code_postal, site_web, reseaux_sociaux,
        nationalite1, nationalite2,
        pays_intervention, nom_responsable, prenom_responsable, fonction_responsable,
        email_responsable, tel_responsable, owner_user_id, abonnement_actif)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0)
    `).run(
      slug, nom_institution || nom, type_org || null, description || null, domaine || null, objectifs || null,
      pays || null, region || null, ville || null, adresse || null, code_postal || null,
      site_web || null,
      typeof reseaux_sociaux === "object" ? JSON.stringify(reseaux_sociaux) : (reseaux_sociaux || "{}"),
      nationalite1 || null, nationalite2 || null,
      JSON.stringify(Array.isArray(pays_intervention) ? pays_intervention : []),
      nom_responsable || nom || null, prenom_responsable || prenom || null,
      fonction_responsable || null, email_responsable || email,
      tel_responsable || telephone || null,
      id
    );
    // Assigner DA-ID à l'initiative aussi
    const initRow = await db.prepare('SELECT id FROM initiatives WHERE owner_user_id=? ORDER BY id DESC LIMIT 1').get(id);
    if (initRow) try { await db.prepare('UPDATE initiatives SET da_id=? WHERE id=?').run(generateDaId(), initRow.id); } catch(_) {}
    // Profil public enrichi : champs facultatifs du formulaire d'inscription
    if (initRow) try {
      await db.prepare('UPDATE initiatives SET publics_json=?, besoins_json=?, annee_creation=? WHERE id=?').run(
        Array.isArray(body.publics) && body.publics.length ? JSON.stringify(body.publics) : null,
        Array.isArray(body.besoins) && body.besoins.length ? JSON.stringify(body.besoins) : null,
        body.annee_creation ? parseInt(body.annee_creation) || null : null,
        initRow.id);
    } catch(_) {}
  }

  // ── Champs étendus Compte Étatique (4 sections) ──
  if (role === "collectivite") {
    const paysEffectif = pays_exercice || pays_concerne || pays || null;
    const villeEffective = ville_exercice || ville || null;
    const fields = {
      // Section 1 — Institution
      type_organisme: type_organisme || type_institution || null,
      sigle_institution: sigle_institution || null,
      description_institution: description_institution || null,
      date_creation_institution: date_creation_institution || null,
      devise_institution: devise_institution || null,
      logo_url: logo_url || null,
      site_officiel: site_officiel || null,
      // Section 2 — Pays d'origine
      pays_origine_institution: pays_origine_institution || null,
      ministere_tutelle: ministere_tutelle || null,
      administration_rattachement: administration_rattachement || null,
      region_origine: region_origine || null,
      // Section 3 — Pays d'exercice
      pays: paysEffectif,
      pays_exercice: pays_exercice || null,
      region: region_exercice || region || null,
      region_exercice: region_exercice || null,
      departement: departement_exercice || departement || null,
      departement_exercice: departement_exercice || null,
      ville: villeEffective,
      ville_exercice: ville_exercice || null,
      adresse: adresse_exercice || adresse || null,
      adresse_exercice: adresse_exercice || null,
      code_postal: code_postal_exercice || code_postal || null,
      code_postal_exercice: code_postal_exercice || null,
      coordonnees_gps: coordonnees_gps || null,
      horaires_ouverture: horaires_ouverture || null,
      site_local: site_local || null,
      telephone: telephone || null,
      tel_secondaire: tel_secondaire || null,
      email_officiel: email_officiel || null,
      email_secondaire: email_secondaire || null,
      facebook_officiel: facebook_officiel || null,
      twitter_officiel: twitter_officiel || null,
      linkedin_officiel: linkedin_officiel || null,
      youtube_officiel: youtube_officiel || null,
      instagram_officiel: instagram_officiel || null,
      tiktok_officiel: tiktok_officiel || null,
      whatsapp_officiel: whatsapp_officiel || null,
      telegram_officiel: telegram_officiel || null,
      // Section 4 — Responsable
      nom_responsable_etatique: nom_responsable_etatique || nom || null,
      prenom_responsable_etatique: prenom_responsable_etatique || prenom || null,
      fonction_responsable_etatique: fonction_responsable_etatique || null,
      email_responsable_etatique: email_responsable_etatique || email || null,
      tel_responsable_etatique: tel_responsable_etatique || null,
      service_direction_responsable: service_direction_responsable || null,
      adresse_pro_responsable: adresse_pro_responsable || null,
      date_prise_fonction: date_prise_fonction || null,
      date_fin_mandat: date_fin_mandat || null,
      declaration_officielle: declaration_officielle ? 1 : 0,
      statut_etatique: statut_etatique || 'declare',
    };
    const setCols = Object.keys(fields).map(k => `${k}=?`).join(',');
    await db.prepare(`UPDATE users SET ${setCols} WHERE id=?`).run(...Object.values(fields), id);
  }

  // ── Abonnement obligatoire au compte officiel Diaspo'Actif ──
  const officialId = await getOfficialUserId();
  if (officialId && Number(id) !== Number(officialId)) {
    db.prepare("INSERT OR IGNORE INTO user_follows (follower_id, followed_id) VALUES (?,?)").run(Number(id), officialId);
  }

  const token = createSession(id);
  const user = await db.prepare("SELECT id, nom, prenom, email, role, ville, pays, statut_verification, email_verifie FROM users WHERE id = ?").get(id);
  const authTok = signAuthToken({ uid: id, role: user.role, exp: Math.floor(Date.now()/1000) + TOKEN_TTL });

  // Email de bienvenue (non bloquant)
  try {
    const { emailBienvenue } = require("./mailer");
    emailBienvenue({ prenom: user.prenom || user.nom, email: user.email, role: user.role, nom_institution: nom_institution || null });
  } catch (_) {}

  // Email de vérification d'adresse (non bloquant — soft gate, ne bloque pas la connexion)
  try {
    const verifToken = crypto.randomBytes(32).toString("hex");
    const verifExpires = Date.now() + 24 * 3600000; // 24h
    await db.prepare("UPDATE users SET email_verif_token=?, email_verif_expires=? WHERE id=?").run(verifToken, verifExpires, id);
    const { emailVerification } = require("./mailer");
    emailVerification({ email: user.email, prenom: user.prenom || user.nom, token: verifToken });
  } catch (_) {}

  { const sf = cookieSecureFlag(req); sendJSON(res, 201, { user: publicUser(user) }, { "Set-Cookie": [`sid=${token}; HttpOnly; Path=/; SameSite=Lax${sf}`, `auth=${authTok}; HttpOnly; Path=/; SameSite=Lax; Max-Age=${TOKEN_TTL}${sf}`] }); }
});

/* Anti brute-force PERSISTANT (survit aux cold starts serverless, contrairement à SEC.rateLimit
   qui vit uniquement en mémoire). Compte les tentatives échouées récentes pour une clé donnée
   (ip:xxx ou email:xxx) dans la table auth_tentatives. */
async function dbLoginGuard(cle, maxEchecs, windowMs) {
  const since = new Date(Date.now() - windowMs).toISOString().slice(0, 19).replace("T", " ");
  const row = await db.prepare("SELECT COUNT(*) AS n, MIN(created_at) AS plus_ancien FROM auth_tentatives WHERE cle=? AND reussite=0 AND created_at >= ?").get(cle, since);
  const n = row?.n || 0;
  if (n >= maxEchecs) {
    const retryAfter = Math.max(1, Math.ceil((new Date(row.plus_ancien).getTime() + windowMs - Date.now()) / 1000));
    return { allowed: false, retryAfter };
  }
  return { allowed: true };
}
async function dbLoginRecord(cle, reussite) {
  try {
    await db.prepare("INSERT INTO auth_tentatives (cle, reussite) VALUES (?,?)").run(cle, reussite ? 1 : 0);
    // Purge paresseuse (1 requête sur ~50) pour éviter la croissance illimitée de la table.
    if (Math.random() < 0.02) db.prepare("DELETE FROM auth_tentatives WHERE created_at < datetime('now','-2 days')").run();
  } catch (_) {}
}

route("POST", "/api/auth/login", async (req, res, params, body) => {
  const ip = SEC.clientIp(req);
  const email = SEC.normalizeEmail(body.email);
  const password = body.password || "";

  /* Anti brute-force : rate-limit mémoire (best-effort, rapide) + garde persistante en base
     (fiable même après un cold start serverless) — par IP puis par compte, fenêtre 15 min. */
  const ipLimit = SEC.rateLimit(`login:ip:${ip}`, 20, 15 * 60 * 1000);
  if (!ipLimit.allowed) {
    SEC.logSecurity("login_ratelimited", { ip, scope: "ip_memoire" });
    return sendJSON(res, 429, { error: `Trop de tentatives. Réessayez dans ${ipLimit.retryAfter}s.` });
  }
  const emailLimit = SEC.rateLimit(`login:email:${email}`, 8, 15 * 60 * 1000);
  if (!emailLimit.allowed) {
    SEC.logSecurity("login_ratelimited", { ip, email, scope: "email_memoire" });
    return sendJSON(res, 429, { error: `Trop de tentatives sur ce compte. Réessayez dans ${emailLimit.retryAfter}s.` });
  }
  const ipGuard = await dbLoginGuard(`ip:${ip}`, 20, 15 * 60 * 1000);
  if (!ipGuard.allowed) {
    SEC.logSecurity("login_ratelimited", { ip, scope: "ip_persistant" });
    return sendJSON(res, 429, { error: `Trop de tentatives. Réessayez dans ${ipGuard.retryAfter}s.` });
  }
  const emailGuard = await dbLoginGuard(`email:${email}`, 8, 15 * 60 * 1000);
  if (!emailGuard.allowed) {
    SEC.logSecurity("login_ratelimited", { ip, email, scope: "email_persistant" });
    return sendJSON(res, 429, { error: `Trop de tentatives sur ce compte. Réessayez dans ${emailGuard.retryAfter}s.` });
  }

  if (!email || !password) return sendJSON(res, 400, { error: "E-mail et mot de passe requis." });

  /* Recherche insensible à la casse (ne casse aucun compte existant). */
  const user = await db.prepare("SELECT * FROM users WHERE LOWER(email) = ?").get(email);
  if (!user || !verifyPassword(password, user.password_salt, user.password_hash)) {
    SEC.logSecurity("login_failed", { ip, email });
    dbLoginRecord(`ip:${ip}`, false);
    dbLoginRecord(`email:${email}`, false);
    return sendJSON(res, 401, { error: "E-mail ou mot de passe incorrect." });
  }
  dbLoginRecord(`ip:${ip}`, true);
  dbLoginRecord(`email:${email}`, true);
  db.prepare("UPDATE users SET nb_connexions = COALESCE(nb_connexions,0) + 1 WHERE id=?").run(user.id);
  const fresh = await db.prepare("SELECT * FROM users WHERE id=?").get(user.id);
  const token = createSession(user.id);
  const authTok = signAuthToken({ uid: user.id, role: user.role, exp: Math.floor(Date.now()/1000) + TOKEN_TTL });
  SEC.logSecurity("login_success", { ip, email, uid: Number(user.id), role: user.role });
  { const sf = cookieSecureFlag(req); sendJSON(res, 200, { user: publicUser(fresh) }, { "Set-Cookie": [`sid=${token}; HttpOnly; Path=/; SameSite=Lax${sf}`, `auth=${authTok}; HttpOnly; Path=/; SameSite=Lax; Max-Age=${TOKEN_TTL}${sf}`] }); }
});

/* POST /api/auth/forgot-password — demande de réinitialisation */
route("POST", "/api/auth/forgot-password", async (req, res, params, body) => {
  const { email } = body;
  if (!email) return sendJSON(res, 400, { error: "Email requis" });
  const user = await db.prepare("SELECT id, email, prenom, nom FROM users WHERE email=?").get(email.toLowerCase().trim());
  // Toujours répondre OK pour ne pas révéler si l'email existe
  if (!user) return sendJSON(res, 200, { ok: true });
  const token = require("node:crypto").randomBytes(32).toString("hex");
  const expires = Date.now() + 3600000; // 1 heure
  await db.prepare("UPDATE users SET reset_token=?, reset_expires=? WHERE id=?").run(token, expires, user.id);
  try {
    const { emailResetPassword } = require("./mailer");
    await emailResetPassword({ email: user.email, token });
  } catch(e) { console.error("[forgot-password] email error:", e.message); }
  sendJSON(res, 200, { ok: true });
});

/* POST /api/auth/reset-password — changement du mot de passe */
route("POST", "/api/auth/reset-password", async (req, res, params, body) => {
  const { token, password } = body;
  if (!token || !password) return sendJSON(res, 400, { error: "Token et mot de passe requis" });
  if (password.length < 8) return sendJSON(res, 400, { error: "Le mot de passe doit comporter au moins 8 caractères" });
  const user = await db.prepare("SELECT id, reset_token, reset_expires FROM users WHERE reset_token=?").get(token);
  if (!user) return sendJSON(res, 400, { error: "Lien invalide ou expiré" });
  if (Date.now() > user.reset_expires) return sendJSON(res, 400, { error: "Lien expiré, veuillez faire une nouvelle demande" });
  const { hash, salt } = hashPassword(password);
  await db.prepare("UPDATE users SET password_hash=?, password_salt=?, reset_token=NULL, reset_expires=NULL WHERE id=?").run(hash, salt, user.id);
  sendJSON(res, 200, { ok: true });
});

/* POST /api/auth/verify-email — confirme une adresse e-mail via token */
route("POST", "/api/auth/verify-email", async (req, res, params, body) => {
  const { token } = body;
  if (!token) return sendJSON(res, 400, { error: "Token requis" });
  const user = await db.prepare("SELECT id, email_verif_expires FROM users WHERE email_verif_token=?").get(token);
  if (!user) return sendJSON(res, 400, { error: "Lien invalide ou déjà utilisé." });
  if (Date.now() > Number(user.email_verif_expires)) return sendJSON(res, 400, { error: "Lien expiré. Demandez un nouvel envoi depuis votre compte." });
  await db.prepare("UPDATE users SET email_verifie=1, email_verif_token=NULL, email_verif_expires=NULL WHERE id=?").run(user.id);
  sendJSON(res, 200, { ok: true });
});

/* GET /api/admin/error-logs — journal d'erreurs serveur (monitoring maison) */
route("GET", "/api/admin/error-logs", async (req, res, params, body, query) => {
  const me = await getCurrentUser(req);
  if (!me || me.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });
  const filtre = query.statut === "resolu" ? "WHERE resolu=1" : query.statut === "actif" ? "WHERE resolu=0" : "";
  const logs = await db.prepare(`SELECT * FROM error_logs ${filtre} ORDER BY id DESC LIMIT 100`).all();
  const stats = {
    total_24h: (await db.prepare(`SELECT COUNT(*) n FROM error_logs WHERE created_at >= datetime('now','-1 day')`).get())?.n,
    non_resolues: (await db.prepare(`SELECT COUNT(*) n FROM error_logs WHERE resolu=0`).get())?.n,
  };
  sendJSON(res, 200, { logs, stats });
});

