const TYPE_PAR_ROLE = { utilisateur: "Utilisateur", initiative: "Initiative", administrateur: "Compte Étatique", collectivite: "Compte Étatique" };

route("POST", "/api/fil", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise pour publier." });

  const pub_type = body.pub_type || "texte";
  const contenu  = (body.contenu || "").trim();
  const article_titre   = (body.article_titre || "").trim();
  const article_contenu = (body.article_contenu || "").trim();
  const statut   = body.statut || "publie"; // publie | brouillon | archive
  const visibilite = body.visibilite || "public";
  const medias   = body.medias ? (typeof body.medias === "string" ? body.medias : JSON.stringify(body.medias)) : "[]";
  const hashtags = body.hashtags ? (typeof body.hashtags === "string" ? body.hashtags : JSON.stringify(body.hashtags)) : "[]";

  if (statut === "publie") {
    if (!contenu && !article_titre) return sendJSON(res, 400, { error: "Le contenu ne peut pas être vide." });
  }

  // Extraire automatiquement les hashtags du contenu
  const hashtagsFromText = (contenu + " " + article_contenu).match(/#[\wÀ-ÿ]+/g) || [];
  const allHashtags = JSON.stringify([...new Set([...JSON.parse(hashtags), ...hashtagsFromText])]);

  const id = db.prepare(`
    INSERT INTO fil_posts
      (auteur_id, auteur_nom, type, pub_type, categorie, contenu,
       media_url, media_type, article_titre, article_contenu, video_duree,
       visibilite, medias, hashtags, statut, programmed_at,
       localisation_pays, localisation_ville)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    user.id, user.nom, pub_type, pub_type,
    body.categorie || "Publication",
    contenu || article_titre,
    body.media_url || null,
    pub_type === "photo" ? "image" : pub_type === "video" ? "video" : null,
    article_titre || null,
    article_contenu || null,
    body.video_duree || null,
    visibilite, medias, allHashtags, statut,
    body.programmed_at || null,
    body.localisation_pays || null,
    body.localisation_ville || null,
  ).lastInsertRowid;
  if (body.source_import) db.prepare("UPDATE fil_posts SET source_import=? WHERE id=?").run(body.source_import, id);

  // Récupère le post complet pour le renvoyer
  const post = await db.prepare("SELECT * FROM fil_posts WHERE id=?").get(id);

  // --- Notifications de mention ---
  // Cherche tous les tokens @[Nom](u:123) et @[Nom](i:456)
  const allText = [contenu, article_titre, article_contenu].join(" ");
  const MENTION_RE = /@\[([^\]]+)\]\(([ui]):(\d+)\)/g;
  const notified = new Set(); // évite les doublons si même personne mentionnée 2x
  let m;
  // Extrait 80 premiers chars du texte visible pour la notification
  const visibleText = allText.replace(MENTION_RE, "@$1").replace(/<[^>]+>/g,"").trim();
  const extrait = visibleText.slice(0, 80) + (visibleText.length > 80 ? "…" : "");

  while ((m = MENTION_RE.exec(allText)) !== null) {
    const [, nomMentionne, kind, rawId] = m;
    const cibleId = Number(rawId);
    if (!cibleId || notified.has(`${kind}:${cibleId}`)) continue;
    notified.add(`${kind}:${cibleId}`);

    if (kind === "u") {
      // Utilisateur direct — ne pas notifier soi-même
      if (cibleId !== user.id) {
        creerNotif(
          cibleId,
          "mention",
          `${user.nom} vous a mentionné dans une publication`,
          `« ${extrait} »`,
          { post_id: Number(id) }
        );
      }
    } else if (kind === "i") {
      // Initiative — notifier le propriétaire de l'initiative
      const owner = await db.prepare("SELECT owner_user_id FROM initiatives WHERE id=?").get(cibleId);
      if (owner && owner.owner_user_id && owner.owner_user_id !== user.id) {
        creerNotif(
          owner.owner_user_id,
          "mention",
          `${user.nom} a mentionné votre initiative dans une publication`,
          `« ${extrait} »`,
          { post_id: Number(id) }
        );
      }
    }
  }

  // --- Notifie les abonnés du profil de l'auteur qu'une nouvelle publication est en ligne ---
  if (statut === "publie" && visibilite === "public") {
    try {
      const abonnes = await db.prepare("SELECT follower_id FROM user_follows WHERE followed_id=?").all(user.id);
      for (const a of abonnes) {
        if (Number(a.follower_id) === user.id) continue;
        creerNotif(a.follower_id, "nouvelle_publication", `${user.nom} a publié`,
          extraitOrDefault(contenu || article_titre || article_contenu),
          { post_id: Number(id) });
      }
    } catch (_) {}
  }

  sendJSON(res, 201, { id, post });
});

function extraitOrDefault(txt) {
  const t = (txt || "").replace(/<[^>]+>/g, "").trim();
  return t ? (t.slice(0, 80) + (t.length > 80 ? "…" : "")) : "Nouvelle publication sur son profil.";
}

/* Priorité 3 (loi de priorité fil) : temps passé sur une publication */
route("POST", "/api/fil/:id/dwell", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 200, { ok: false });
  const duree = Math.max(0, Math.min(600, Number(body.duree_sec) || 0));
  if (duree < 2) return sendJSON(res, 200, { ok: true, ignore: true });
  try { db.prepare("INSERT INTO fil_post_dwell (post_id, user_id, duree_sec) VALUES (?,?,?)").run(params.id, user.id, duree); } catch (_) {}
  sendJSON(res, 200, { ok: true });
});

route("POST", "/api/fil/:id/react", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const type = body.type || "like";
  try {
    db.prepare("INSERT INTO fil_reactions (post_id, user_id, type) VALUES (?, ?, ?)").run(params.id, user.id, type);
  } catch (e) { /* déjà réagi avec ce type : ignorer (contrainte UNIQUE) */ }
  const reactions = await db.prepare("SELECT type, COUNT(*) AS n FROM fil_reactions WHERE post_id = ? GROUP BY type").all(params.id);
  const counts = {};
  reactions.forEach(r => counts[r.type] = r.n);
  // Notifier l'auteur du post
  const post = await db.prepare("SELECT auteur_id,contenu FROM fil_posts WHERE id=?").get(params.id);
  if (post && post.auteur_id && post.auteur_id !== user.id) {
    creerNotif(post.auteur_id, "reaction", "Réaction sur votre post", `${user.nom} a réagi à votre publication`, { post_id: Number(params.id) });
  }
  sendJSON(res, 200, { reactions: counts });
});

/* ---------- Galerie photo (réactions/commentaires par photo, comptes utilisateur ou initiative) ---------- */

function checkGalerieOwnerType(t) { return t === 'user' || t === 'initiative'; }

/* Compteurs (réactions + commentaires) pour toutes les photos d'un propriétaire, en un seul appel */
route("GET", "/api/galerie/:ownerType/:ownerId/stats", async (req, res, params) => {
  if (!checkGalerieOwnerType(params.ownerType)) return sendJSON(res, 400, { error: "Type invalide." });
  const reacts = await db.prepare("SELECT photo_id, COUNT(*) AS n FROM galerie_reactions WHERE owner_type=? AND owner_id=? GROUP BY photo_id").all(params.ownerType, params.ownerId);
  const coms = await db.prepare("SELECT photo_id, COUNT(*) AS n FROM galerie_commentaires WHERE owner_type=? AND owner_id=? GROUP BY photo_id").all(params.ownerType, params.ownerId);
  const stats = {};
  reacts.forEach(r => { stats[r.photo_id] = stats[r.photo_id] || { reactions: 0, commentaires: 0 }; stats[r.photo_id].reactions = r.n; });
  coms.forEach(c => { stats[c.photo_id] = stats[c.photo_id] || { reactions: 0, commentaires: 0 }; stats[c.photo_id].commentaires = c.n; });
  sendJSON(res, 200, { stats });
});

route("POST", "/api/galerie/:ownerType/:ownerId/:photoId/react", async (req, res, params) => {
  if (!checkGalerieOwnerType(params.ownerType)) return sendJSON(res, 400, { error: "Type invalide." });
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const already = await db.prepare("SELECT 1 FROM galerie_reactions WHERE owner_type=? AND owner_id=? AND photo_id=? AND user_id=? AND type='jaime'").get(params.ownerType, params.ownerId, params.photoId, user.id);
  if (already) {
    await db.prepare("DELETE FROM galerie_reactions WHERE owner_type=? AND owner_id=? AND photo_id=? AND user_id=? AND type='jaime'").run(params.ownerType, params.ownerId, params.photoId, user.id);
  } else {
    try { await db.prepare("INSERT INTO galerie_reactions (owner_type, owner_id, photo_id, user_id, type) VALUES (?,?,?,?,'jaime')").run(params.ownerType, params.ownerId, params.photoId, user.id); } catch (e) {}
  }
  const n = (await db.prepare("SELECT COUNT(*) AS n FROM galerie_reactions WHERE owner_type=? AND owner_id=? AND photo_id=?").get(params.ownerType, params.ownerId, params.photoId))?.n || 0;
  sendJSON(res, 200, { reactions: n, jaime: !already });
});

