/* ---------- Republier ---------- */

route("POST", "/api/fil/:id/republier", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });

  const original = await db.prepare("SELECT * FROM fil_posts WHERE id=?").get(params.id);
  if (!original) return sendJSON(res, 404, { error: "Publication introuvable." });

  const commentaire = (body.commentaire || "").trim();

  const newId = db.prepare(`
    INSERT INTO fil_posts
      (auteur_id, auteur_nom, type, pub_type, categorie, contenu, original_post_id, repost_commentaire)
    VALUES (?,?,?,?,?,?,?,?)
  `).run(
    user.id, user.nom, "repost", "repost",
    original.categorie || "Republication",
    commentaire || "",
    original.id,
    commentaire || null
  ).lastInsertRowid;

  // Notifier l'auteur de l'original
  if (original.auteur_id && original.auteur_id !== user.id) {
    creerNotif(original.auteur_id, "mention",
      `${user.nom} a republié votre publication`,
      commentaire ? `« ${commentaire.slice(0,80)} »` : "Sans commentaire ajouté",
      { post_id: Number(newId) });
  }

  const post = await db.prepare("SELECT * FROM fil_posts WHERE id=?").get(newId);
  sendJSON(res, 201, { id: newId, post });
});

/* ================================================================
   MESSAGERIE INTERNE UNIFIÉE
   ================================================================ */

/* Matrice d'initiation : qui peut DÉMARRER une conversation avec qui.
   Les comptes officiels (collectivite) ne peuvent JAMAIS initier directement
   avec un membre (utilisateur) ou une organisation (initiative) — voir règles
   de communication des comptes Collectivités : ils doivent passer par une
   demande de mise en relation (table demandes_relation), acceptée explicitement
   par le destinataire, seule voie créant la conversation. Ils peuvent en
   revanche échanger librement avec d'autres comptes institutionnels. */
const PEUT_INITIER = {
  utilisateur:   ["utilisateur", "initiative", "collectivite", "administrateur"],
  initiative:    ["utilisateur", "initiative", "collectivite", "administrateur"],
  collectivite:  ["collectivite", "administrateur"],
  administrateur:["utilisateur", "initiative", "collectivite", "administrateur"],
};
const PEUT_CONTACTER = PEUT_INITIER;

/* ===========================================================================
   GOUVERNANCE DES COMPTES COLLECTIVITÉ — « Observer largement, agir localement »
   Diaspo'Actif distingue deux droits : le droit d'OBSERVER (vision mondiale,
   données anonymisées) et le droit d'INTERAGIR (uniquement les membres relevant
   de la compétence de la collectivité ou ayant choisi d'entrer en relation).
   Helpers de juridiction utilisés par la messagerie et la diffusion.
=========================================================================== */

/* Périmètre de compétence d'une collectivité, déduit de son type d'organisme et
   de ses zones d'exercice (avec repli sur les champs de localisation du compte). */
function getPerimetre(coll) {
  const org = (coll.type_organisme || coll.type_institution || "").toLowerCase();
  const pays = coll.pays_exercice || coll.pays || null;
  const region = coll.region_exercice || coll.region || null;
  const departement = coll.departement_exercice || coll.departement || null;
  const ville = coll.ville_exercice || coll.ville || null;
  let niveau;
  if (/mairie|commune|municipal/.test(org)) niveau = "ville";
  else if (/d[ée]partement/.test(org)) niveau = "departement";
  else if (/r[ée]gion/.test(org)) niveau = "region";
  else if (/ambassade|consulat|minist|nation|[ée]tat|gouvern/.test(org)) niveau = "pays";
  else niveau = ville ? "ville" : region ? "region" : departement ? "departement" : "pays"; // repli : le plus précis disponible
  return { niveau, pays, region, departement, ville };
}

/* Libellé lisible du périmètre (pour l'UI et les messages). */
function libellePerimetre(p) {
  if (p.niveau === "ville" && p.ville) return `${p.ville}${p.pays ? " (" + p.pays + ")" : ""}`;
  if (p.niveau === "departement" && p.departement) return `${p.departement}${p.pays ? " (" + p.pays + ")" : ""}`;
  if (p.niveau === "region" && p.region) return `${p.region}${p.pays ? " (" + p.pays + ")" : ""}`;
  return p.pays || "Périmètre non défini";
}

/* Clause SQL bornant des `users` au périmètre de compétence de la collectivité.
   Sert à limiter la DIFFUSION (principe 4) : on ne peut toucher que les membres
   du territoire. Retourne { where, params }. */
function perimetreWhere(p, alias = "u") {
  const conds = [];
  const params = [];
  if (p.pays)  { conds.push(`${alias}.pays = ?`); params.push(p.pays); }
  if (p.niveau === "region" && p.region) { conds.push(`${alias}.region = ?`); params.push(p.region); }
  if (p.niveau === "departement" && p.departement) { conds.push(`${alias}.departement = ?`); params.push(p.departement); }
  if (p.niveau === "ville" && p.ville) { conds.push(`${alias}.ville = ?`); params.push(p.ville); }
  const where = conds.length ? conds.join(" AND ") : "1=0"; // périmètre indéfini ⇒ aucune diffusion
  return { where, params };
}

/* Un membre relève-t-il du périmètre de compétence d'une collectivité ?
   Utilisé pour la diffusion (principe 4) : un membre ne reçoit les contenus
   poussés (communications, consultations) que des collectivités dont il dépend. */
function membreDansPerimetre(coll, membre) {
  const p = getPerimetre(coll);
  if (!p.pays) return false;                                   // périmètre indéfini ⇒ aucune diffusion ciblée
  if (membre.pays !== p.pays) return false;
  if (p.niveau === "region" && p.region && membre.region !== p.region) return false;
  if (p.niveau === "departement" && p.departement && membre.departement !== p.departement) return false;
  if (p.niveau === "ville" && p.ville && membre.ville !== p.ville) return false;
  return true;
}

/* ===========================================================================
   REGISTRE UNIQUE DES COLLECTIVITÉS — identité territoriale.
   Identifiant unique + détection de doublons pour faire de Diaspo'Actif un
   registre territorial fiable (carte d'identité numérique des institutions).
=========================================================================== */
const PAYS_ISO = {
  "france": "FR", "côte d'ivoire": "CI", "cote d'ivoire": "CI", "sénégal": "SN", "senegal": "SN",
  "cameroun": "CM", "mali": "ML", "canada": "CA", "belgique": "BE", "suisse": "CH", "maroc": "MA",
  "congo": "CG", "royaume-uni": "UK", "états-unis": "US", "etats-unis": "US", "espagne": "ES",
  "allemagne": "DE", "italie": "IT", "portugal": "PT", "bénin": "BJ", "benin": "BJ", "togo": "TG",
  "guinée": "GN", "guinee": "GN", "burkina faso": "BF", "gabon": "GA", "niger": "NE", "tchad": "TD",
};
const TYPE_ORG_ABBR = {
  "état": "ETAT", "etat": "ETAT", "ministère": "MIN", "ministere": "MIN", "ambassade": "AMB",
  "consulat": "CONSULAT", "région": "REGION", "region": "REGION", "département": "DEP", "departement": "DEP",
  "commune": "COMMUNE", "ville": "VILLE", "mairie": "MAIRIE", "district": "DISTRICT", "préfecture": "PREF",
  "prefecture": "PREF", "chambre consulaire": "CCI", "collectivite territoriale": "CT", "organisation territoriale": "OT",
};
const sansAccents = s => (s || "").normalize("NFD").replace(/[̀-ͯ]/g, "");
function abrevType(t) {
  const k = sansAccents((t || "").toLowerCase()).trim();
  for (const [key, val] of Object.entries(TYPE_ORG_ABBR)) if (sansAccents(key) === k) return val;
  return sansAccents((t || "ORG").toUpperCase()).replace(/[^A-Z]/g, "").slice(0, 8) || "ORG";
}
function codePays(pays) {
  const iso = PAYS_ISO[(pays || "").toLowerCase().trim()];
  return iso || sansAccents((pays || "XX").toUpperCase()).replace(/[^A-Z]/g, "").slice(0, 2) || "XX";
}
function slugVille(ville) {
  return sansAccents((ville || "").toUpperCase()).replace(/[^A-Z0-9]/g, "").slice(0, 10) || "NA";
}
/* Génère un identifiant territorial unique : COL-{PAYS}-{CP}-{VILLE}-{TYPE}-{NNN}. */
function genererIdentifiantTerritorial(coll) {
  const pays = codePays(coll.pays_exercice || coll.pays);
  const cp = (coll.code_postal_exercice || coll.code_postal || "").replace(/[^0-9A-Za-z]/g, "").slice(0, 5);
  const ville = slugVille(coll.ville_exercice || coll.ville);
  const type = abrevType(coll.type_organisme || coll.type_institution);
  const prefixe = ["COL", pays, cp, ville, type].filter(Boolean).join("-");
  // Numéro séquentiel pour désambiguïser d'éventuelles collisions sur le même préfixe.
  let n = 1, candidat;
  do {
    candidat = `${prefixe}-${String(n).padStart(3, "0")}`;
    n++;
  } while (db.prepare("SELECT COUNT(*) AS c FROM users WHERE identifiant_territorial=?").get(candidat)?.c > 0 && n < 1000);
  return candidat;
}
/* Similarité de deux chaînes (0..1) — distance de Levenshtein normalisée. */
function similariteChaine(a, b) {
  a = sansAccents((a || "").toLowerCase()).replace(/\s+/g, " ").trim();
  b = sansAccents((b || "").toLowerCase()).replace(/\s+/g, " ").trim();
  if (!a || !b) return 0;
  if (a === b) return 1;
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, (_, i) => [i, ...Array(n).fill(0)]);
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) for (let j = 1; j <= n; j++)
    dp[i][j] = a[i - 1] === b[j - 1] ? dp[i - 1][j - 1] : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
  const lev = dp[m][n];
  const distSim = 1 - lev / Math.max(m, n);
  // Bonus : recouvrement de tokens (gère « Région Bélier » vs « Conseil Régional du Bélier »).
  const ta = new Set(a.split(" ").filter(w => w.length > 2));
  const tb = new Set(b.split(" ").filter(w => w.length > 2));
  const inter = [...ta].filter(w => tb.has(w)).length;
  const tokenSim = (ta.size && tb.size) ? inter / Math.min(ta.size, tb.size) : 0;
  return Math.max(distSim, tokenSim);
}
function journalColl(collId, action, detail) {
  try { db.prepare("INSERT INTO collectivite_journal (collectivite_id,action,detail) VALUES (?,?,?)").run(collId, action, detail || null); } catch(e) {}
}

/* Portée d'une requête Observatoire selon le paramètre ?scope=
   - "territorial"  → bornée au périmètre de compétence de la collectivité (Module 2).
   - défaut/mondial → vision globale, sans restriction (Module 1).
   Retourne { where, params, territorial } où `where` est préfixé « AND … » (ou vide). */
async function obsScope(user, req) {
  let scope = null;
  try { scope = new URL(req.url, "http://x").searchParams.get("scope"); } catch(e) {}
  if (scope === "territorial") {
    const coll = await db.prepare("SELECT type_organisme,type_institution,pays_exercice,region_exercice,departement_exercice,ville_exercice,pays,region,departement,ville FROM users WHERE id=?").get(user.id);
    const p = getPerimetre(coll);
    const { where, params } = perimetreWhere(p, "u");
    return { where: where ? "AND " + where : "", params, territorial: true, perimetre: p };
  }
  // Mondial : réutilise le filtre d'accréditation (désormais accès complet ⇒ where vide).
  const base = buildObsWhere(getAccred(user.id), "u");
  return { ...base, territorial: false };
}

async function convAnonyme(conv, userId) {
  const isU1 = conv.user1_id === userId;
  return {
    ...conv,
    autre_id: isU1 ? conv.user2_id : conv.user1_id,
    archive: isU1 ? !!conv.archive_u1 : !!conv.archive_u2,
    deleted: isU1 ? !!conv.deleted_u1 : !!conv.deleted_u2,
  };
}

/* GET /api/conversations — liste des conversations (avec stats) */
route("GET", "/api/conversations", async (req, res, params, body, query) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });

  const filtre = query.filtre || "tous"; // tous | non_lus | archives
  const q = (query.q || "").toLowerCase();

  const rows = await db.prepare(`
    SELECT c.*,
      u.nom AS avec_nom, u.role AS avec_role, u.ville AS avec_ville, u.photo_url AS avec_photo,
      (SELECT contenu FROM messages WHERE conversation_id = c.id ORDER BY created_at DESC LIMIT 1) AS derniere,
      (SELECT type FROM messages WHERE conversation_id = c.id ORDER BY created_at DESC LIMIT 1) AS derniere_type,
      (SELECT created_at FROM messages WHERE conversation_id = c.id ORDER BY created_at DESC LIMIT 1) AS derniere_date,
      (SELECT COUNT(*) FROM messages WHERE conversation_id = c.id AND sender_id != ? AND lu = 0) AS non_lus
    FROM conversations c
    JOIN users u ON u.id = CASE WHEN c.user1_id = ? THEN c.user2_id ELSE c.user1_id END
    WHERE (c.user1_id = ? OR c.user2_id = ?)
      AND (CASE WHEN c.user1_id = ? THEN c.deleted_u1 ELSE c.deleted_u2 END) = 0
    ORDER BY COALESCE((SELECT created_at FROM messages WHERE conversation_id = c.id ORDER BY created_at DESC LIMIT 1), c.created_at) DESC
  `).all(user.id, user.id, user.id, user.id, user.id);

  let filtered = rows.map(r => ({ ...r, archive: r.user1_id === user.id ? !!r.archive_u1 : !!r.archive_u2 }));

  if (filtre === "non_lus") filtered = filtered.filter(r => r.non_lus > 0);
  if (filtre === "archives") filtered = filtered.filter(r => r.archive);
  else if (filtre === "tous") filtered = filtered.filter(r => !r.archive);

  if (query.liste_id) {
    const liste = await db.prepare("SELECT id FROM listes_diffusion WHERE id=? AND proprietaire_id=?").get(query.liste_id, user.id);
    if (liste) {
      const membres = await db.prepare("SELECT user_id FROM listes_diffusion_contacts WHERE liste_id=? AND user_id IS NOT NULL").all(query.liste_id);
      const ids = new Set(membres.map(m => Number(m.user_id)));
      filtered = filtered.filter(r => ids.has(r.user1_id === user.id ? Number(r.user2_id) : Number(r.user1_id)));
    } else {
      filtered = [];
    }
  }

  if (q) filtered = filtered.filter(r =>
    (r.avec_nom||"").toLowerCase().includes(q) ||
    (r.sujet||"").toLowerCase().includes(q) ||
    (r.derniere||"").toLowerCase().includes(q)
  );

  sendJSON(res, 200, { conversations: filtered });
});

/* POST /api/conversations — créer ou retrouver une conversation */
route("POST", "/api/conversations", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });

  const otherId = Number(body.user_id);
  if (!otherId || otherId === user.id) return sendJSON(res, 400, { error: "Destinataire invalide." });

  const other = await db.prepare("SELECT id, nom, role FROM users WHERE id = ?").get(otherId);
  if (!other) return sendJSON(res, 404, { error: "Destinataire introuvable." });

  let conv = await db.prepare("SELECT * FROM conversations WHERE (user1_id=? AND user2_id=?) OR (user1_id=? AND user2_id=?)").get(user.id, otherId, otherId, user.id);

  // Vérification d'initiation uniquement pour les NOUVELLES conversations
  if (!conv) {
    const allowed = PEUT_INITIER[user.role] || [];
    if (!allowed.includes(other.role)) {
      const msg = user.role === "collectivite"
        ? "Les comptes officiels ne peuvent pas initier un contact direct avec un membre ou une organisation. Utilisez « Demande de mise en relation » : la conversation ne sera créée qu'après acceptation du destinataire."
        : `Votre rôle (${user.role}) ne peut pas initier une conversation avec ce type de compte (${other.role}).`;
      return sendJSON(res, 403, { error: msg });
    }
  }
  if (conv) {
    // Réactiver si supprimé côté expéditeur
    if (conv.user1_id === user.id && conv.deleted_u1) await db.prepare("UPDATE conversations SET deleted_u1=0 WHERE id=?").run(conv.id);
    if (conv.user2_id === user.id && conv.deleted_u2) await db.prepare("UPDATE conversations SET deleted_u2=0 WHERE id=?").run(conv.id);
  } else {
    const id = await db.prepare("INSERT INTO conversations (user1_id, user2_id, sujet) VALUES (?, ?, ?)").run(user.id, otherId, body.sujet || null).lastInsertRowid;
    conv = { id };
  }
  sendJSON(res, 201, { conversation_id: conv.id });
});

/* ===========================================================================
   DEMANDES DE CONTACT INSTITUTIONNELLES
   Remplace le premier message privé par un consentement explicite du
   destinataire. Obligatoire pour les comptes Collectivité (voir PEUT_INITIER,
   ils ne peuvent jamais démarrer une conversation directement) ; ouvert à tout
   compte souhaitant une prise de contact plus formelle (motif, urgence).
=========================================================================== */

const DEMANDES_CONTACT_MOTIFS_DEFAUT = [
  "Proposition de partenariat", "Demande d'expertise", "Invitation à un événement",
  "Opportunité d'investissement", "Recherche de compétences", "Participation à une mission",
  "Projet de développement territorial", "Demande d'informations", "Échange institutionnel", "Autre",
];

let _demandesContactConfigCache = null;
async function getDemandesContactConfig() {
  if (_demandesContactConfigCache) return _demandesContactConfigCache;
  let row = await db.prepare("SELECT * FROM demandes_contact_config WHERE id=1").get();
  if (!row) {
    await db.prepare(
      "INSERT INTO demandes_contact_config (id, expiration_jours, cooldown_jours, max_par_jour, longueur_max_message, motifs_json) VALUES (1,30,90,20,600,?)"
    ).run(JSON.stringify(DEMANDES_CONTACT_MOTIFS_DEFAUT));
    row = await db.prepare("SELECT * FROM demandes_contact_config WHERE id=1").get();
  }
  _demandesContactConfigCache = {
    expiration_jours: row.expiration_jours, cooldown_jours: row.cooldown_jours,
    max_par_jour: row.max_par_jour, longueur_max_message: row.longueur_max_message,
    motifs: safeParse(row.motifs_json) || DEMANDES_CONTACT_MOTIFS_DEFAUT,
  };
  return _demandesContactConfigCache;
}

/* Révision légère (sans LLM) du message avant envoi : signale un ton commercial
   ou un message trop court, propose une reformulation neutre. Non bloquant —
   l'utilisateur reste libre d'envoyer tel quel (voir spec « Intelligence artificielle »). */
const DEMANDE_CONTACT_MOTS_DEMARCHAGE = [
  "achetez", "promo", "% de réduction", "cliquez ici", "argent facile", "offre limitée",
  "gratuit aujourd'hui", "投资", "buy now", "click here",
];
function analyserDemandeContactIA(motif, message) {
  const remarques = [];
  const m = (message || "").toLowerCase();
  if ((message || "").trim().length < 20) remarques.push("Le message est très court : détaillez le contexte et vos attentes pour augmenter vos chances de réponse.");
  if (DEMANDE_CONTACT_MOTS_DEMARCHAGE.some(w => m.includes(w))) remarques.push("Le message contient des formulations proches du démarchage commercial ; reformulez-le de façon institutionnelle.");
  if (!/[.?!]$/.test((message || "").trim())) remarques.push("Terminez votre message par une phrase de clôture claire (ex. une question ou un appel à échanger).");
  const suggestion = remarques.length
    ? `Bonjour, je me permets de vous contacter au sujet de « ${motif || "notre demande"} ». [Présentez le contexte en une phrase, puis votre demande précise et ce que vous proposez en retour.] Restant à votre disposition pour en échanger.`
    : null;
  return { ok: remarques.length === 0, remarques, suggestion };
}

