/* GET /api/users/search?q= — chercher des utilisateurs pour démarrer une conversation */
route("GET", "/api/users/search", async (req, res, params, body, query) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });

  const q = (query.q || "").trim();
  if (q.length < 2) return sendJSON(res, 200, { users: [] });

  const allowed = PEUT_CONTACTER[user.role] || [];
  const placeholders = allowed.map(() => "?").join(",");
  if (!placeholders) return sendJSON(res, 200, { users: [] });

  const pattern = `%${q}%`;
  const results = await db.prepare(`
    SELECT id, nom, role, ville, pays FROM users
    WHERE id != ? AND role IN (${placeholders})
      AND (nom LIKE ? OR email LIKE ?)
    LIMIT 10
  `).all(user.id, ...allowed, pattern, pattern);

  sendJSON(res, 200, { users: results });
});


/* ---------- Abonnements : suivre / ne plus suivre une initiative ---------- */
route("POST", "/api/initiatives/:id/suivre", async (req, res, params) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  if (user.role !== "utilisateur") return sendJSON(res, 403, { error: "Seuls les comptes Utilisateur peuvent suivre une initiative." });
  const init = await db.prepare("SELECT id, abonnes FROM initiatives WHERE id = ?").get(params.id);
  if (!init) return sendJSON(res, 404, { error: "Initiative introuvable." });
  try {
    db.prepare("INSERT INTO abonnements (user_id, initiative_id) VALUES (?, ?)").run(user.id, params.id);
    await db.prepare("UPDATE initiatives SET abonnes = abonnes + 1 WHERE id = ?").run(params.id);
    sendJSON(res, 201, { ok: true, abonne: true });
  } catch (e) {
    sendJSON(res, 409, { ok: false, abonne: true, message: "Déjà abonné." });
  }
});

route("DELETE", "/api/initiatives/:id/suivre", async (req, res, params) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const info = await db.prepare("DELETE FROM abonnements WHERE user_id = ? AND initiative_id = ?").run(user.id, params.id);
  if (info.changes > 0) db.prepare("UPDATE initiatives SET abonnes = MAX(0, abonnes - 1) WHERE id = ?").run(params.id);
  sendJSON(res, 200, { ok: true, abonne: false });
});

route("GET", "/api/mes-suivis", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const rows = await db.prepare(`
    SELECT i.*, a.created_at AS suivi_depuis
    FROM abonnements a
    JOIN initiatives i ON i.id = a.initiative_id
    WHERE a.user_id = ?
    ORDER BY a.created_at DESC
  `).all(user.id);
  const mapped = rows.map(r => ({
    ...r,
    nationalites_concernees: safeParse(r.nationalites_concernees),
    nationalite_unique: !!r.nationalite_unique,
    abonnement_actif: !!r.abonnement_actif
  }));
  sendJSON(res, 200, { initiatives: mapped });
});

/* ---------- Formations ---------- */
/* ──────────────────────────────────────────────────────────
   DIASPO FORMATION — Routes publiques & créateur
   ────────────────────────────────────────────────────────── */

/* 🎭 Mode démo investisseurs (temporaire) — PREMIUM_DEMO_UNLOCK=1 débloque l'accès réel à
   toutes les fonctionnalités Premium pour tous les comptes, sans toucher aux visuels (badges
   dorés, cadenas, modales "Passer à Premium" restent affichés normalement côté front).
   Désactiver : retirer la variable d'environnement PREMIUM_DEMO_UNLOCK (Vercel + .env local). */
function isPremiumDemoUnlock() { return process.env.PREMIUM_DEMO_UNLOCK === '1'; }

async function hasAccreditation(userId, type) {
  if (isPremiumDemoUnlock()) return true;
  const ancien = await db.prepare("SELECT id FROM compte_accreditations WHERE user_id=? AND type=? AND statut='active'").get(userId, type);
  if (ancien) return true;
  const def = await db.prepare("SELECT id FROM accred_definitions WHERE type=?").get(type);
  if (!def) return false;
  const nouv = await db.prepare("SELECT id, date_expiration FROM user_accreditations WHERE user_id=? AND accred_id=? AND statut='active'").get(userId, def.id);
  if (!nouv) return false;
  if (nouv.date_expiration && new Date(nouv.date_expiration).getTime() < Date.now()) return false;
  return true;
}

/* 🥇 Découverte Premium — période d'essai de 30 jours accordée automatiquement à la création
   du compte, pour tout rôle disposant d'un type d'accréditation "_abonne" premium.
   Générique : ajouter une entrée ici suffit à couvrir un futur type de compte. */
const PREMIUM_ACCRED_TYPE_BY_ROLE = {
  utilisateur: 'utilisateur_abonne',
  initiative: 'initiative_abonne',
};
/* Retourne { date_expiration } si l'utilisateur est actuellement en période d'essai
   🥇 Découverte Premium (active, non expirée, type_tarif='decouverte'), sinon null. */
async function getDecouvertePremium(userId) {
  const row = await db.prepare(`
    SELECT ua.date_expiration FROM user_accreditations ua
    WHERE ua.user_id=? AND ua.statut='active' AND ua.type_tarif='decouverte'
    ORDER BY ua.date_expiration DESC LIMIT 1
  `).get(userId);
  if (!row || !row.date_expiration) return null;
  if (new Date(row.date_expiration).getTime() < Date.now()) return null;
  return { date_expiration: row.date_expiration };
}

async function accorderDecouvertePremium(userId, role) {
  const type = PREMIUM_ACCRED_TYPE_BY_ROLE[role];
  if (!type) return;
  try {
    const def = await db.prepare("SELECT id FROM accred_definitions WHERE type=?").get(type);
    if (!def) return;
    const expire = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString();
    await db.prepare(`
      INSERT INTO user_accreditations (user_id, accred_id, statut, date_expiration, type_tarif, montant_paye)
      VALUES (?,?,?,?,?,0)
    `).run(userId, def.id, 'active', expire, 'decouverte');
  } catch (_) {}
}

/* Gate "Utilisateur Abonné" — Réseau Pro, Business Plans, Mes projets.
   Ne s'applique qu'aux comptes de rôle 'utilisateur' (les autres rôles ne sont pas concernés
   par cette accréditation). Retourne true si l'accès est autorisé, sinon répond 402 et retourne false. */
async function requireUtilisateurAbonne(user, res) {
  if (user.role !== 'utilisateur') return true;
  const ok = await hasAccreditation(user.id, 'utilisateur_abonne');
  if (!ok) {
    sendJSON(res, 402, { error: "Ce module est réservé aux comptes Utilisateur Abonné.", accred_type: 'utilisateur_abonne' });
    return false;
  }
  return true;
}

/* Middleware Express équivalent, pour les routes Business Plans (app.get/post/put/delete + requireAuth) */
async function requireUtilisateurAbonneMw(req, res, next) {
  const user = req.user || await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  if (!(await requireUtilisateurAbonne(user, res))) return;
  next();
}

/* ── Besoins en formation (la communauté exprime un besoin, formateurs/diasportifs peuvent voter) ── */

/* GET /api/formation-besoins — liste des besoins avec nombre de votes (+ mon vote éventuel) */
route("GET", "/api/formation-besoins", async (req, res, params, body, query) => {
  const me = await getCurrentUser(req);
  const rows = await db.prepare(`
    SELECT b.*, u.nom AS auteur_nom,
      (SELECT COUNT(*) FROM formation_besoins_votes v WHERE v.besoin_id=b.id) AS nb_votes
    FROM formation_besoins b
    LEFT JOIN users u ON u.id=b.user_id
    WHERE b.statut != 'clos'
    ORDER BY nb_votes DESC, b.created_at DESC
  `).all();
  let monVote = new Map();
  if (me) {
    const mine = await db.prepare("SELECT besoin_id, commentaire FROM formation_besoins_votes WHERE user_id=?").all(me.id);
    monVote = new Map(mine.map(v => [v.besoin_id, v.commentaire]));
  }
  const enriched = rows.map(r => ({ ...r, mon_vote: monVote.has(r.id), mon_commentaire: monVote.get(r.id) || null }));
  if (query.domaine) return sendJSON(res, 200, { besoins: enriched.filter(r => r.domaine === query.domaine) });
  sendJSON(res, 200, { besoins: enriched });
});

/* POST /api/formation-besoins — soumettre un besoin en formation (tous comptes connectés) */
route("POST", "/api/formation-besoins", async (req, res, params, body) => {
  const me = await getCurrentUser(req);
  if (!me) return sendJSON(res, 401, { error: "Connexion requise." });
  const titre = SEC.sanitizeString(body.titre || "", 200);
  const domaine = SEC.sanitizeString(body.domaine || "", 100);
  const description = SEC.sanitizeString(body.description || "", 3000);
  if (!titre) return sendJSON(res, 400, { error: "Le titre du besoin est obligatoire." });
  const id = await db.prepare("INSERT INTO formation_besoins (user_id,titre,domaine,description) VALUES (?,?,?,?)")
    .run(me.id, titre, domaine || null, description || null).lastInsertRowid;
  /* L'auteur soutient automatiquement son propre besoin */
  try { db.prepare("INSERT OR IGNORE INTO formation_besoins_votes (besoin_id,user_id,commentaire) VALUES (?,?,?)").run(id, me.id, null); } catch(_) {}
  sendJSON(res, 201, { id, ok: true });
});

/* POST /api/formation-besoins/:id/voter — soutenir un besoin (avec commentaire optionnel) */
route("POST", "/api/formation-besoins/:id/voter", async (req, res, params, body) => {
  const me = await getCurrentUser(req);
  if (!me) return sendJSON(res, 401, { error: "Connexion requise." });
  const besoin = await db.prepare("SELECT id FROM formation_besoins WHERE id=?").get(params.id);
  if (!besoin) return sendJSON(res, 404, { error: "Besoin introuvable." });
  const commentaire = body.commentaire ? SEC.sanitizeString(body.commentaire, 1000) : null;
  db.prepare(`INSERT INTO formation_besoins_votes (besoin_id,user_id,commentaire) VALUES (?,?,?)
    ON CONFLICT(besoin_id,user_id) DO UPDATE SET commentaire=?`).run(params.id, me.id, commentaire, commentaire);
  const nb_votes = (await db.prepare("SELECT COUNT(*) AS n FROM formation_besoins_votes WHERE besoin_id=?").get(params.id))?.n;
  sendJSON(res, 200, { ok: true, nb_votes });
});

/* DELETE /api/formation-besoins/:id/voter — retirer son soutien */
route("DELETE", "/api/formation-besoins/:id/voter", async (req, res, params) => {
  const me = await getCurrentUser(req);
  if (!me) return sendJSON(res, 401, { error: "Connexion requise." });
  await db.prepare("DELETE FROM formation_besoins_votes WHERE besoin_id=? AND user_id=?").run(params.id, me.id);
  const nb_votes = (await db.prepare("SELECT COUNT(*) AS n FROM formation_besoins_votes WHERE besoin_id=?").get(params.id))?.n;
  sendJSON(res, 200, { ok: true, nb_votes });
});

