  const totalMembres = (await db.prepare("SELECT COUNT(*) AS n FROM users WHERE role IN ('utilisateur', 'initiative')").get())?.n ?? 0;
  const totalInitiatives = (await db.prepare("SELECT COUNT(*) AS n FROM initiatives").get())?.n ?? 0;
