/* ---------- Autocomplete @mentions ---------- */
route("GET", "/api/mentions", async (req, res, params, body, query) => {
  const q = (query.q || "").trim();
  if (q.length < 1) return sendJSON(res, 200, { results: [] });
  const like = `%${q}%`;
  const users = await db.prepare(`
    SELECT id, nom, prenom, role, ville, pays, photo_url
    FROM users WHERE (nom LIKE ? OR prenom LIKE ?) AND role != 'administrateur' LIMIT 5
  `).all(like, like);
  const inits = await db.prepare(`
    SELECT id, nom, 'initiative' AS role, pays, logo_url AS photo_url
    FROM initiatives WHERE nom LIKE ? LIMIT 4
  `).all(like);
  const results = [
    ...users.map(u => ({
      id: u.id,
      nom: [u.prenom, u.nom].filter(Boolean).join(" "),
      type: "user",
      type_label: u.role === "initiative" ? "Initiative" : "Utilisateur",
      pays: u.pays || u.ville || "",
      photo_url: u.photo_url || null,
    })),
    ...inits.map(i => ({
      id: i.id,
      nom: i.nom,
      type: "initiative",
      type_label: "Initiative",
      pays: i.pays || "",
      photo_url: i.photo_url || null,
    })),
  ].slice(0, 8);
  sendJSON(res, 200, { results });
});

route("GET", "/api/recherche", async (req, res, params, body, query) => {
  const q = (query.q || "").trim();
  if (q.length < 2) return sendJSON(res, 200, { utilisateurs: [], initiatives: [], publications: [], formations: [], evenements: [] });
  const like = `%${q}%`;
  const type = query.type || "tous";

  // Priorité 3 (loi de priorité fil) : trace la recherche pour affiner les recommandations OZ
  const cuRech = await getCurrentUser(req);
  if (cuRech) { try { db.prepare("INSERT INTO recherches_utilisateur (user_id, requete) VALUES (?,?)").run(cuRech.id, q.slice(0, 200)); } catch (_) {} }

  const utilisateurs = (type === "tous" || type === "utilisateurs")
    ? await db.prepare("SELECT id,nom,role,ville,pays FROM users WHERE (nom LIKE ? OR ville LIKE ?) AND role != 'administrateur' LIMIT 8").all(like, like)
    : [];
  const _rawInits = (type === "tous" || type === "initiatives")
    ? await db.prepare("SELECT id,slug,nom,domaine,pays,ville,description,owner_user_id FROM initiatives WHERE nom LIKE ? OR description LIKE ? OR domaine LIKE ? LIMIT 8").all(like, like, like)
    : [];
  const initiatives = await Promise.all(_rawInits.map(async i => ({
    ...i,
    accreditations: i.owner_user_id
      ? (await db.prepare("SELECT type FROM compte_accreditations WHERE user_id=? AND statut='active'").all(i.owner_user_id)).map(a => a.type)
      : []
  })));
  const publications = (type === "tous" || type === "publications")
    ? await db.prepare("SELECT id,auteur_nom,contenu,categorie,created_at FROM fil_posts WHERE contenu LIKE ? OR auteur_nom LIKE ? LIMIT 8").all(like, like)
    : [];
  const formations = (type === "tous" || type === "formations")
    ? await db.prepare("SELECT id,titre,domaine,organisme,gratuit,duree FROM formations WHERE titre LIKE ? OR description LIKE ? OR organisme LIKE ? LIMIT 8").all(like, like, like)
    : [];
  const evenements = (type === "tous" || type === "evenements")
    ? await db.prepare("SELECT id,titre,lieu,date_evt,type_evt,pays FROM evenements WHERE titre LIKE ? OR lieu LIKE ? OR description LIKE ? LIMIT 8").all(like, like, like)
    : [];

  sendJSON(res, 200, { q, utilisateurs, initiatives, publications, formations, evenements });
});

/* ---------- Recherche de contacts (barre "trouver une personne/initiative", façon amis) ----------
   Recherche intelligente : priorité au réseau de l'utilisateur (suivis/suiveurs/contacts/initiatives
   suivies), repli automatique sur toute la plateforme si aucun résultat dans le réseau. Multi-critères
   (nom, bio, titre, compétences, domaine, description, services) + tolérance fautes/accents/synonymes
   (réutilise les helpers ANNUAIRE_* du moteur de recherche Annuaire). */
route("GET", "/api/recherche-contacts", async (req, res, params, body, query) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const qRaw = (query.q || "").trim();
  if (qRaw.length < 2) return sendJSON(res, 200, { results: [], source: null });

  const termesOriginaux = ANNUAIRE_NORMALISE(qRaw).split(/\s+/).filter(w => w.length >= 2);
  const termesEtendus = annuaireExpandTermes(termesOriginaux);

  const users = await db.prepare(`
    SELECT id, nom, prenom, role, ville, pays, photo_url, titre_pro, bio, competences
    FROM users WHERE id != ? AND role != 'administrateur' AND (compte_masque IS NULL OR compte_masque=0) LIMIT 500
  `).all(user.id);
  const inits = await db.prepare(`
    SELECT id, nom, domaine, ville, pays, owner_user_id, logo_url, description, mission, services, vitrine_services_categories_json
    FROM initiatives WHERE owner_user_id IS NULL OR owner_user_id != ? LIMIT 500
  `).all(user.id);

  let candidats = [
    ...users.map(u => {
      const score = annuaireScorerEntite([
        [[u.prenom, u.nom], 1000],
        [[u.titre_pro], 500],
        [[safeParse(u.competences)], 400],
        [[u.bio], 200],
      ], termesOriginaux, termesEtendus);
      return score > 0 ? {
        id: u.id, target_user_id: u.id, type: "user", score,
        nom: [u.prenom, u.nom].filter(Boolean).join(" ") || u.nom,
        sous_titre: u.role === "initiative" ? "Initiative" : "Utilisateur",
        lieu: [u.ville, u.pays].filter(Boolean).join(", "),
        photo_url: u.photo_url || null,
        lien: `profil.html?id=${u.id}`,
      } : null;
    }).filter(Boolean),
    ...inits.map(i => {
      const score = annuaireScorerEntite([
        [[i.nom], 1000],
        [[i.domaine], 500],
        [[i.services, safeParse(i.vitrine_services_categories_json)], 400],
        [[i.description, i.mission], 200],
      ], termesOriginaux, termesEtendus);
      return (score > 0 && i.owner_user_id) ? {
        id: i.id, target_user_id: i.owner_user_id, type: "initiative", score,
        nom: i.nom,
        sous_titre: i.domaine || "Initiative",
        lieu: [i.ville, i.pays].filter(Boolean).join(", "),
        photo_url: i.logo_url || null,
        lien: `initiative.html?id=${i.id}`,
      } : null;
    }).filter(Boolean),
  ].filter(c => c.target_user_id && Number(c.target_user_id) !== Number(user.id));

  candidats.sort((a, b) => b.score - a.score);

  // ── Priorité 1 : réseau de l'utilisateur (suivis, suiveurs, contacts acceptés, initiatives suivies) ──
  const reseauIds = new Set();
  (await db.prepare("SELECT followed_id FROM user_follows WHERE follower_id=?").all(user.id)).forEach(r => reseauIds.add(Number(r.followed_id)));
  (await db.prepare("SELECT follower_id FROM user_follows WHERE followed_id=?").all(user.id)).forEach(r => reseauIds.add(Number(r.follower_id)));
  (await db.prepare("SELECT demandeur_id, destinataire_id FROM demandes_contact WHERE statut='acceptee' AND (demandeur_id=? OR destinataire_id=?)").all(user.id, user.id))
    .forEach(r => reseauIds.add(Number(r.demandeur_id) === user.id ? Number(r.destinataire_id) : Number(r.demandeur_id)));
  const initiativesSuivies = await db.prepare("SELECT initiative_id FROM abonnements WHERE user_id=?").all(user.id);
  if (initiativesSuivies.length) {
    const ph = initiativesSuivies.map(() => "?").join(",");
    (await db.prepare(`SELECT owner_user_id FROM initiatives WHERE id IN (${ph}) AND owner_user_id IS NOT NULL`).all(...initiativesSuivies.map(i => i.initiative_id)))
      .forEach(r => reseauIds.add(Number(r.owner_user_id)));
  }
  (await db.prepare("SELECT collectivite_id FROM abonnements_collectivite WHERE user_id=?").all(user.id)).forEach(r => reseauIds.add(Number(r.collectivite_id)));

  const targetIds = [...new Set(candidats.map(c => Number(c.target_user_id)))];
  let relationsMap = {};
  if (targetIds.length) {
    const placeholders = targetIds.map(() => "?").join(",");
    const relations = await db.prepare(`
      SELECT demandeur_id, destinataire_id, statut, created_at FROM demandes_contact
      WHERE (demandeur_id=? AND destinataire_id IN (${placeholders}))
         OR (destinataire_id=? AND demandeur_id IN (${placeholders}))
      ORDER BY created_at DESC
    `).all(user.id, ...targetIds, user.id, ...targetIds);
    for (const r of relations) {
      const otherId = Number(r.demandeur_id) === Number(user.id) ? Number(r.destinataire_id) : Number(r.demandeur_id);
      if (relationsMap[otherId]) continue; // garder la plus récente déjà rencontrée
      relationsMap[otherId] = r.statut === "acceptee" ? "contact"
        : r.statut === "en_attente" ? (Number(r.demandeur_id) === Number(user.id) ? "envoyee" : "recue")
        : "aucune";
    }
  }

  const withRelation = candidats.map(c => ({ ...c, statut_relation: relationsMap[Number(c.target_user_id)] || "aucune" }));
  const dansReseau = withRelation.filter(c => reseauIds.has(Number(c.target_user_id)));
  const source = dansReseau.length ? "reseau" : "global";
  const results = (dansReseau.length ? dansReseau : withRelation).slice(0, 12);
  sendJSON(res, 200, { results, source });
});

/* ---------- Notifications ---------- */
async function creerNotif(userId, type, titre, contenu, data = {}) {
  try {
    db.prepare("INSERT INTO notifications (user_id,type,titre,contenu,data_json) VALUES (?,?,?,?,?)").run(userId, type, titre, contenu, JSON.stringify(data));
  } catch (e) { /* silencieux */ }
}

/* Notifie tous les abonnés d'une vitrine (initiative), sauf les user_id exclus (ex: déjà notifiés) */
async function notifierAbonnes(initiativeId, type, titre, contenu, data = {}, exceptIds = []) {
  try {
    const skip = new Set((exceptIds || []).map(Number));
    const abonnes = await db.prepare("SELECT user_id FROM abonnements WHERE initiative_id=?").all(initiativeId);
    for (const a of abonnes) {
      if (skip.has(Number(a.user_id))) continue;
      creerNotif(a.user_id, type, titre, contenu, { ...data, initiative_id: Number(initiativeId) });
    }
  } catch (e) { /* silencieux */ }
}

/* ═══════════════════════════════════════════════════════════════
   VÉRIFICATION D'IDENTITÉ (Stripe Identity) — 🔐 badge "Identité vérifiée"
   Aucun document n'est jamais stocké côté Diaspo'Actif : Stripe Identity
   héberge les documents/selfies, on ne conserve que le statut, les dates
   et l'identifiant technique de session (voir identity_verifications_log).
   ═══════════════════════════════════════════════════════════════ */
const IDENTITY_VALIDITY_MONTHS = 24;

function getOrigin(req) {
  const proto = req.headers["x-forwarded-proto"] || (req.socket && req.socket.encrypted ? "https" : "http");
  const host = req.headers.host || "localhost:3000";
  // Stripe Identity exige un return_url en https, sauf pour localhost (autorisé en test).
  const isLocal = /^localhost(:\d+)?$/.test(host) || /^127\.0\.0\.1(:\d+)?$/.test(host);
  return `${isLocal ? proto : "https"}://${host}`;
}

function addMonths(dateStr, months) {
  const d = dateStr ? new Date(dateStr) : new Date();
  d.setMonth(d.getMonth() + months);
  return d.toISOString();
}

/* Correspondance nom de pays (texte libre, tel que déclaré par l'utilisateur) → code ISO2,
   pour pouvoir comparer à l'issuing_country (ISO2) extrait du document par Stripe Identity. */
const PAYS_NOM_VERS_ISO2 = {
  france:"FR", francaise:"FR", "cote d ivoire":"CI", "cote divoire":"CI", ivoirienne:"CI", ivoirien:"CI",
  senegal:"SN", senegalaise:"SN", senegalais:"SN", mali:"ML", malienne:"ML", malien:"ML",
  cameroun:"CM", camerounaise:"CM", camerounais:"CM", benin:"BJ", beninoise:"BJ", beninois:"BJ",
  togo:"TG", togolaise:"TG", togolais:"TG", "burkina faso":"BF", burkinabe:"BF",
  guinee:"GN", guineenne:"GN", guineen:"GN", niger:"NE", nigerienne:"NE", nigerien:"NE",
  nigeria:"NG", nigeriane:"NG", nigerian:"NG", gabon:"GA", gabonaise:"GA", gabonais:"GA",
  congo:"CG", "republique democratique du congo":"CD", congolaise:"CG", congolais:"CG",
  tchad:"TD", tchadienne:"TD", tchadien:"TD", maroc:"MA", marocaine:"MA", marocain:"MA",
  algerie:"DZ", algerienne:"DZ", algerien:"DZ", tunisie:"TN", tunisienne:"TN", tunisien:"TN",
  madagascar:"MG", malgache:"MG", "republique centrafricaine":"CF", centrafricaine:"CF", centrafricain:"CF",
  mauritanie:"MR", mauritanienne:"MR", mauritanien:"MR", "guinee bissau":"GW",
  "guinee equatoriale":"GQ", "cap vert":"CV", capverdienne:"CV", capverdien:"CV",
  belgique:"BE", belge:"BE", suisse:"CH", allemagne:"DE", allemande:"DE", allemand:"DE",
  "royaume uni":"GB", "royaume-uni":"GB", britannique:"GB", "etats unis":"US", "etats-unis":"US", americaine:"US", americain:"US",
  canada:"CA", canadienne:"CA", canadien:"CA", italie:"IT", italienne:"IT", italien:"IT",
  espagne:"ES", espagnole:"ES", espagnol:"ES", portugal:"PT", portugaise:"PT", portugais:"PT",
};
function normaliserTexte(s) {
  return String(s || "").normalize("NFD").replace(/[̀-ͯ]/g, "").toLowerCase().replace(/['’]/g, " ").replace(/\s+/g, " ").trim();
}
function paysNomVersISO2(nom) {
  if (!nom) return null;
  const n = normaliserTexte(nom);
  if (PAYS_NOM_VERS_ISO2[n]) return PAYS_NOM_VERS_ISO2[n];
  if (/^[a-z]{2}$/.test(n)) return n.toUpperCase(); // déjà un code ISO2
  return null;
}

/* POST /api/identity/verify — crée une session de vérification Stripe Identity, renvoie l'URL hébergée */
route("POST", "/api/identity/verify", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const { stripe } = require("./stripe-client");
  if (!stripe) return sendJSON(res, 503, { error: "Vérification d'identité momentanément indisponible." });

  // Déjà vérifié et non expiré → rien à refaire
  const current = await db.prepare("SELECT identite_verifiee, identite_expire_le FROM users WHERE id=?").get(user.id);
  if (current?.identite_verifiee && current.identite_expire_le && new Date(current.identite_expire_le) > new Date()) {
    return sendJSON(res, 400, { error: "Votre identité est déjà vérifiée et valide." });
  }

  try {
    const origin = getOrigin(req);
    const session = await stripe.identity.verificationSessions.create({
      type: "document",
      // require_id_number pousse Stripe à extraire davantage de champs du document (dont le pays d'émission),
      // utilisés ensuite pour comparer l'origine/nationalité déclarée à celle du document.
      options: { document: { require_matching_selfie: true, require_id_number: true } },
      metadata: { diaspoactif_user_id: String(user.id) },
      return_url: `${origin}/profil.html?identity=retour`,
    });
    await db.prepare("UPDATE users SET stripe_identity_session_id=? WHERE id=?").run(session.id, user.id);
    await db.prepare(
      "INSERT INTO identity_verifications_log (user_id, stripe_session_id, type, statut) VALUES (?,?,?,?)"
    ).run(user.id, session.id, "personne", "requires_input");
    sendJSON(res, 200, { url: session.url });
  } catch (e) {
    // Erreurs Stripe (StripeInvalidRequestError, etc.) portent le détail utile dans e.raw / e.type / e.code,
    // que safeError() n'expose pas au client — on les journalise ici pour diagnostiquer sans exposer de données.
    if (e && e.type) {
      console.error(`[identity-verify] Stripe ${e.type} (code=${e.code || "?"}): ${e.raw?.message || e.message}`);
    }
    sendJSON(res, 500, SEC.safeError(e, "identity-verify"));
  }
});

/* GET /api/identity/status — statut de vérification de l'utilisateur connecté */
route("GET", "/api/identity/status", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const row = await db.prepare(
    "SELECT identite_verifiee, identite_verifiee_le, identite_expire_le, stripe_identity_session_id, identite_pays_document, identite_mismatch FROM users WHERE id=?"
  ).get(user.id);
  const verifie = !!row?.identite_verifiee && row.identite_expire_le && new Date(row.identite_expire_le) > new Date();
  sendJSON(res, 200, {
    verifie,
    verifie_le: row?.identite_verifiee_le || null,
    expire_le: row?.identite_expire_le || null,
    session_en_cours: !verifie && !!row?.stripe_identity_session_id,
    pays_document: row?.identite_pays_document || null,
    mismatch: verifie && !!row?.identite_mismatch,
  });
});

/* POST /api/stripe/webhook — événements Identity (vérification) + Connect (comptes vendeurs).
   Appelé AVANT readBody() global (nécessite le corps BRUT pour vérifier la signature). */
async function handleStripeWebhook(req, res) {
  const { stripe } = require("./stripe-client");
  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
  if (!stripe || !webhookSecret) {
    console.log("[Stripe webhook] Non configuré (clé ou secret webhook absent) — événement ignoré.");
    return sendJSON(res, 200, { received: false });
  }
  const chunks = [];
  req.on("data", c => chunks.push(c));
  await new Promise(r => req.on("end", r));
  const rawBody = Buffer.concat(chunks);

  let event;
  try {
    event = stripe.webhooks.constructEvent(rawBody, req.headers["stripe-signature"], webhookSecret);
  } catch (e) {
    SEC.logSecurity("stripe_webhook_bad_signature", { error: e.message });
    return sendJSON(res, 400, { error: "Signature invalide." });
  }

  try {
    if (event.type === "identity.verification_session.verified") {
      const session = event.data.object;
      const userId = Number(session.metadata?.diaspoactif_user_id);
      if (userId) {
        const now = new Date().toISOString();
        const expire = addMonths(now, IDENTITY_VALIDITY_MONTHS);
        // Pays d'émission du document (ISO2), extrait par Stripe Identity — comparé aux nationalités déclarées.
        const vo = session.verified_outputs || {};
        const paysDocument = vo.address?.country || vo.issuing_country || null;
        const userDecl = await db.prepare("SELECT nationalite1, nationalite2, nationalite3, pays FROM users WHERE id=?").get(userId);
        const declarees = [userDecl?.nationalite1, userDecl?.nationalite2, userDecl?.nationalite3, userDecl?.pays]
          .map(paysNomVersISO2).filter(Boolean);
        const mismatch = paysDocument && declarees.length && !declarees.includes(paysDocument) ? 1 : 0;
        await db.prepare(
          "UPDATE users SET identite_verifiee=1, identite_verifiee_le=?, identite_expire_le=?, identite_renouvellement_notifie=0, identite_pays_document=?, identite_mismatch=? WHERE id=?"
        ).run(now, expire, paysDocument, mismatch, userId);
        await db.prepare(
          "INSERT INTO identity_verifications_log (user_id, stripe_session_id, type, statut) VALUES (?,?,?,?)"
        ).run(userId, session.id, "personne", "verified");
        creerNotif(userId, "identite_verifiee", "Identité vérifiée ✔️",
          "Votre identité a été vérifiée avec succès. Le badge est maintenant visible sur votre profil.", {});
        if (mismatch) {
          creerNotif(userId, "identite_mismatch", "Origine à confirmer",
            "Le pays associé à votre document d'identité ne correspond pas à la nationalité déclarée sur votre profil. Vérifiez vos informations dans Confidentialité, ou contactez le support si c'est une erreur.", {});
        }
      }
    } else if (event.type === "identity.verification_session.requires_input") {
      const session = event.data.object;
      const userId = Number(session.metadata?.diaspoactif_user_id);
      if (userId) {
        await db.prepare(
          "INSERT INTO identity_verifications_log (user_id, stripe_session_id, type, statut) VALUES (?,?,?,?)"
        ).run(userId, session.id, "personne", "requires_input");
        const reason = session.last_error?.reason || "Document non valide.";
        creerNotif(userId, "identite_echec", "Vérification d'identité incomplète",
          `La vérification n'a pas pu être finalisée : ${reason} Vous pouvez réessayer depuis votre profil.`, {});
      }
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.pub_abonnement_user_id) {
      const session = event.data.object;
      const userId = Number(session.metadata.pub_abonnement_user_id);
      const plan = session.metadata.pub_abonnement_plan;
      const paymentMode = session.metadata.pub_abonnement_payment_mode;
      const planDef = PUB_PLANS.find(p => p.id === plan);
      if (userId && planDef) {
        await db.prepare(`
          INSERT INTO pub_abonnements (user_id, plan, statut, payment_mode, credits_restants, credits_reset_le, stripe_customer_id, stripe_subscription_id)
          VALUES (?,?,'active',?,?,datetime('now','+1 month'),?,?)
          ON CONFLICT(user_id) DO UPDATE SET plan=?, statut='active', payment_mode=?, credits_restants=?, credits_reset_le=datetime('now','+1 month'),
            stripe_customer_id=?, stripe_subscription_id=?, grace_until=NULL, updated_at=datetime('now')
        `).run(
          userId, plan, paymentMode, planDef.quota_mensuel, session.customer, session.subscription,
          plan, paymentMode, planDef.quota_mensuel, session.customer, session.subscription
        );
        creerNotif(userId, "pub_abonnement_actif", "Abonnement Publicité actif 📣",
          `Votre abonnement « ${planDef.label} » est actif. Vous disposez de ${planDef.quota_mensuel} publicité(s)/mois.`, {});
      }
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.diaspoactif_ticket_id) {
      const session = event.data.object;
      const ticketId = Number(session.metadata.diaspoactif_ticket_id);
      const ticket = await db.prepare(`SELECT * FROM tickets WHERE id=? AND payment_status='pending'`).get(ticketId);
      if (ticket) {
        const ts = new Date().toISOString();
        /* signé avec created_at (déjà fixé à l'insertion) : la vérification au scan recalcule
           la signature à partir de ce même champ, il ne faut donc pas utiliser un nouvel horodatage ici */
        const qrToken = await signTicket(ticket.id, ticket.event_id, ticket.created_at);
        await db.prepare(`UPDATE tickets SET payment_status='paid', qr_token=? WHERE id=?`).run(qrToken, ticket.id);
        await db.prepare(`UPDATE ticket_types SET quantite_vendue=quantite_vendue+1 WHERE id=?`).run(ticket.ticket_type_id);
        await db.prepare(`INSERT OR IGNORE INTO event_attendees (ticket_id,event_id,user_id,nom_display,pays) SELECT ?,?,u.id,u.nom,u.pays FROM users u WHERE u.id=?`)
          .run(ticket.id, ticket.event_id, ticket.user_id);

        const ev = await db.prepare(`SELECT * FROM events WHERE id=?`).get(ticket.event_id);
        const COMMISSION_RATE = 0.05;
        const platform_fee = parseFloat((ticket.prix_paye * COMMISSION_RATE).toFixed(2));
        const organizer_amount = parseFloat((ticket.prix_paye - platform_fee).toFixed(2));
        await db.prepare(`INSERT INTO wallet_transactions (ticket_id,event_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,?,'platform_fee',NULL,?,?,?,?,?)`)
          .run(ticket.id, ticket.event_id, platform_fee, COMMISSION_RATE, ticket.prix_paye, platform_fee, organizer_amount);
        await db.prepare(`INSERT INTO wallet_transactions (ticket_id,event_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,?,'organizer_credit',?,?,?,?,?,?)`)
          .run(ticket.id, ticket.event_id, ev.organisateur_id, organizer_amount, COMMISSION_RATE, ticket.prix_paye, platform_fee, organizer_amount);
        await db.prepare(`UPDATE users SET wallet_balance = COALESCE(wallet_balance,0) + ? WHERE id = ?`).run(organizer_amount, ev.organisateur_id);
        await db.prepare(`UPDATE platform_wallet SET total_commissions = total_commissions + ?, total_transactions = total_transactions + 1, updated_at = datetime('now') WHERE id = 1`).run(platform_fee);
        try {
          db.prepare(`INSERT INTO transactions (user_id,type,montant,statut,description,date_transaction) VALUES (?,'billet_evenement',?,'reussi',?,?)`)
            .run(ticket.user_id, ticket.prix_paye, 'billet_evenement', ts);
        } catch(e) { /* table transactions peut avoir schema différent */ }
        creerNotif(ticket.user_id, "billet_paye", "Billet payé ✅", `Votre billet pour « ${ev.titre} » est confirmé.`, { event_id: ev.id });
        if (ev.organisateur_id) creerNotif(ev.organisateur_id, "billet_vendu", "Nouveau billet vendu 🎟️", `Un billet vient d'être vendu pour « ${ev.titre} » (+${organizer_amount}€).`, { event_id: ev.id });
      }
    } else if (event.type === "checkout.session.expired" && event.data.object.metadata?.diaspoactif_ticket_id) {
      const session = event.data.object;
      const ticketId = Number(session.metadata.diaspoactif_ticket_id);
      await db.prepare(`UPDATE tickets SET payment_status='failed' WHERE id=? AND payment_status='pending'`).run(ticketId);
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.diaspoactif_commande_id) {
      /* Achat multi-billets (Billetterie V1) — une session Stripe peut couvrir plusieurs lignes `tickets`
         partageant le même transaction_ref. Idempotent comme la branche unitaire ci-dessus : si la commande
         a déjà été traitée, le filtre payment_status='pending' ne trouve plus rien à mettre à jour. */
      const session = event.data.object;
      const commandeTickets = await db.prepare(`SELECT * FROM tickets WHERE transaction_ref=? AND payment_status='pending'`).all(session.id);
      if (commandeTickets.length) {
        const ev = await db.prepare(`SELECT * FROM events WHERE id=?`).get(commandeTickets[0].event_id);
        const COMMISSION_RATE = 0.05;
        let totalOrganizer = 0, totalPlatform = 0;
        const promoUsageParCode = new Map(); // code_promo_id -> [{ticketId, userId}]
        for (const ticket of commandeTickets) {
          const qrToken = await signTicket(ticket.id, ticket.event_id, ticket.created_at);
          await db.prepare(`UPDATE tickets SET payment_status='paid', qr_token=? WHERE id=?`).run(qrToken, ticket.id);
          await db.prepare(`INSERT OR IGNORE INTO event_attendees (ticket_id,event_id,user_id,nom_display,pays) SELECT ?,?,u.id,COALESCE(?,u.nom),u.pays FROM users u WHERE u.id=?`)
            .run(ticket.id, ticket.event_id, ticket.titulaire_nom ? `${ticket.titulaire_prenom||''} ${ticket.titulaire_nom}`.trim() : null, ticket.user_id);

          const platform_fee = parseFloat((ticket.prix_paye * COMMISSION_RATE).toFixed(2));
          const organizer_amount = parseFloat((ticket.prix_paye - platform_fee).toFixed(2));
          totalPlatform += platform_fee; totalOrganizer += organizer_amount;
          await db.prepare(`INSERT INTO wallet_transactions (ticket_id,event_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,?,'platform_fee',NULL,?,?,?,?,?)`)
            .run(ticket.id, ticket.event_id, platform_fee, COMMISSION_RATE, ticket.prix_paye, platform_fee, organizer_amount);
          await db.prepare(`INSERT INTO wallet_transactions (ticket_id,event_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,?,'organizer_credit',?,?,?,?,?,?)`)
            .run(ticket.id, ticket.event_id, ev.organisateur_id, organizer_amount, COMMISSION_RATE, ticket.prix_paye, platform_fee, organizer_amount);

          if (ticket.code_promo_id) {
            if (!promoUsageParCode.has(ticket.code_promo_id)) promoUsageParCode.set(ticket.code_promo_id, []);
            promoUsageParCode.get(ticket.code_promo_id).push(ticket.id);
          }
          try {
            db.prepare(`INSERT INTO transactions (user_id,type,montant,statut,description,date_transaction) VALUES (?,'billet_evenement',?,'reussi',?,?)`)
              .run(ticket.user_id, ticket.prix_paye, 'billet_evenement', new Date().toISOString());
          } catch (e) { /* table transactions peut avoir schema différent */ }
        }
        await db.prepare(`UPDATE ticket_types SET quantite_vendue=quantite_vendue+? WHERE id=?`).run(commandeTickets.length, commandeTickets[0].ticket_type_id);
        await db.prepare(`UPDATE users SET wallet_balance = COALESCE(wallet_balance,0) + ? WHERE id = ?`).run(totalOrganizer, ev.organisateur_id);
        await db.prepare(`UPDATE platform_wallet SET total_commissions = total_commissions + ?, total_transactions = total_transactions + ?, updated_at = datetime('now') WHERE id = 1`)
          .run(totalPlatform, commandeTickets.length);
        for (const [codeId, ticketIds] of promoUsageParCode) {
          await consommerCodePromo(codeId, commandeTickets[0].user_id, ticketIds, ticketIds.length);
        }
        const acheteur = commandeTickets[0].user_id;
        creerNotif(acheteur, "billet_paye", "Billet(s) payé(s) ✅",
          `Votre commande de ${commandeTickets.length} billet(s) pour « ${ev.titre} » est confirmée.`, { event_id: ev.id });
        if (ev.organisateur_id) creerNotif(ev.organisateur_id, "billet_vendu", "Nouveaux billets vendus 🎟️",
          `${commandeTickets.length} billet(s) vendu(s) pour « ${ev.titre} » (+${totalOrganizer.toFixed(2)}€).`, { event_id: ev.id });
        try {
          const buyer = await db.prepare(`SELECT email, prenom, nom FROM users WHERE id=?`).get(acheteur);
          const tt = await db.prepare(`SELECT nom FROM ticket_types WHERE id=?`).get(commandeTickets[0].ticket_type_id);
          if (buyer?.email) {
            const { emailConfirmationBillets } = require('./mailer');
            const total = commandeTickets.reduce((s,t)=>s+t.prix_paye,0);
            emailConfirmationBillets({
              email: buyer.email, prenom: buyer.prenom || buyer.nom, eventTitre: ev.titre,
              dateEvenement: ev.date_debut ? new Date(ev.date_debut).toLocaleDateString('fr-FR', { day:'numeric', month:'long', year:'numeric', hour:'2-digit', minute:'2-digit' }) : '',
              lieu: [ev.ville, ev.pays].filter(Boolean).join(', '),
              billets: commandeTickets.map(t => ({ type_nom: tt?.nom || 'Billet', prix: t.prix_paye, titulaire: t.titulaire_nom ? `${t.titulaire_prenom||''} ${t.titulaire_nom}`.trim() : null })),
              montantTotal: total,
            }).catch(e => console.error('[email confirmation billets]', e.message));
          }
        } catch (e) { /* best-effort : ne jamais bloquer un paiement déjà confirmé pour un souci d'email */ }
      }
    } else if (event.type === "checkout.session.expired" && event.data.object.metadata?.diaspoactif_commande_id) {
      const session = event.data.object;
      await db.prepare(`UPDATE tickets SET payment_status='failed' WHERE transaction_ref=? AND payment_status='pending'`).run(session.id);
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.diaspoactif_commande_vitrine_id) {
      /* Paiement Boutique confirmé — même modèle que la Billetterie (commission 5%, crédit wallet_balance
         à l'initiative, retrait ultérieur via le Centre Financier). Idempotent : ne traite que si encore 'en_attente'. */
      const commandeId = Number(event.data.object.metadata.diaspoactif_commande_vitrine_id);
      const cmd = await db.prepare(`SELECT * FROM commandes_vitrine WHERE id=? AND paiement_statut='en_attente'`).get(commandeId);
      if (cmd) {
        const [prod, init] = await Promise.all([
          db.prepare(`SELECT * FROM produits_vitrine WHERE id=?`).get(cmd.produit_id),
          db.prepare(`SELECT * FROM initiatives WHERE id=?`).get(cmd.initiative_id),
        ]);
        const COMMISSION_RATE = 0.05;
        const montant = Number(cmd.montant_total) || 0;
        const platform_fee = parseFloat((montant * COMMISSION_RATE).toFixed(2));
        const organizer_amount = parseFloat((montant - platform_fee).toFixed(2));
        await db.prepare(`UPDATE commandes_vitrine SET paiement_statut='paye', statut='traitee' WHERE id=?`).run(commandeId);
        await db.prepare(`INSERT INTO wallet_transactions (commande_vitrine_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,'platform_fee',NULL,?,?,?,?,?)`)
          .run(commandeId, platform_fee, COMMISSION_RATE, montant, platform_fee, organizer_amount);
        await db.prepare(`INSERT INTO wallet_transactions (commande_vitrine_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,'organizer_credit',?,?,?,?,?,?)`)
          .run(commandeId, init.owner_user_id, organizer_amount, COMMISSION_RATE, montant, platform_fee, organizer_amount);
        await db.prepare(`UPDATE users SET wallet_balance = COALESCE(wallet_balance,0) + ? WHERE id = ?`).run(organizer_amount, init.owner_user_id);
        await db.prepare(`UPDATE platform_wallet SET total_commissions = total_commissions + ?, total_transactions = total_transactions + 1, updated_at = datetime('now') WHERE id = 1`).run(platform_fee);
        try {
          db.prepare(`INSERT INTO transactions (user_id,type,montant,statut,description,date_transaction) VALUES (?,'commande_boutique',?,'reussi',?,?)`)
            .run(cmd.acheteur_id, montant, 'commande_boutique', new Date().toISOString());
        } catch (e) { /* table transactions peut avoir schema différent */ }
        creerNotif(cmd.acheteur_id, "commande_payee", "Commande payée ✅", `Votre commande « ${prod?.nom || ''} » (x${cmd.quantite}) est confirmée.`, { commande_id: commandeId });
        creerNotif(init.owner_user_id, "commande_vendue", "Nouvelle vente 🛍️", `« ${prod?.nom || ''} » vendu (x${cmd.quantite}, +${organizer_amount}€).`, { commande_id: commandeId });
      }
    } else if (event.type === "checkout.session.expired" && event.data.object.metadata?.diaspoactif_commande_vitrine_id) {
      const commandeId = Number(event.data.object.metadata.diaspoactif_commande_vitrine_id);
      await db.prepare(`UPDATE commandes_vitrine SET paiement_statut='echoue' WHERE id=? AND paiement_statut='en_attente'`).run(commandeId);
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.diaspoactif_formation_inscription_id) {
      /* Paiement formation confirmé — même modèle que Boutique/Billetterie (commission 5%,
         crédit wallet_balance au propriétaire de la formation). Idempotent : ne traite que si
         encore 'en_attente' (une session Stripe peut renvoyer plusieurs fois le même événement). */
      const inscriptionId = Number(event.data.object.metadata.diaspoactif_formation_inscription_id);
      const insc = await db.prepare(`SELECT * FROM formation_inscriptions WHERE id=? AND paiement_statut='en_attente'`).get(inscriptionId);
      if (insc) {
        const f = await db.prepare(`SELECT * FROM formations WHERE id=?`).get(insc.formation_id);
        const session = event.data.object;
        const montant = (session.amount_total || 0) / 100;
        await db.prepare(`UPDATE formation_inscriptions SET paiement_statut='paye', montant_paye=? WHERE id=?`).run(montant, inscriptionId);
        if (f?.owner_user_id) {
          const COMMISSION_RATE = 0.05;
          const platform_fee = parseFloat((montant * COMMISSION_RATE).toFixed(2));
          const organizer_amount = parseFloat((montant - platform_fee).toFixed(2));
          await db.prepare(`INSERT INTO wallet_transactions (type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES ('platform_fee',NULL,?,?,?,?,?)`)
            .run(platform_fee, COMMISSION_RATE, montant, platform_fee, organizer_amount);
          await db.prepare(`INSERT INTO wallet_transactions (type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES ('organizer_credit',?,?,?,?,?,?)`)
            .run(f.owner_user_id, organizer_amount, COMMISSION_RATE, montant, platform_fee, organizer_amount);
          await db.prepare(`UPDATE users SET wallet_balance = COALESCE(wallet_balance,0) + ? WHERE id = ?`).run(organizer_amount, f.owner_user_id);
          await db.prepare(`UPDATE platform_wallet SET total_commissions = total_commissions + ?, total_transactions = total_transactions + 1, updated_at = datetime('now') WHERE id = 1`).run(platform_fee);
          creerNotif(f.owner_user_id, "commande_vendue", "Nouvelle inscription payante 🎓", `« ${f.titre} » vendue (+${organizer_amount}€).`, { formation_id: f.id });
        }
        creerNotif(insc.user_id, "formation", "Inscription confirmée ✅", `Votre paiement pour « ${f?.titre||''} » est confirmé. Accédez à la formation depuis « Mes inscriptions ».`, { formation_id: insc.formation_id });
        /* Alimente aussi le suivi de progression (« Mes inscriptions ») — pour le parcours gratuit
           c'est le frontend qui l'appelle juste après l'inscription instantanée ; ici, côté paiement
           différé par Stripe, on le fait côté serveur pour que ce soit fiable même si l'utilisateur
           ferme l'onglet avant le retour sur le site. */
        try {
          const exists = await db.prepare("SELECT id FROM user_formations_suivi WHERE user_id=? AND formation_id=?").get(insc.user_id, insc.formation_id);
          if (!exists && f) db.prepare("INSERT INTO user_formations_suivi (user_id,formation_id,titre,organisme) VALUES (?,?,?,?)").run(insc.user_id, insc.formation_id, f.titre, f.organisme||null);
        } catch(_) {}
      }
    } else if (event.type === "checkout.session.expired" && event.data.object.metadata?.diaspoactif_formation_inscription_id) {
      const inscriptionId = Number(event.data.object.metadata.diaspoactif_formation_inscription_id);
      await db.prepare(`DELETE FROM formation_inscriptions WHERE id=? AND paiement_statut='en_attente'`).run(inscriptionId);
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.diaspoactif_adhesion_paiement_id) {
      /* Paiement Cotisations & Adhésions confirmé (one-off ou 1ère facture d'une subscription).
         Même modèle commission 5%/wallet_balance que Boutique/Billetterie. Idempotent : ne traite que si 'en_attente'. */
      const paiementId = Number(event.data.object.metadata.diaspoactif_adhesion_paiement_id);
      const session = event.data.object;
      const pay = await db.prepare(`SELECT * FROM adhesion_paiements WHERE id=? AND statut='en_attente'`).get(paiementId);
      if (pay) {
        const [formule, init, membre] = await Promise.all([
          db.prepare(`SELECT * FROM adhesion_formules WHERE id=?`).get(pay.formule_id),
          db.prepare(`SELECT * FROM initiatives WHERE id=?`).get(pay.initiative_id),
          db.prepare(`SELECT * FROM adhesion_membres WHERE id=?`).get(pay.membre_id),
        ]);
        const COMMISSION_RATE = 0.05;
        const montant = Number(pay.montant) || 0;
        const platform_fee = parseFloat((montant * COMMISSION_RATE).toFixed(2));
        const organizer_amount = parseFloat((montant - platform_fee).toFixed(2));
        const numeroRecu = `REC-${pay.initiative_id}-${paiementId}`;
        const months = adhesionExpirationMonths(formule?.type_contribution);

        await db.prepare(`UPDATE adhesion_paiements SET statut='paye', numero_recu=?, stripe_subscription_id=?, date_paiement=datetime('now') WHERE id=?`)
          .run(numeroRecu, session.subscription || null, paiementId);
        await db.prepare(`UPDATE adhesion_membres SET statut='a_jour', mode_paiement='carte', montant_paye=?, numero_recu=?,
            date_adhesion=COALESCE(date_adhesion, datetime('now')),
            date_expiration=${months ? `datetime('now','+${months} months')` : 'NULL'},
            stripe_customer_id=?, stripe_subscription_id=?, updated_at=datetime('now') WHERE id=?`)
          .run(montant, numeroRecu, session.customer || null, session.subscription || null, pay.membre_id);

        await db.prepare(`INSERT INTO wallet_transactions (adhesion_paiement_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,'platform_fee',NULL,?,?,?,?,?)`)
          .run(paiementId, platform_fee, COMMISSION_RATE, montant, platform_fee, organizer_amount);
        await db.prepare(`INSERT INTO wallet_transactions (adhesion_paiement_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,'organizer_credit',?,?,?,?,?,?)`)
          .run(paiementId, init.owner_user_id, organizer_amount, COMMISSION_RATE, montant, platform_fee, organizer_amount);
        await db.prepare(`UPDATE users SET wallet_balance = COALESCE(wallet_balance,0) + ? WHERE id = ?`).run(organizer_amount, init.owner_user_id);
        await db.prepare(`UPDATE platform_wallet SET total_commissions = total_commissions + ?, total_transactions = total_transactions + 1, updated_at = datetime('now') WHERE id = 1`).run(platform_fee);

        if (membre.linked_user_id) {
          creerNotif(membre.linked_user_id, "adhesion_payee", "Adhésion confirmée ✅",
            `Votre « ${formule?.nom || 'adhésion'} » (${init.nom}) est confirmée. Reçu ${numeroRecu}.`, { paiement_id: paiementId });
        }
        creerNotif(init.owner_user_id, "adhesion_recue", "Nouvelle adhésion 🎫",
          `« ${formule?.nom || ''} » réglée par ${membre.prenom || ''} ${membre.nom} (+${organizer_amount}€).`, { paiement_id: paiementId });
        await ajouterAListeStockage(pay.formule_id, membre);
      }
    } else if (event.type === "checkout.session.expired" && event.data.object.metadata?.diaspoactif_adhesion_paiement_id) {
      const paiementId = Number(event.data.object.metadata.diaspoactif_adhesion_paiement_id);
      await db.prepare(`UPDATE adhesion_paiements SET statut='echoue' WHERE id=? AND statut='en_attente'`).run(paiementId);
    } else if (event.type === "checkout.session.completed" && event.data.object.metadata?.diaspoactif_accred_paiement_id) {
      /* Paiement d'une accréditation payante confirmé (ex. Utilisateur Abonné). Auto-active
         immédiatement — pas de validation admin pour ce type d'accréditation. Idempotent. */
      const paiementId = Number(event.data.object.metadata.diaspoactif_accred_paiement_id);
      const session = event.data.object;
      const pay = await db.prepare(`SELECT * FROM accred_paiements WHERE id=? AND statut='en_attente'`).get(paiementId);
      if (pay) {
        await db.prepare(`UPDATE accred_paiements SET statut='paye', stripe_subscription_id=?, updated_at=datetime('now') WHERE id=?`)
          .run(session.subscription || null, paiementId);
        await db.prepare(`
          INSERT INTO user_accreditations (user_id, accred_id, statut, type_tarif, montant_paye, stripe_customer_id, stripe_subscription_id)
          VALUES (?,?,'active',?,?,?,?)
          ON CONFLICT(user_id, accred_id) DO UPDATE SET statut='active', type_tarif=excluded.type_tarif,
            montant_paye=excluded.montant_paye, stripe_customer_id=excluded.stripe_customer_id,
            stripe_subscription_id=excluded.stripe_subscription_id, updated_at=datetime('now')
        `).run(pay.user_id, pay.accred_id, pay.type_tarif, pay.montant, session.customer || null, session.subscription || null);
        creerNotif(pay.user_id, "accred_abonnement", "Abonnement activé ⭐", "Votre abonnement est actif : Réseau Pro, Business Plans et Mes projets sont débloqués.", { accred_id: pay.accred_id });
      }
    } else if (event.type === "checkout.session.expired" && event.data.object.metadata?.diaspoactif_accred_paiement_id) {
      const paiementId = Number(event.data.object.metadata.diaspoactif_accred_paiement_id);
      await db.prepare(`UPDATE accred_paiements SET statut='echoue' WHERE id=? AND statut='en_attente'`).run(paiementId);
    } else if (event.type === "invoice.payment_succeeded" && event.data.object.subscription) {
      const invoice = event.data.object;
      const abo = await db.prepare("SELECT * FROM pub_abonnements WHERE stripe_subscription_id=?").get(invoice.subscription);
      if (abo && invoice.billing_reason !== "subscription_create") {
        const planDef = PUB_PLANS.find(p => p.id === abo.plan);
        await db.prepare(`UPDATE pub_abonnements SET statut='active', credits_restants=?, credits_reset_le=datetime('now','+1 month'), grace_until=NULL, updated_at=datetime('now') WHERE id=?`)
          .run(planDef?.quota_mensuel || 0, abo.id);
      }
      /* Renouvellement d'une cotisation périodique Adhésions (hors 1ère facture, déjà traitée par checkout.session.completed) */
      const adhMembre = await db.prepare("SELECT * FROM adhesion_membres WHERE stripe_subscription_id=?").get(invoice.subscription);
      if (adhMembre && invoice.billing_reason !== "subscription_create") {
        const formule = await db.prepare("SELECT * FROM adhesion_formules WHERE id=?").get(adhMembre.formule_id);
        const months = adhesionExpirationMonths(formule?.type_contribution) || 12;
        const montant = (invoice.amount_paid || 0) / 100;
        const paiementId = (await db.prepare(`
          INSERT INTO adhesion_paiements (membre_id,formule_id,initiative_id,montant,devise,mode_paiement,statut,stripe_subscription_id,date_paiement)
          VALUES (?,?,?,?,?,?,?,?,datetime('now'))
        `).run(adhMembre.id, adhMembre.formule_id, adhMembre.initiative_id, montant, formule?.devise || 'EUR', 'carte', 'paye', invoice.subscription)).lastInsertRowid;
        const numeroRecu = `REC-${adhMembre.initiative_id}-${paiementId}`;
        await db.prepare(`UPDATE adhesion_paiements SET numero_recu=? WHERE id=?`).run(numeroRecu, paiementId);
        await db.prepare(`UPDATE adhesion_membres SET statut='a_jour', montant_paye=?, numero_recu=?, date_expiration=datetime('now','+${months} months'), updated_at=datetime('now') WHERE id=?`)
          .run(montant, numeroRecu, adhMembre.id);

        const COMMISSION_RATE = 0.05;
        const platform_fee = parseFloat((montant * COMMISSION_RATE).toFixed(2));
        const organizer_amount = parseFloat((montant - platform_fee).toFixed(2));
        const init = await db.prepare("SELECT owner_user_id FROM initiatives WHERE id=?").get(adhMembre.initiative_id);
        await db.prepare(`INSERT INTO wallet_transactions (adhesion_paiement_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,'platform_fee',NULL,?,?,?,?,?)`)
          .run(paiementId, platform_fee, COMMISSION_RATE, montant, platform_fee, organizer_amount);
        await db.prepare(`INSERT INTO wallet_transactions (adhesion_paiement_id,type,beneficiaire_id,montant,commission_rate,prix_billet,platform_fee,organizer_amount) VALUES (?,'organizer_credit',?,?,?,?,?,?)`)
          .run(paiementId, init.owner_user_id, organizer_amount, COMMISSION_RATE, montant, platform_fee, organizer_amount);
        await db.prepare(`UPDATE users SET wallet_balance = COALESCE(wallet_balance,0) + ? WHERE id = ?`).run(organizer_amount, init.owner_user_id);
        await db.prepare(`UPDATE platform_wallet SET total_commissions = total_commissions + ?, total_transactions = total_transactions + 1, updated_at = datetime('now') WHERE id = 1`).run(platform_fee);

        if (adhMembre.linked_user_id) {
          creerNotif(adhMembre.linked_user_id, "adhesion_renouvelee", "Adhésion renouvelée ✅",
            `Votre cotisation a été renouvelée. Reçu ${numeroRecu}.`, { membre_id: adhMembre.id });
        }
      }
      /* Renouvellement de l'abonnement Utilisateur Abonné (hors 1ère facture) */
      const accredUA = await db.prepare("SELECT * FROM user_accreditations WHERE stripe_subscription_id=?").get(invoice.subscription);
      if (accredUA && invoice.billing_reason !== "subscription_create") {
        await db.prepare(`UPDATE user_accreditations SET statut='active', updated_at=datetime('now') WHERE id=?`).run(accredUA.id);
      }
    } else if (event.type === "invoice.payment_failed" && event.data.object.subscription) {
      const invoice = event.data.object;
      const abo = await db.prepare("SELECT * FROM pub_abonnements WHERE stripe_subscription_id=?").get(invoice.subscription);
      if (abo) {
        await db.prepare(`UPDATE pub_abonnements SET statut='suspended', grace_until=datetime('now','+7 days'), updated_at=datetime('now') WHERE id=?`).run(abo.id);
        creerNotif(abo.user_id, "pub_abonnement_suspendu", "Paiement échoué — Abonnement Publicité",
          "Votre paiement n'a pas pu être traité. Vos publicités sont en pause. Vous avez 7 jours pour régulariser.", {});
      }
      const adhMembre = await db.prepare("SELECT * FROM adhesion_membres WHERE stripe_subscription_id=?").get(invoice.subscription);
      if (adhMembre) {
        await db.prepare(`UPDATE adhesion_membres SET statut='non_a_jour', updated_at=datetime('now') WHERE id=?`).run(adhMembre.id);
        if (adhMembre.linked_user_id) {
          creerNotif(adhMembre.linked_user_id, "adhesion_paiement_echoue", "Paiement échoué — Adhésion",
            "Votre paiement de cotisation n'a pas pu être traité.", {});
        }
      }
    } else if (event.type === "customer.subscription.deleted") {
      const sub = event.data.object;
      await db.prepare(`UPDATE pub_abonnements SET statut='canceled', updated_at=datetime('now') WHERE stripe_subscription_id=?`).run(sub.id);
      await db.prepare(`UPDATE adhesion_membres SET statut='non_a_jour', updated_at=datetime('now') WHERE stripe_subscription_id=?`).run(sub.id);
      await db.prepare(`UPDATE user_accreditations SET statut='expiree', updated_at=datetime('now') WHERE stripe_subscription_id=?`).run(sub.id);
    } else if (event.type === "account.updated") {
      const account = event.data.object;
      const row = await db.prepare("SELECT initiative_id FROM stripe_connect_accounts WHERE stripe_account_id=?").get(account.id);
      if (row) {
        const detailsSubmitted = account.details_submitted ? 1 : 0;
        const chargesEnabled = account.charges_enabled ? 1 : 0;
        const payoutsEnabled = account.payouts_enabled ? 1 : 0;
        await db.prepare(
          "UPDATE stripe_connect_accounts SET details_submitted=?, charges_enabled=?, payouts_enabled=?, statut=?, updated_at=datetime('now') WHERE stripe_account_id=?"
        ).run(detailsSubmitted, chargesEnabled, payoutsEnabled, (chargesEnabled && payoutsEnabled) ? "active" : "pending", account.id);

        if (chargesEnabled && payoutsEnabled && detailsSubmitted) {
          const init = await db.prepare("SELECT organisation_verifiee, owner_user_id, nom FROM initiatives WHERE id=?").get(row.initiative_id);
          if (init && !init.organisation_verifiee) {
            const now = new Date().toISOString();
            await db.prepare(
              "UPDATE initiatives SET organisation_verifiee=1, organisation_verifiee_le=?, organisation_expire_le=? WHERE id=?"
            ).run(now, addMonths(now, IDENTITY_VALIDITY_MONTHS), row.initiative_id);
            if (init.owner_user_id) {
              creerNotif(init.owner_user_id, "organisation_verifiee", "Organisation vérifiée 🏢",
                `« ${init.nom} » a obtenu le badge Organisation vérifiée.`, { initiative_id: row.initiative_id });
            }
          }
        }
      }
    }
    sendJSON(res, 200, { received: true });
  } catch (e) {
    logError(e, "stripe-webhook", req);
    sendJSON(res, 200, { received: true }); // toujours 200 pour éviter les réessais infinis de Stripe sur une erreur interne
  }
}

/* ═══════════════════════════════════════════════════════════════
   MODULE PUBLICITÉ — régie publicitaire (campagnes + abonnements)
   Mode Stripe TEST uniquement (voir stripe-client.js).
   ═══════════════════════════════════════════════════════════════ */
const PUB_PLANS = [
  { id: "start",    label: "Start",    prix_annuel: 110, prix_mensuel_equiv: 9.17,  quota_mensuel: 1 },
  { id: "business", label: "Business", prix_annuel: 150, prix_mensuel_equiv: 12.50, quota_mensuel: 2 },
  { id: "premium",  label: "Premium",  prix_annuel: 200, prix_mensuel_equiv: 16.67, quota_mensuel: 4 },
];
const PUB_SLOTS = ["homepage_feed", "between_posts", "between_videos", "vitrine_section"];
const PUB_AD_CTA = ["En savoir plus", "Acheter", "Contacter", "S'inscrire"];

route("GET", "/api/ads/plans", async (req, res) => {
  sendJSON(res, 200, { plans: PUB_PLANS, slots: PUB_SLOTS, cta: PUB_AD_CTA });
});

/* GET /api/pub-abonnements/mon — abonnement publicité de l'utilisateur connecté */
route("GET", "/api/pub-abonnements/mon", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const abo = await db.prepare("SELECT * FROM pub_abonnements WHERE user_id=?").get(user.id);
  sendJSON(res, 200, { abonnement: abo || null });
});

/* POST /api/pub-abonnements/souscrire — crée une session Stripe Checkout (mode subscription) */
route("POST", "/api/pub-abonnements/souscrire", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const { stripe } = require("./stripe-client");
  if (!stripe) return sendJSON(res, 503, { error: "Paiements momentanément indisponibles." });

  const planDef = PUB_PLANS.find(p => p.id === body.plan);
  if (!planDef) return sendJSON(res, 400, { error: "Plan invalide." });
  const paymentMode = body.payment_mode === "mensuel" ? "mensuel" : "annuel";
  const montant = paymentMode === "mensuel"
    ? Math.round(planDef.prix_mensuel_equiv * 100)
    : Math.round(planDef.prix_annuel * 100);
  const interval = paymentMode === "mensuel" ? "month" : "year";

  try {
    const origin = getOrigin(req);
    const session = await stripe.checkout.sessions.create({
      mode: "subscription",
      line_items: [{
        price_data: {
          currency: "eur",
          unit_amount: montant,
          recurring: { interval },
          product_data: { name: `Diaspo'Actif Publicité — Plan ${planDef.label}` },
        },
        quantity: 1,
      }],
      metadata: {
        pub_abonnement_user_id: String(user.id),
        pub_abonnement_plan: planDef.id,
        pub_abonnement_payment_mode: paymentMode,
      },
      success_url: `${origin}/dashboard-initiative.html?pub_abonnement=retour#publicites-init`,
      cancel_url: `${origin}/dashboard-initiative.html?pub_abonnement=annule#publicites-init`,
    });
    sendJSON(res, 200, { url: session.url });
  } catch (e) {
    sendJSON(res, 500, SEC.safeError(e, "pub-abonnement-souscrire"));
  }
});

/* GET /api/ads/mes — mes campagnes */
route("GET", "/api/ads/mes", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const rows = await db.prepare("SELECT * FROM publicites WHERE user_id=? ORDER BY created_at DESC").all(user.id);
  sendJSON(res, 200, { publicites: rows });
});

/* GET /api/ads/:id/stats */
route("GET", "/api/ads/:id/stats", async (req, res, params) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  const ad = await db.prepare("SELECT * FROM publicites WHERE id=?").get(params.id);
  if (!ad || Number(ad.user_id) !== Number(user.id)) return sendJSON(res, 404, { error: "Publicité introuvable." });
  const ctr = ad.nb_impressions > 0 ? ((ad.nb_clics / ad.nb_impressions) * 100).toFixed(2) : "0.00";
  sendJSON(res, 200, {
    impressions: ad.nb_impressions, clics: ad.nb_clics, ctr,
    video_views: ad.nb_video_views, full_video_views: ad.nb_full_video_views,
    statut: ad.statut, date_debut: ad.date_debut, date_fin: ad.date_fin,
  });
});

/* POST /api/ads/create — crée une campagne (multipart: media image/vidéo) */
/* Compte le nombre de comptes correspondant à un ciblage géo + listes Réseau Pro (cumulatif). */
async function adsComptesCiblage({ zones = [], ville, departement, region, pays, listes = [] }) {
  let sql = "SELECT COUNT(DISTINCT u.id) AS n FROM users u WHERE u.role != 'administrateur' AND (u.compte_masque IS NULL OR u.compte_masque=0)";
  const args = [];
  const zoneConds = [];
  if ((zones.includes('ville') || zones.includes('commune')) && ville) { zoneConds.push('u.ville=?'); args.push(ville); }
  if (zones.includes('departement') && departement) { zoneConds.push('u.departement_exercice=?'); args.push(departement); }
  if (zones.includes('region') && region) { zoneConds.push('u.region_exercice=?'); args.push(region); }
  if (zones.includes('pays') && pays) { zoneConds.push('u.pays=?'); args.push(pays); }
  if (zoneConds.length) sql += ' AND (' + zoneConds.join(' OR ') + ')';
  if (listes.length) {
    const ph = listes.map(() => '?').join(',');
    sql += ` AND u.id IN (SELECT user_id FROM listes_diffusion_contacts WHERE liste_id IN (${ph}) AND user_id IS NOT NULL)`;
    args.push(...listes);
  }
  const r = await db.prepare(sql).get(...args);
  return r?.n || 0;
}

/* GET /api/ads/audience-preview — estimation en temps réel du nombre de destinataires avant publication */
route("GET", "/api/ads/audience-preview", async (req, res, params, body, query) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  let zones = [], listes = [];
  try { zones = JSON.parse(query.zones || "[]"); } catch (_) {}
  try { listes = JSON.parse(query.listes || "[]"); } catch (_) {}
  const criteres = { zones, ville: query.ville || null, departement: query.departement || null, region: query.region || null, pays: query.pays || null, listes: listes.map(Number).filter(Boolean) };
  const total = await adsComptesCiblage(criteres);
  // Répartition par pays (top 5) sur le même périmètre, pour l'aperçu
  let repartitionPays = [];
  try {
    let sql = "SELECT u.pays, COUNT(*) AS n FROM users u WHERE u.role != 'administrateur' AND u.pays IS NOT NULL";
    const args = [];
    const zoneConds = [];
    if ((zones.includes('ville') || zones.includes('commune')) && criteres.ville) { zoneConds.push('u.ville=?'); args.push(criteres.ville); }
    if (zones.includes('departement') && criteres.departement) { zoneConds.push('u.departement_exercice=?'); args.push(criteres.departement); }
    if (zones.includes('region') && criteres.region) { zoneConds.push('u.region_exercice=?'); args.push(criteres.region); }
    if (zones.includes('pays') && criteres.pays) { zoneConds.push('u.pays=?'); args.push(criteres.pays); }
    if (zoneConds.length) sql += ' AND (' + zoneConds.join(' OR ') + ')';
    if (criteres.listes.length) {
      const ph = criteres.listes.map(() => '?').join(',');
      sql += ` AND u.id IN (SELECT user_id FROM listes_diffusion_contacts WHERE liste_id IN (${ph}) AND user_id IS NOT NULL)`;
      args.push(...criteres.listes);
    }
    sql += " GROUP BY u.pays ORDER BY n DESC LIMIT 5";
    repartitionPays = await db.prepare(sql).all(...args);
  } catch (_) {}
  sendJSON(res, 200, { total, repartition_pays: repartitionPays });
});

route("POST", "/api/ads/create", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
  if (user.role !== "initiative") return sendJSON(res, 403, { error: "Réservé aux comptes Initiative." });

  /* Accréditation/abonnement Publicité désactivée temporairement (accès libre pour toute Initiative).
     Pour réactiver : décommenter le bloc ci-dessous. */
  const abo = await db.prepare("SELECT * FROM pub_abonnements WHERE user_id=?").get(user.id);
  // if (!abo || abo.statut !== "active") return sendJSON(res, 403, { error: "Un abonnement Publicité actif est requis pour créer une campagne." });
  // if (Number(abo.credits_restants) <= 0) return sendJSON(res, 403, { error: "Vous n'avez plus de crédit publicité ce mois-ci." });

  const contentType = req.headers["content-type"] || "";
  const boundaryMatch = contentType.match(/boundary=([^\s;]+)/);
  if (!boundaryMatch) return sendJSON(res, 400, { error: "Format invalide" });
  const chunks = [];
  req.on("data", c => chunks.push(c));
  await new Promise(r => req.on("end", r));
  const body = Buffer.concat(chunks);

  const { uploadToBunny, parseMultipart, uniqueFilename } = require("./upload");
  const { fields, files } = parseMultipart(body, boundaryMatch[1]);
  const file = files["media"] || files[Object.keys(files)[0]];
  if (!file) return sendJSON(res, 400, { error: "Aucun média reçu." });

  const titre = String(fields.titre || "").trim();
  if (!titre) return sendJSON(res, 400, { error: "Titre requis." });
  if (fields.charte_acceptee !== "1") return sendJSON(res, 400, { error: "Vous devez accepter la charte d'engagement des annonceurs avant de publier." });
  const dureeSec = Number(fields.duree_sec || 0);

  let mediaType = "image", checkedType = null;
  if (SEC.isSafeVideo(file.buffer)) {
    mediaType = "video";
    checkedType = SEC.isSafeVideo(file.buffer);
    if (dureeSec > 30) return sendJSON(res, 400, { error: "La vidéo doit durer 30 secondes maximum." });
    if (file.buffer.length > 40 * 1024 * 1024) return sendJSON(res, 400, { error: "Vidéo trop volumineuse (max 40 Mo)." });
  } else if (SEC.isSafeRasterImage(file.buffer)) {
    mediaType = "image";
    checkedType = SEC.isSafeRasterImage(file.buffer);
    if (file.buffer.length > 8 * 1024 * 1024) return sendJSON(res, 400, { error: "Image trop volumineuse (max 8 Mo)." });
  } else {
    return sendJSON(res, 400, { error: "Format de média non valide (JPEG, PNG, GIF, WebP, MP4 ou WebM requis)." });
  }

  let emplacements = ["homepage_feed"];
  try { const p = JSON.parse(fields.emplacements || "[]"); if (Array.isArray(p) && p.length) emplacements = p.filter(e => PUB_SLOTS.includes(e)); } catch (_) {}

  let cibleZones = [];
  try { const z = JSON.parse(fields.cible_zones || "[]"); if (Array.isArray(z)) cibleZones = z.filter(v => ['ville','commune','departement','region','pays','international'].includes(v)); } catch (_) {}
  let cibleListes = [];
  try { const l = JSON.parse(fields.cible_listes || "[]"); if (Array.isArray(l)) cibleListes = l.map(Number).filter(Boolean); } catch (_) {}
  const cibleVille = fields.cible_ville || null;
  const cibleDepartement = fields.cible_departement || null;
  const cibleRegion = fields.cible_region || null;
  const ciblePaysVal = fields.cible_pays || null;

  /* Durée toujours plafonnée à un mois maximum (30 jours) — jamais modifiable ensuite. */
  const dureeJours = Math.min(Math.max(parseInt(fields.duree_jours) || 7, 1), 30);

  /* Publication immédiate par défaut, ou programmée à une date future (fields.date_publication, YYYY-MM-DD).
     Aucune validation administrateur n'est requise : la campagne est active dès sa date de début. */
  let datePublicationSql = "date('now')";
  const dp = fields.date_publication ? String(fields.date_publication).slice(0, 10) : null;
  if (dp && /^\d{4}-\d{2}-\d{2}$/.test(dp) && new Date(dp) >= new Date(new Date().toDateString())) {
    datePublicationSql = `date('${dp}')`;
  }
  const dateFinSql = `date(${datePublicationSql},'+${dureeJours} days')`;

  try {
    const filename = uniqueFilename(file.filename, user.id);
    const url = await uploadToBunny(file.buffer, filename, "ads");
    const id = db.prepare(`
      INSERT INTO publicites (user_id, annonceur, media_type, media_url, titre, description, cta, lien_url, duree_jours,
        cible_pays, cible_langue, cible_interet, emplacements, statut, date_debut, date_fin, charte_acceptee_le,
        cible_zones, cible_ville, cible_departement, cible_region, cible_listes)
      VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?, 'approved', ${datePublicationSql}, ${dateFinSql}, datetime('now'), ?,?,?,?,?)
    `).run(
      user.id, user.nom || 'Diaspo\'Actif', mediaType, url, titre, fields.description || null,
      PUB_AD_CTA.includes(fields.cta) ? fields.cta : "En savoir plus",
      fields.lien_url || null, dureeJours,
      JSON.stringify(ciblePaysVal ? [ciblePaysVal] : []),
      JSON.stringify(fields.cible_langue ? [fields.cible_langue] : []),
      JSON.stringify(fields.cible_interet ? [fields.cible_interet] : []),
      JSON.stringify(emplacements),
      JSON.stringify(cibleZones), cibleVille, cibleDepartement, cibleRegion, JSON.stringify(cibleListes)
    ).lastInsertRowid;

    if (abo) await db.prepare("UPDATE pub_abonnements SET credits_restants=credits_restants-1, updated_at=datetime('now') WHERE id=?").run(abo.id);

    SEC.logSecurity("upload", { uid: Number(user.id), kind: "ad", type: checkedType, size: file.buffer.length });
    sendJSON(res, 201, { id, ok: true });
  } catch (e) {
    sendJSON(res, 500, SEC.safeError(e, "ads-create"));
  }
});

/* GET /api/ads/servir — diffusion publique d'une publicité approuvée pour un emplacement donné */
route("GET", "/api/ads/servir", async (req, res, params, body, query) => {
  const emplacement = query.emplacement || "homepage_feed";
  const user = await getCurrentUser(req);
  const now = new Date().toISOString();

  const candidates = await db.prepare(`
    SELECT * FROM publicites
    WHERE statut='approved' AND emplacements LIKE ?
      AND (date_debut IS NULL OR date_debut <= ?)
      AND (date_fin IS NULL OR date_fin >= ?)
    ORDER BY RANDOM()
  `).all(`%${emplacement}%`, now, now);

  let ad = null;
  for (const c of candidates) {
    const zones = safeParse(c.cible_zones) || [];
    if (zones.length && !zones.includes('international')) {
      if (!user) continue;
      let geoOk = false;
      if ((zones.includes('ville') || zones.includes('commune')) && c.cible_ville && user.ville === c.cible_ville) geoOk = true;
      if (!geoOk && zones.includes('departement') && c.cible_departement && user.departement_exercice === c.cible_departement) geoOk = true;
      if (!geoOk && zones.includes('region') && c.cible_region && user.region_exercice === c.cible_region) geoOk = true;
      const cp = safeParse(c.cible_pays);
      if (!geoOk && zones.includes('pays') && Array.isArray(cp) && cp.length && cp.includes(user.pays)) geoOk = true;
      if (!geoOk) continue;
    } else {
      // Rétrocompatibilité : ancien ciblage cible_pays seul, sans cible_zones défini
      const cp = safeParse(c.cible_pays);
      if (Array.isArray(cp) && cp.length && (!user || !cp.includes(user.pays))) continue;
    }
    const cibleListes = safeParse(c.cible_listes) || [];
    if (cibleListes.length) {
      if (!user) continue;
      const ph = cibleListes.map(() => '?').join(',');
      const membre = await db.prepare(`SELECT 1 FROM listes_diffusion_contacts WHERE liste_id IN (${ph}) AND user_id=? LIMIT 1`).get(...cibleListes, user.id);
      if (!membre) continue;
    }
    ad = c;
    break;
  }
  if (!ad) return sendJSON(res, 200, { ad: null });

  db.prepare("UPDATE publicites SET nb_impressions=nb_impressions+1, updated_at=datetime('now') WHERE id=?").run(ad.id);
  sendJSON(res, 200, { ad: {
    id: ad.id, media_type: ad.media_type, media_url: ad.media_url,
    titre: ad.titre, description: ad.description, cta: ad.cta, lien_url: ad.lien_url,
  }});
});

