/* ---------- Helper : enrichir un post ---------- */
async function enrichPost(p, cu) {
  const reactions = await db.prepare("SELECT type,COUNT(*) AS n FROM fil_reactions WHERE post_id=? GROUP BY type").all(p.id);
  const counts = {}; reactions.forEach(r => counts[r.type] = r.n);
  const _nbComm = await db.prepare("SELECT COUNT(*) AS n FROM fil_commentaires WHERE post_id=?").get(p.id);
  const nb_commentaires = _nbComm ? _nbComm.n : 0;
  const user_a_aime = cu ? !!await db.prepare("SELECT 1 FROM fil_reactions WHERE post_id=? AND user_id=? AND type='like'").get(p.id, cu.id) : false;

  let auteur = {}, auteur_certif = null;
  if (p.auteur_id) {
    const u = await db.prepare("SELECT photo_url,banner_url,ville,pays,nationalite1,titre_pro,bio,situation_pro,theme_couleur,role FROM users WHERE id=?").get(p.auteur_id);
    if (u) {
      auteur = u;
      if (u.role === "initiative") {
        const init = await db.prepare("SELECT id FROM initiatives WHERE owner_user_id=?").get(p.auteur_id);
        if (init) auteur_certif = getCertif(init.id);
      }
    }
  }
  // Fallback : posts seedés sans auteur_id — chercher par nom d'initiative
  if (!auteur_certif && p.auteur_nom) {
    const initByName = await db.prepare("SELECT id FROM initiatives WHERE nom=? OR sigle=?").get(p.auteur_nom, p.auteur_nom);
    if (initByName) auteur_certif = getCertif(initByName.id);
  }

  // Score de popularité : likes×3 + commentaires×2 + reposts×1
  const _nbReposts = await db.prepare("SELECT COUNT(*) AS n FROM fil_posts WHERE original_post_id=?").get(p.id);
  const nb_reposts = _nbReposts ? _nbReposts.n : 0;
  const score = (counts.like||0)*3 + nb_commentaires*2 + nb_reposts;

  let original_post = null;
  if ((p.type === "repost" || p.pub_type === "repost") && p.original_post_id) {
    const orig = await db.prepare("SELECT * FROM fil_posts WHERE id=?").get(p.original_post_id);
    if (orig) {
      let orig_auteur = {};
      if (orig.auteur_id) {
        const ou = await db.prepare("SELECT photo_url,banner_url,ville,pays,nationalite1,titre_pro,bio,situation_pro,theme_couleur FROM users WHERE id=?").get(orig.auteur_id);
        if (ou) orig_auteur = ou;
      }
      const orig_reactions = await db.prepare("SELECT type,COUNT(*) AS n FROM fil_reactions WHERE post_id=? GROUP BY type").all(orig.id);
      const orig_counts = {}; orig_reactions.forEach(r => orig_counts[r.type] = r.n);
      original_post = { ...orig, reactions: orig_counts, auteur_profil: orig_auteur };
    }
  }
  const auteur_accreditations = p.auteur_id
    ? (await db.prepare("SELECT type FROM compte_accreditations WHERE user_id=? AND statut='active'").all(p.auteur_id)).map(a => a.type)
    : [];
  return { ...p, reactions: counts, nb_commentaires, user_a_aime, auteur_profil: auteur, auteur_certif, auteur_accreditations, score, original_post };
}

/* ---------- Fil intelligent ---------- */
/* ── Cartes Vitrine dans le fil (vitrines/catalogues/promotions/meilleures ventes) ──
   Calculées à la volée (pas stockées dans fil_posts). Score = localisation + nouveauté + popularité. */
function filNorm(s) { return String(s||"").toLowerCase().trim().normalize("NFD").replace(/[̀-ͯ]/g, ""); }

async function buildVitrineCards(cu, capCount) {
  const cards = [];
  const now = Date.now();

  const vitrines = await db.prepare(`
    SELECT id, nom, owner_user_id, vitrine_ville, vitrine_region, vitrine_pays, vitrine_banniere_url, created_at, vues
    FROM initiatives WHERE vitrine_active=1 AND owner_user_id IS NOT NULL ORDER BY created_at DESC LIMIT 20
  `).all();
  vitrines.forEach(v => cards.push({
    sous_type: 'vitrine', initiative_id: v.id, owner_user_id: v.owner_user_id, initiative_nom: v.nom,
    ville: v.vitrine_ville, region: v.vitrine_region, pays: v.vitrine_pays, image_url: v.vitrine_banniere_url,
    titre: v.nom, description: null, created_at: v.created_at, pop: Number(v.vues)||0,
  }));

  const catalogues = await db.prepare(`
    SELECT c.id, c.nom, c.description, c.image_url, c.created_at, i.id AS initiative_id, i.owner_user_id, i.nom AS initiative_nom,
      i.vitrine_ville, i.vitrine_region, i.vitrine_pays
    FROM catalogues_vitrine c JOIN initiatives i ON i.id=c.initiative_id
    WHERE c.statut='visible' AND i.vitrine_active=1 ORDER BY c.created_at DESC LIMIT 20
  `).all();
  catalogues.forEach(c => cards.push({
    sous_type: 'catalogue', initiative_id: c.initiative_id, owner_user_id: c.owner_user_id, initiative_nom: c.initiative_nom,
    ville: c.vitrine_ville, region: c.vitrine_region, pays: c.vitrine_pays, image_url: c.image_url,
    titre: c.nom, description: c.description, created_at: c.created_at, pop: 0,
  }));

  const promotions = await db.prepare(`
    SELECT pr.id, pr.titre, pr.description, pr.photo_url, pr.prix_initial, pr.prix_promo, pr.date_fin, pr.created_at,
      i.id AS initiative_id, i.owner_user_id, i.nom AS initiative_nom, i.vitrine_ville, i.vitrine_region, i.vitrine_pays
    FROM vitrine_promotions pr JOIN initiatives i ON i.id=pr.initiative_id
    WHERE pr.date_fin >= datetime('now') AND i.vitrine_active=1 ORDER BY pr.created_at DESC LIMIT 20
  `).all();
  promotions.forEach(p => cards.push({
    sous_type: 'promotion', initiative_id: p.initiative_id, owner_user_id: p.owner_user_id, initiative_nom: p.initiative_nom,
    ville: p.vitrine_ville, region: p.vitrine_region, pays: p.vitrine_pays, image_url: p.photo_url,
    titre: p.titre, description: p.description, prix_initial: p.prix_initial, prix_promo: p.prix_promo,
    date_fin: p.date_fin, created_at: p.created_at, pop: 0,
  }));

  const meilleuresVentes = await db.prepare(`
    SELECT p.id, p.nom, p.description, p.prix, p.devise, p.photos_json, p.created_at,
      i.id AS initiative_id, i.owner_user_id, i.nom AS initiative_nom, i.vitrine_ville, i.vitrine_region, i.vitrine_pays,
      COUNT(c.id) AS nb_ventes
    FROM produits_vitrine p JOIN commandes_vitrine c ON c.produit_id=p.id JOIN initiatives i ON i.id=p.initiative_id
    WHERE (p.statut IS NULL OR p.statut != 'masque') AND i.vitrine_active=1
    GROUP BY p.id ORDER BY nb_ventes DESC LIMIT 3
  `).all();
  meilleuresVentes.forEach(m => {
    const photos = safeParse(m.photos_json || "[]");
    cards.push({
      sous_type: 'meilleure_vente', initiative_id: m.initiative_id, owner_user_id: m.owner_user_id, initiative_nom: m.initiative_nom,
      ville: m.vitrine_ville, region: m.vitrine_region, pays: m.vitrine_pays, image_url: photos[0] || null,
      titre: m.nom, description: m.description, prix: m.prix, devise: m.devise, nb_ventes: m.nb_ventes,
      created_at: m.created_at, pop: Number(m.nb_ventes)||0,
    });
  });

  // Score = localisation + nouveauté (dégressif 14j) + popularité
  const cuVille = cu ? filNorm(cu.ville) : "", cuRegion = cu ? filNorm(cu.region) : "", cuPays = cu ? filNorm(cu.pays) : "";
  cards.forEach(c => {
    let locBonus = 0;
    if (cuVille && filNorm(c.ville).includes(cuVille)) locBonus = 30;
    else if (cuRegion && filNorm(c.region).includes(cuRegion)) locBonus = 15;
    else if (cuPays && filNorm(c.pays).includes(cuPays)) locBonus = 5;
    const ageDays = (now - new Date(c.created_at).getTime()) / (24*3600*1000);
    const recencyBonus = Math.max(0, 14 - ageDays);
    c.score = locBonus + recencyBonus + Math.min(20, c.pop);
  });

  // Anti-répétition : au plus 1 carte par initiative (garde la mieux notée)
  const parInitiative = new Map();
  cards.forEach(c => {
    const existing = parInitiative.get(c.initiative_id);
    if (!existing || c.score > existing.score) parInitiative.set(c.initiative_id, c);
  });

  const finalCards = [...parInitiative.values()].sort((a,b) => b.score - a.score).slice(0, capCount);
  return finalCards.map(c => ({
    id: `vc-${c.sous_type}-${c.initiative_id}-${c.titre ? filNorm(c.titre).slice(0,8) : ''}`,
    type: 'carte_vitrine', sous_type: c.sous_type, initiative_id: c.initiative_id, owner_user_id: c.owner_user_id,
    initiative_nom: c.initiative_nom, ville: c.ville, region: c.region, pays: c.pays, image_url: c.image_url,
    titre: c.titre, description: c.description, prix: c.prix, prix_initial: c.prix_initial, prix_promo: c.prix_promo,
    devise: c.devise, nb_ventes: c.nb_ventes, date_fin: c.date_fin, created_at: c.created_at, source: 'vitrine',
  }));
}

route("GET", "/api/fil", async (req, res, params, body, query) => {
  const cu = await getCurrentUser(req);
  const mode  = query.mode  || "tous";   // suivis | populaires | articles | tous
  const page  = Math.max(1, Number(query.page) || 1);
  const limit = Math.min(Number(query.limit) || 20, 50);
  const offset = (page - 1) * limit;

  // ─── MODE SUIVIS ───────────────────────────────────────────────────────────
  if (mode === "suivis" && cu) {
    // IDs des utilisateurs suivis
    const followedUsers = (await db.prepare("SELECT followed_id FROM user_follows WHERE follower_id=?").all(cu.id)).map(r => r.followed_id);
    // IDs des initiatives suivies → propriétaires (owner_user_id)
    const followedInits = (await db.prepare("SELECT initiative_id FROM abonnements WHERE user_id=?").all(cu.id)).map(r => r.initiative_id);
    const initAuthorIds = followedInits.length
      ? (await db.prepare(`SELECT owner_user_id AS id FROM initiatives WHERE id IN (${followedInits.map(()=>"?").join(",")}) AND owner_user_id IS NOT NULL`).all(...followedInits)).map(r => r.id)
      : [];
    const allIds = [...new Set([...followedUsers, ...initAuthorIds])];

    if (!allIds.length) {
      return sendJSON(res, 200, { posts: [], total: 0, page, pages: 0, mode, conseil: "Suivez des personnes et des initiatives pour voir leurs publications ici." });
    }
    const placeholders = allIds.map(()=>"?").join(",");
    const total = (await db.prepare(`SELECT COUNT(*) AS n FROM fil_posts p JOIN users u ON u.id=p.auteur_id WHERE p.auteur_id IN (${placeholders}) AND (u.is_demo IS NULL OR u.is_demo=FALSE)`).get(...allIds))?.n;
    const posts = await db.prepare(`SELECT p.* FROM fil_posts p JOIN users u ON u.id=p.auteur_id WHERE p.auteur_id IN (${placeholders}) AND (u.is_demo IS NULL OR u.is_demo=FALSE) ORDER BY p.created_at DESC LIMIT ? OFFSET ?`).all(...allIds, limit, offset);
    return sendJSON(res, 200, { posts: await Promise.all(posts.map(async p => ({ ...await enrichPost(p, cu), source: "suivi" }))), total, page, pages: Math.ceil(total/limit), mode });
  }

  // ─── MODE POPULAIRES ───────────────────────────────────────────────────────
  if (mode === "populaires") {
    // Fenêtre 30 jours, score = likes×3 + commentaires×2 + reposts
    const since = new Date(Date.now() - 30*24*60*60*1000).toISOString().slice(0,19).replace("T"," ");
    const posts = await db.prepare(`
      SELECT p.*,
        (SELECT COUNT(*) FROM fil_reactions r WHERE r.post_id=p.id AND r.type='like')*3 +
        (SELECT COUNT(*) FROM fil_commentaires c WHERE c.post_id=p.id)*2 +
        (SELECT COUNT(*) FROM fil_posts rp WHERE rp.original_post_id=p.id) AS score_calc
      FROM fil_posts p JOIN users u ON u.id=p.auteur_id
      WHERE p.created_at >= ? AND (p.pub_type IS NULL OR p.pub_type != 'repost') AND (p.type IS NULL OR p.type != 'repost')
        AND (u.is_demo IS NULL OR u.is_demo=FALSE)
      ORDER BY score_calc DESC, p.created_at DESC
      LIMIT ? OFFSET ?
    `).all(since, limit, offset);
    const _totalPop = await db.prepare(`SELECT COUNT(*) AS n FROM fil_posts p JOIN users u ON u.id=p.auteur_id WHERE p.created_at >= ? AND (p.pub_type IS NULL OR p.pub_type != 'repost') AND (u.is_demo IS NULL OR u.is_demo=FALSE)`).get(since);
    const total = _totalPop ? _totalPop.n : 0;
    return sendJSON(res, 200, { posts: await Promise.all(posts.map(async p => ({ ...await enrichPost(p, cu), source: "populaire" }))), total, page, pages: Math.ceil(total/limit), mode });
  }

  // ─── MODE ARTICLES MIS EN AVANT ────────────────────────────────────────────
  if (mode === "articles") {
    const posts = await db.prepare(`
      SELECT p.* FROM fil_posts p JOIN users u ON u.id=p.auteur_id
      WHERE (p.pub_type='article' OR p.type='article') AND (u.is_demo IS NULL OR u.is_demo=FALSE)
      ORDER BY p.created_at DESC LIMIT ? OFFSET ?
    `).all(limit, offset);
    const _totalArt = await db.prepare("SELECT COUNT(*) AS n FROM fil_posts p JOIN users u ON u.id=p.auteur_id WHERE (p.pub_type='article' OR p.type='article') AND (u.is_demo IS NULL OR u.is_demo=FALSE)").get();
    const total = _totalArt ? _totalArt.n : 0;
    return sendJSON(res, 200, { posts: await Promise.all(posts.map(async p => ({ ...await enrichPost(p, cu), source: "article" }))), total, page, pages: Math.ceil(total/limit), mode });
  }

  // ─── MODE TOUS (fil global enrichi) ────────────────────────────────────────
  // Algorithme : suivis en premier, puis populaires, puis reste chronologique
  let orderedIds = new Set();
  const allPosts = [];

  if (cu) {
    // 1) Posts des profils/initiatives suivis (récents d'abord)
    const followedUsers = (await db.prepare("SELECT followed_id FROM user_follows WHERE follower_id=?").all(cu.id)).map(r => r.followed_id);
    const followedInits = (await db.prepare("SELECT initiative_id FROM abonnements WHERE user_id=?").all(cu.id)).map(r => r.initiative_id);
    const initOwners = followedInits.length
      ? (await db.prepare(`SELECT owner_user_id AS id FROM initiatives WHERE id IN (${followedInits.map(()=>"?").join(",")}) AND owner_user_id IS NOT NULL`).all(...followedInits)).map(r => r.id)
      : [];
    const followedAll = [...new Set([...followedUsers, ...initOwners])];
    if (followedAll.length) {
      const ph = followedAll.map(()=>"?").join(",");
      (await db.prepare(`SELECT p.* FROM fil_posts p JOIN users u ON u.id=p.auteur_id WHERE p.auteur_id IN (${ph}) AND (u.is_demo IS NULL OR u.is_demo=FALSE) ORDER BY p.created_at DESC LIMIT 10`).all(...followedAll))
        .forEach(p => { if(!orderedIds.has(p.id)){ orderedIds.add(p.id); allPosts.push({ ...p, source:"suivi" }); } });
    }
  }

  // 2) Reste du fil — classé par la loi de priorité (préférences Programmation > habitudes OZ > proximité géo > fraîcheur)
  {
    const excludeClause = orderedIds.size ? `AND p.id NOT IN (${[...orderedIds].map(()=>"?").join(",")})` : "";
    const excludeArgs = orderedIds.size ? [...orderedIds] : [];
    const since90 = new Date(Date.now() - 90*24*60*60*1000).toISOString().slice(0,19).replace("T"," ");
    const candidats = await db.prepare(`
      SELECT p.* FROM fil_posts p JOIN users u ON u.id=p.auteur_id
      WHERE p.created_at >= ? ${excludeClause} AND (u.is_demo IS NULL OR u.is_demo=FALSE)
      ORDER BY p.created_at DESC LIMIT 200
    `).all(since90, ...excludeArgs);

    let filPrefs = {};
    let behaviorMap = {};
    let meVillePays = { ville: null, pays: null };
    let recentAuteurs = new Set();
    let recentTermes = [];
    if (cu) {
      try {
        const row = await db.prepare("SELECT programmation_json FROM users WHERE id=?").get(cu.id);
        filPrefs = JSON.parse(row?.programmation_json || '{}').fil || {};
      } catch (_) { filPrefs = {}; }
      const meRow = await db.prepare("SELECT ville, pays FROM users WHERE id=?").get(cu.id);
      meVillePays = { ville: meRow?.ville || null, pays: meRow?.pays || null };
      // Priorité 3 : affinité par catégorie déduite des likes/commentaires ET du temps passé (dwell)
      const interactions = await db.prepare(`
        SELECT p.categorie AS categorie FROM fil_reactions r JOIN fil_posts p ON p.id=r.post_id WHERE r.user_id=? AND p.categorie IS NOT NULL
        UNION ALL
        SELECT p.categorie AS categorie FROM fil_commentaires c JOIN fil_posts p ON p.id=c.post_id WHERE c.auteur_id=? AND p.categorie IS NOT NULL
      `).all(cu.id, cu.id);
      interactions.forEach(r => { behaviorMap[r.categorie] = (behaviorMap[r.categorie] || 0) + 1; });
      const dwellRows = await db.prepare(`
        SELECT p.categorie AS categorie, SUM(d.duree_sec) AS total
        FROM fil_post_dwell d JOIN fil_posts p ON p.id=d.post_id
        WHERE d.user_id=? AND p.categorie IS NOT NULL GROUP BY p.categorie
      `).all(cu.id);
      dwellRows.forEach(r => { behaviorMap[r.categorie] = (behaviorMap[r.categorie] || 0) + Math.floor((r.total || 0) / 20); });
      // Priorité 3 : profils récemment visités (boost transitoire, hors comptes déjà suivis)
      (await db.prepare(`SELECT DISTINCT profil_user_id FROM profil_visites WHERE visiteur_id=? ORDER BY created_at DESC LIMIT 50`).all(cu.id))
        .forEach(r => recentAuteurs.add(r.profil_user_id));
      // Priorité 3 : recherches récentes (les termes recherchés augmentent la pertinence des posts qui les contiennent)
      recentTermes = (await db.prepare(`SELECT DISTINCT requete FROM recherches_utilisateur WHERE user_id=? ORDER BY created_at DESC LIMIT 15`).all(cu.id))
        .map(r => (r.requete || '').toLowerCase()).filter(Boolean);
    }
    const prefsCategories = Array.isArray(filPrefs.categories) && filPrefs.categories.length ? filPrefs.categories : null;
    const prefsOrigines = Array.isArray(filPrefs.origines) && filPrefs.origines.length && !filPrefs.origines.includes('Toutes les origines') ? filPrefs.origines : null;

    const scored = candidats.map(p => {
      let score = 0;
      // Priorité 2 : préférences Programmation
      if (prefsCategories && p.categorie && prefsCategories.includes(p.categorie)) score += 1000;
      if (prefsOrigines && p.localisation_pays && prefsOrigines.includes(p.localisation_pays)) score += 200;
      // Priorité 3 : habitudes (affinité catégorie via likes/commentaires/temps passé, plafonnée)
      if (p.categorie && behaviorMap[p.categorie]) score += Math.min(behaviorMap[p.categorie] * 50, 500);
      // Priorité 3 : profil de l'auteur récemment consulté
      if (recentAuteurs.has(p.auteur_id)) score += 300;
      // Priorité 3 : le contenu correspond à une recherche récente
      if (p.contenu && recentTermes.some(t => p.contenu.toLowerCase().includes(t))) score += 250;
      // Priorité 4 : proximité géographique
      if (meVillePays.ville && p.localisation_ville && p.localisation_ville === meVillePays.ville) score += 400;
      else if (meVillePays.pays && p.localisation_pays && p.localisation_pays === meVillePays.pays) score += 150;
      // Priorité 5 : fraîcheur (tie-break infinitésimal, ne dépasse jamais un écart de score entier)
      score += (new Date(p.created_at).getTime() || 0) / 1e15;
      return { p, score };
    });
    scored.sort((a, b) => b.score - a.score);
    scored.forEach(({ p }) => { if (!orderedIds.has(p.id)) { orderedIds.add(p.id); allPosts.push({ ...p, source: "fil" }); } });
  }

  // 5) Cartes vitrine (vitrines/catalogues/promotions/meilleures ventes) — intercalées, plafonnées à ~30%
  try {
    const capCount = Math.max(1, Math.floor(allPosts.length * 0.3));
    const vitrineCards = await buildVitrineCards(cu, capCount);
    const merged = [];
    let vi = 0;
    allPosts.forEach((p, idx) => {
      merged.push(p);
      if ((idx + 1) % 4 === 0 && vi < vitrineCards.length) merged.push(vitrineCards[vi++]);
    });
    while (vi < vitrineCards.length) merged.push(vitrineCards[vi++]);
    allPosts.length = 0;
    allPosts.push(...merged);
  } catch (e) { /* le fil classique doit toujours fonctionner même si les cartes vitrine échouent */ }

  // Pagination sur le résultat fusionné
  const total = allPosts.length;
  const paginated = allPosts.slice(offset, offset + limit);
  sendJSON(res, 200, {
    posts: await Promise.all(paginated.map(p => p.type === 'carte_vitrine' ? p : enrichPost(p, cu))),
    total, page, pages: Math.ceil(total/limit), mode
  });
});

/* ---------- Follow / Unfollow utilisateur ---------- */
route("POST", "/api/follow/:id", async (req, res, params) => {
  const cu = await getCurrentUser(req);
  if (!cu) return sendJSON(res, 401, { error: "Connexion requise." });
  const targetId = Number(params.id);
  if (targetId === cu.id) return sendJSON(res, 400, { error: "Vous ne pouvez pas vous suivre vous-même." });
  try {
    db.prepare("INSERT INTO user_follows (follower_id, followed_id) VALUES (?,?)").run(cu.id, targetId);
    creerNotif(targetId, "abonnement", `${cu.nom} vous suit maintenant`, "", { user_id: cu.id });
  } catch(e) { /* déjà suivi */ }
  sendJSON(res, 200, { ok: true, suivi: true });
});

route("DELETE", "/api/follow/:id", async (req, res, params) => {
  const cu = await getCurrentUser(req);
  if (!cu) return sendJSON(res, 401, { error: "Connexion requise." });
  await db.prepare("DELETE FROM user_follows WHERE follower_id=? AND followed_id=?").run(cu.id, Number(params.id));
  sendJSON(res, 200, { ok: true, suivi: false });
});

/* ---------- Static file server (frontend existant) ---------- */
async function serveStatic(req, res, pathname) {
  let filePath = path.join(ROOT, pathname === "/" ? "index.html" : pathname);
  if (!filePath.startsWith(ROOT)) return send(res, 403, "Forbidden");
  fs.stat(filePath, (err, stat) => {
    if (err || !stat.isFile()) return send(res, 404, "Not found");
    const ext = path.extname(filePath).toLowerCase();
    const headers = { "Content-Type": MIME[ext] || "application/octet-stream" };
    // Le HTML doit toujours être revalidé (évite qu'un navigateur serve une vieille page en cache).
    // Les JS/CSS restent revalidés aussi mais peuvent être mis en cache court.
    if (ext === ".html") headers["Cache-Control"] = "no-cache, must-revalidate";
    else if (ext === ".js" || ext === ".css") headers["Cache-Control"] = "no-cache";
    res.writeHead(200, headers);
    fs.createReadStream(filePath).pipe(res);
  });
}

/* ================================================================
   HANDLER PRINCIPAL (utilisé en local ET en Vercel serverless)
   ================================================================ */
/* ===== MODULE RÉSEAU & DIASPORA ===== */

route("GET", "/api/admin/reseau", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  const parPays     = await db.prepare("SELECT pays, COUNT(*) n FROM users WHERE pays IS NOT NULL GROUP BY pays ORDER BY n DESC LIMIT 12").all();
  const parNat1     = await db.prepare("SELECT nationalite1 AS nat, COUNT(*) n FROM users WHERE nationalite1 IS NOT NULL GROUP BY nat ORDER BY n DESC LIMIT 10").all();
  const parNat2     = await db.prepare("SELECT nationalite2 AS nat, COUNT(*) n FROM users WHERE nationalite2 IS NOT NULL GROUP BY nat ORDER BY n DESC LIMIT 8").all();
  const parOrig1    = []; // "origine1" n'existe que sur la table initiatives, pas sur users — pas de données pertinentes ici
  const parVille    = await db.prepare("SELECT ville, pays, COUNT(*) n FROM users WHERE ville IS NOT NULL GROUP BY ville ORDER BY n DESC LIMIT 10").all();

  // Top pays actifs = pays avec le plus d'activité (user_activity JOIN users)
  const paysActifs  = await db.prepare(`
    SELECT u.pays, COUNT(DISTINCT a.user_id) n
    FROM user_activity a JOIN users u ON u.id=a.user_id
    WHERE a.date >= date('now','-30 days') AND u.pays IS NOT NULL
    GROUP BY u.pays ORDER BY n DESC LIMIT 8
  `).all();

  // Croissance internationale : nombre de pays distincts avec inscrits ce mois
  const paysNouveaux = await db.prepare(`
    SELECT COUNT(DISTINCT pays) n FROM users
    WHERE pays IS NOT NULL AND created_at >= datetime('now','-30 days')
  `).get().n;

  sendJSON(res, 200, { par_pays: parPays, par_nationalite: parNat1, par_nationalite2: parNat2,
    par_origine: parOrig1, par_ville: parVille, pays_actifs: paysActifs,
    pays_nouveaux_mois: paysNouveaux });
});

/* ===== MODULE RÉSEAU PROFESSIONNEL ===== */

// Liste paginée des professionnels avec filtres
route("GET", "/api/admin/reseau-pro", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  const q = req.query || {};
  const page  = Math.max(1, parseInt(q.page) || 1);
  const limit = Math.min(100, parseInt(q.limit) || 30);
  const offset = (page - 1) * limit;

  let where = ["u.role IN ('utilisateur','initiative','collectivite','officiel')"];
  const params = [];

  if (q.pays)     { where.push("u.pays = ?");         params.push(q.pays); }
  if (q.ville)    { where.push("u.ville LIKE ?");      params.push('%' + q.ville + '%'); }
  if (q.origine)  { where.push("(u.origine1 = ? OR u.origine2 = ?)"); params.push(q.origine, q.origine); }
  if (q.nationalite) { where.push("(u.nationalite1 = ? OR u.nationalite2 = ?)"); params.push(q.nationalite, q.nationalite); }
  if (q.domaine)  { where.push("u.situation_pro LIKE ?"); params.push('%' + q.domaine + '%'); }
  if (q.role)     { where.push("u.role = ?");          params.push(q.role); }
  if (q.actif === '1') {
    where.push("EXISTS (SELECT 1 FROM user_activity a WHERE a.user_id=u.id AND a.date >= date('now','-30 days'))");
  }

  const whereStr = where.join(' AND ');

  const total = (await db.prepare(`SELECT COUNT(*) n FROM users u WHERE ${whereStr}`).get(...params))?.n;
  const rows  = await db.prepare(`
    SELECT u.id, u.nom, u.prenom, u.titre_pro, u.situation_pro,
           u.ville, u.pays, u.origine1 AS pays_origine, u.nationalite1 AS nationalite,
           u.role, substr(u.created_at,1,10) AS date_inscription,
           CASE WHEN a.user_id IS NOT NULL THEN 1 ELSE 0 END AS actif_30j
    FROM users u
    LEFT JOIN (
      SELECT DISTINCT user_id FROM user_activity WHERE date >= date('now','-30 days')
    ) a ON a.user_id = u.id
    WHERE ${whereStr}
    ORDER BY u.created_at DESC
    LIMIT ? OFFSET ?
  `).all(...params, limit, offset);

  sendJSON(res, 200, { total, page, limit, professionnels: rows });
});

// Statistiques agrégées du réseau pro
route("GET", "/api/admin/reseau-pro/stats", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  const roleFilter = "role IN ('utilisateur','initiative','collectivite','officiel')";

  const total        = (await db.prepare(`SELECT COUNT(*) n FROM users WHERE ${roleFilter}`).get())?.n;
  const actifs30j    = (await db.prepare(`SELECT COUNT(DISTINCT u.id) n FROM users u JOIN user_activity a ON a.user_id=u.id WHERE a.date >= date('now','-30 days') AND u.${roleFilter}`).get())?.n;
  const nouveaux30j  = (await db.prepare(`SELECT COUNT(*) n FROM users WHERE ${roleFilter} AND created_at >= datetime('now','-30 days')`).get())?.n;

  const parVille     = await db.prepare(`SELECT ville, pays, COUNT(*) n FROM users WHERE ${roleFilter} AND ville IS NOT NULL GROUP BY ville ORDER BY n DESC LIMIT 15`).all();
  const parPays      = await db.prepare(`SELECT pays, COUNT(*) n FROM users WHERE ${roleFilter} AND pays IS NOT NULL GROUP BY pays ORDER BY n DESC LIMIT 12`).all();
  const parOrigine   = await db.prepare(`SELECT origine1 AS origine, COUNT(*) n FROM users WHERE ${roleFilter} AND origine1 IS NOT NULL GROUP BY origine ORDER BY n DESC LIMIT 12`).all();
  const parNat       = await db.prepare(`SELECT nationalite1 AS nationalite, COUNT(*) n FROM users WHERE ${roleFilter} AND nationalite1 IS NOT NULL GROUP BY nationalite ORDER BY n DESC LIMIT 10`).all();
  const parRole      = await db.prepare(`SELECT role, COUNT(*) n FROM users WHERE ${roleFilter} GROUP BY role ORDER BY n DESC`).all();
  const parSitPro    = await db.prepare(`SELECT situation_pro, COUNT(*) n FROM users WHERE ${roleFilter} AND situation_pro IS NOT NULL GROUP BY situation_pro ORDER BY n DESC LIMIT 10`).all();

  // Top villes actives (activité 30j)
  const villesActives = await db.prepare(`
    SELECT u.ville, u.pays, COUNT(DISTINCT a.user_id) n
    FROM user_activity a JOIN users u ON u.id=a.user_id
    WHERE a.date >= date('now','-30 days') AND u.${roleFilter} AND u.ville IS NOT NULL
    GROUP BY u.ville ORDER BY n DESC LIMIT 10
  `).all();

  // Évolution inscriptions 6 derniers mois
  const evolution = await db.prepare(`
    SELECT substr(created_at,1,7) AS mois, COUNT(*) n
    FROM users WHERE ${roleFilter}
    GROUP BY mois ORDER BY mois DESC LIMIT 6
  `).all().reverse();

  sendJSON(res, 200, {
    totaux: { total, actifs_30j: actifs30j, nouveaux_30j: nouveaux30j },
    par_ville: parVille, par_pays: parPays, par_origine: parOrigine,
    par_nationalite: parNat, par_role: parRole, par_situation_pro: parSitPro,
    villes_actives: villesActives, evolution
  });
});

/* ===== DIASPORA DONNÉES STATISTIQUES ===== */

route("GET", "/api/admin/diaspora-stats", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  try {
  // KPIs globaux
  const totalInit    = (await db.prepare("SELECT COUNT(*) n FROM initiatives").get())?.n;
  const totalEvents  = (await db.prepare("SELECT COUNT(*) n FROM evenements WHERE statut='ouvert'").get())?.n;
  const totalForm    = (await db.prepare("SELECT COUNT(*) n FROM formations").get())?.n;
  const totalAbos    = (await db.prepare("SELECT COUNT(*) n FROM abonnements").get())?.n;
  const totalPays    = (await db.prepare("SELECT COUNT(DISTINCT pays) n FROM initiatives WHERE pays IS NOT NULL").get())?.n;
  const totalVilles  = (await db.prepare("SELECT COUNT(DISTINCT ville) n FROM initiatives WHERE ville IS NOT NULL").get())?.n;
  const actifs30j    = (await db.prepare("SELECT COUNT(DISTINCT i.id) n FROM initiatives i JOIN abonnements a ON a.initiative_id=i.id JOIN user_activity ua ON ua.user_id=a.user_id WHERE ua.date>=date('now','-30 days')").get())?.n;

  // Par domaine avec events + formations
  const parDomaine = await db.prepare(`
    SELECT domaine, COUNT(*) n,
      ROUND(AVG(COALESCE(vues,0)),0) AS moy_vues
    FROM initiatives WHERE domaine IS NOT NULL
    GROUP BY domaine ORDER BY n DESC LIMIT 12
  `).all();
  const eventsParDomaine = await db.prepare(`SELECT i.domaine, COUNT(*) n FROM evenements e JOIN initiatives i ON i.owner_user_id=e.owner_user_id WHERE i.domaine IS NOT NULL GROUP BY i.domaine ORDER BY n DESC LIMIT 10`).all();
  const formParDomaine   = await db.prepare(`SELECT domaine, COUNT(*) n FROM formations WHERE domaine IS NOT NULL GROUP BY domaine ORDER BY n DESC LIMIT 10`).all();

  // Par pays d'origine
  const parOrigine = await db.prepare(`
    SELECT nationalite1 AS pays_origine, COUNT(*) n
    FROM initiatives WHERE nationalite1 IS NOT NULL
    GROUP BY nationalite1 ORDER BY n DESC LIMIT 20
  `).all();

  // Par pays de résidence
  const parPaysResidence = await db.prepare(`
    SELECT pays, COUNT(*) n FROM initiatives WHERE pays IS NOT NULL
    GROUP BY pays ORDER BY n DESC LIMIT 20
  `).all();

  // Par ville (top 20)
  const parVille = await db.prepare(`
    SELECT ville, pays, COUNT(*) n,
      SUM(COALESCE(vues,0)) AS total_vues,
      (SELECT COUNT(*) FROM evenements e JOIN initiatives i2 ON i2.owner_user_id=e.owner_user_id WHERE i2.ville=i.ville) AS nb_events
    FROM initiatives i WHERE ville IS NOT NULL
    GROUP BY ville, pays ORDER BY n DESC LIMIT 20
  `).all();

  // Score d'activité par initiative (top 15)
  const topInitiatives = await db.prepare(`
    SELECT i.id, i.nom, i.slug, i.ville, i.pays, i.domaine,
      COALESCE(i.vues,0) AS nb_vues,
      (SELECT COUNT(*) FROM abonnements a WHERE a.initiative_id=i.id) AS nb_abonnes,
      (SELECT COUNT(*) FROM evenements e WHERE e.owner_user_id=i.owner_user_id) AS nb_events,
      (SELECT COUNT(*) FROM formations f WHERE f.owner_user_id=i.owner_user_id) AS nb_formations,
      MIN(100, ROUND(
        COALESCE(i.vues,0)*0.05 +
        (SELECT COUNT(*) FROM abonnements a WHERE a.initiative_id=i.id)*8.0 +
        (SELECT COUNT(*) FROM evenements e WHERE e.owner_user_id=i.owner_user_id)*12.0 +
        (SELECT COUNT(*) FROM formations f WHERE f.owner_user_id=i.owner_user_id)*10.0
      ,0)) AS score
    FROM initiatives i ORDER BY score DESC, nb_abonnes DESC LIMIT 15
  `).all();

  // Évolution mensuelle inscriptions initiatives (12 mois)
  const evolution = (await db.prepare(`
    SELECT substr(created_at,1,7) AS mois, COUNT(*) n
    FROM initiatives GROUP BY mois ORDER BY mois DESC LIMIT 12
  `).all()).reverse();

  // Évolution événements (12 mois)
  const evolutionEvents = (await db.prepare(`
    SELECT substr(created_at,1,7) AS mois, COUNT(*) n
    FROM evenements GROUP BY mois ORDER BY mois DESC LIMIT 12
  `).all()).reverse();

  // Tendances: comparer mois courant vs précédent par domaine
  const tendanceDomaine = await db.prepare(`
    SELECT domaine,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END) AS ce_mois,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END) AS mois_prec
    FROM initiatives WHERE domaine IS NOT NULL
    GROUP BY domaine
    HAVING SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END)>0
        OR SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END)>0
    ORDER BY (SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END)
            - SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END)) DESC LIMIT 8
  `).all();

  // Tendances villes
  const tendanceVille = await db.prepare(`
    SELECT ville,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END) AS ce_mois,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END) AS mois_prec
    FROM initiatives WHERE ville IS NOT NULL
    GROUP BY ville
    HAVING SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END)>0
        OR SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END)>0
    ORDER BY (SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END)
            - SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END)) DESC LIMIT 8
  `).all();

  sendJSON(res, 200, {
    kpi: { totalInit, totalEvents, totalForm, totalAbos, totalPays, totalVilles, actifs30j },
    par_domaine: parDomaine, events_par_domaine: eventsParDomaine, formations_par_domaine: formParDomaine,
    par_origine: parOrigine, par_pays_residence: parPaysResidence,
    par_ville: parVille, top_initiatives: topInitiatives,
    evolution, evolution_events: evolutionEvents,
    tendance_domaine: tendanceDomaine, tendance_ville: tendanceVille
  });
  } catch(e) {
    sendJSON(res, 500, SEC.safeError(e, "admin/diaspora-stats"));
  }
});

// Insights IA algorithmiques
route("GET", "/api/admin/diaspora-stats/insights", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  const insights = [];
  const alertes  = [];

  // Top domaine
  const topDom = await db.prepare(`SELECT domaine, COUNT(*) n FROM initiatives WHERE domaine IS NOT NULL GROUP BY domaine ORDER BY n DESC LIMIT 1`).get();
  if (topDom) insights.push({ type:'analyse', icone:'📊', texte:`Le domaine <strong>${topDom.domaine}</strong> domine avec ${topDom.n} initiatives enregistrées.` });

  // Top ville
  const topVille = await db.prepare(`SELECT ville, pays, COUNT(*) n FROM initiatives WHERE ville IS NOT NULL GROUP BY ville ORDER BY n DESC LIMIT 1`).get();
  if (topVille) insights.push({ type:'analyse', icone:'📍', texte:`<strong>${topVille.ville}</strong> (${topVille.pays||'—'}) est la ville avec la plus forte concentration d'initiatives diaspora (${topVille.n}).` });

  // Top pays d'origine
  const topOrigine = await db.prepare(`SELECT nationalite1 AS o, COUNT(*) n FROM initiatives WHERE nationalite1 IS NOT NULL GROUP BY nationalite1 ORDER BY n DESC LIMIT 1`).get();
  if (topOrigine) insights.push({ type:'analyse', icone:'🌍', texte:`La diaspora <strong>${topOrigine.o}</strong> est la plus représentée avec ${topOrigine.n} initiatives actives.` });

  // Croissance domaine ce mois
  const croissanceDom = await db.prepare(`
    SELECT domaine,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END) AS cm,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END) AS pm
    FROM initiatives WHERE domaine IS NOT NULL GROUP BY domaine HAVING pm>0
    ORDER BY (CAST(cm AS REAL)/pm) DESC LIMIT 1
  `).get();
  if (croissanceDom && croissanceDom.pm > 0) {
    const pct = Math.round(((croissanceDom.cm - croissanceDom.pm) / croissanceDom.pm) * 100);
    if (pct > 0) insights.push({ type:'tendance', icone:'📈', texte:`Les activités <strong>${croissanceDom.domaine}</strong> augmentent de <strong>+${pct}%</strong> ce mois par rapport au précédent.` });
    else if (pct < -10) alertes.push({ type:'alerte', icone:'⚠️', texte:`Baisse de ${Math.abs(pct)}% des nouvelles initiatives <strong>${croissanceDom.domaine}</strong> ce mois.` });
  }

  // Ville en croissance
  const croissanceVille = await db.prepare(`
    SELECT ville,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now') THEN 1 ELSE 0 END) AS cm,
      SUM(CASE WHEN substr(created_at,1,7)=strftime('%Y-%m','now','-1 month') THEN 1 ELSE 0 END) AS pm
    FROM initiatives WHERE ville IS NOT NULL GROUP BY ville HAVING pm>0
    ORDER BY (CAST(cm AS REAL)/pm) DESC LIMIT 1
  `).get();
  if (croissanceVille && croissanceVille.pm > 0 && croissanceVille.cm > croissanceVille.pm) {
    const pct = Math.round(((croissanceVille.cm - croissanceVille.pm) / croissanceVille.pm) * 100);
    if (pct >= 15) insights.push({ type:'tendance', icone:'🚀', texte:`<strong>${croissanceVille.ville}</strong> devient un hub émergent diaspora avec une croissance de <strong>+${pct}%</strong> ce mois.` });
  }

  // Score moyen
  const scoreMoy = (await db.prepare(`
    SELECT ROUND(AVG(
      MIN(100, COALESCE(nb_vues,0)*0.05 +
        (SELECT COUNT(*) FROM abonnements a WHERE a.initiative_id=i.id)*8.0 +
        (SELECT COUNT(*) FROM evenements e WHERE e.owner_user_id=i.owner_user_id)*12.0 +
        (SELECT COUNT(*) FROM formations f WHERE f.owner_user_id=i.owner_user_id)*10.0
      )
    ),1) AS s FROM initiatives i
  `).get())?.s || 0;
  insights.push({ type:'analyse', icone:'⚡', texte:`Score d'activité moyen des initiatives : <strong>${scoreMoy}/100</strong>.` });

  // Ratio événements/initiatives
  const nbInit = (await db.prepare("SELECT COUNT(*) n FROM initiatives").get())?.n;
  const nbEvt  = (await db.prepare("SELECT COUNT(*) n FROM evenements").get())?.n;
  if (nbInit > 0) {
    const ratio = (nbEvt / nbInit).toFixed(1);
    insights.push({ type:'analyse', icone:'📅', texte:`En moyenne, chaque initiative génère <strong>${ratio} événements</strong> enregistrés sur la plateforme.` });
  }

  sendJSON(res, 200, { insights, alertes });
});

/* ===== MODULE CONTENU ===== */

route("GET", "/api/admin/contenu", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  // Publications les plus engageantes (vue simulée = score engagement)
  const topPublications = await db.prepare(`
    SELECT p.id, p.contenu, p.auteur_nom, p.categorie, substr(p.created_at,1,10) AS date_pub,
      COUNT(DISTINCT r.id) AS nb_reactions, COUNT(DISTINCT c.id) AS nb_commentaires,
      (COUNT(DISTINCT r.id) * 2 + COUNT(DISTINCT c.id) * 3) AS score
    FROM fil_posts p
    LEFT JOIN fil_reactions r ON r.post_id = p.id
    LEFT JOIN fil_commentaires c ON c.post_id = p.id
    GROUP BY p.id ORDER BY score DESC LIMIT 10
  `).all();

  // Articles les plus partagés
  const topArticles = await db.prepare(`
    SELECT p.id, p.contenu, p.auteur_nom, substr(p.created_at,1,10) AS date_pub,
      COUNT(DISTINCT r.id) AS nb_reposts
    FROM fil_posts p
    LEFT JOIN fil_reactions r ON r.post_id = p.id AND r.type IN ('repost','partage')
    WHERE p.categorie = 'article' OR p.type = 'article'
    GROUP BY p.id ORDER BY nb_reposts DESC LIMIT 8
  `).all();

  // Initiatives les plus consultées (par nb_vues ou score engagement)
  const topInitiatives = await db.prepare(`
    SELECT i.id, i.nom, i.ville, i.pays, i.domaine, COALESCE(i.nb_vues,0) AS nb_vues,
      (SELECT COUNT(*) FROM user_follows f WHERE f.followed_id = u.id) AS nb_abonnes
    FROM initiatives i
    LEFT JOIN users u ON u.role='initiative' AND u.nom=i.nom
    ORDER BY nb_vues DESC, nb_abonnes DESC LIMIT 8
  `).all();

  // Utilisateurs les plus influents
  const topInfluents = await db.prepare(`
    SELECT u.id, u.nom, u.role, u.pays,
      COUNT(DISTINCT p.id) AS nb_posts,
      SUM(COALESCE(sub.nb_react,0)) AS nb_reactions_recues,
      (SELECT COUNT(*) FROM user_follows f WHERE f.followed_id = u.id) AS nb_abonnes,
      (COUNT(DISTINCT p.id)*2 + SUM(COALESCE(sub.nb_react,0))*3 + (SELECT COUNT(*) FROM user_follows f WHERE f.followed_id=u.id)*5) AS score
    FROM users u
    LEFT JOIN fil_posts p ON p.auteur_id = u.id
    LEFT JOIN (SELECT post_id, COUNT(*) nb_react FROM fil_reactions GROUP BY post_id) sub ON sub.post_id = p.id
    WHERE u.role IN ('utilisateur','initiative')
    GROUP BY u.id ORDER BY score DESC LIMIT 8
  `).all();

  // Types de contenu les plus performants
  const parCategorie = await db.prepare(`
    SELECT p.categorie, COUNT(DISTINCT p.id) AS nb_posts,
      AVG(sub.score) AS score_moy
    FROM fil_posts p
    LEFT JOIN (
      SELECT post_id,
        COUNT(DISTINCT r.id)*2 + COUNT(DISTINCT c.id)*3 AS score
      FROM fil_posts pp
      LEFT JOIN fil_reactions r ON r.post_id = pp.id
      LEFT JOIN fil_commentaires c ON c.post_id = pp.id
      GROUP BY pp.id
    ) sub ON sub.post_id = p.id
    WHERE p.categorie IS NOT NULL
    GROUP BY p.categorie ORDER BY score_moy DESC
  `).all();

  sendJSON(res, 200, { top_publications: topPublications, top_articles: topArticles,
    top_initiatives: topInitiatives, top_influents: topInfluents, par_categorie: parCategorie });
});

/* ===== MODULE FINANCES ===== */

route("GET", "/api/admin/finances", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  // Abonnés actifs (abonnements table)
  const abonnesActifs = (await db.prepare("SELECT COUNT(*) n FROM abonnements").get())?.n;

  // Transactions du mois courant
  const txMois = await db.prepare(`
    SELECT type, statut, SUM(montant) total, COUNT(*) nb
    FROM transactions
    WHERE date_transaction >= datetime('now','-30 days')
    GROUP BY type, statut
  `).all();

  // MRR = revenus abonnements réussis du mois en cours
  const mrrRow = await db.prepare(`
    SELECT COALESCE(SUM(montant),0) mrr FROM transactions
    WHERE type='abonnement' AND statut='reussi'
      AND date_transaction >= datetime('now','-30 days')
  `).get();
  const mrr = mrrRow.mrr;
  const arr = Math.round(mrr * 12 * 100) / 100;

  // Revenus par source
  const parSource = await db.prepare(`
    SELECT type, COALESCE(SUM(CASE WHEN statut='reussi' THEN montant ELSE 0 END),0) AS total,
      COUNT(CASE WHEN statut='reussi' THEN 1 END) AS nb_reussis,
      COUNT(CASE WHEN statut='echoue' THEN 1 END) AS nb_echoues
    FROM transactions
    WHERE date_transaction >= datetime('now','-30 days')
    GROUP BY type
  `).all();

  // Tendance revenus 30 jours
  const tendance30j = await db.prepare(`
    SELECT date(date_transaction) jour, SUM(CASE WHEN statut='reussi' THEN montant ELSE 0 END) revenu,
      COUNT(CASE WHEN statut='reussi' THEN 1 END) nb_ventes
    FROM transactions
    WHERE date_transaction >= datetime('now','-29 days')
    GROUP BY date(date_transaction) ORDER BY jour ASC
  `).all();

  // Paiements réussis / échoués / remboursements
  const paiementsStatuts = await db.prepare(`
    SELECT statut, COUNT(*) nb, COALESCE(SUM(montant),0) total
    FROM transactions GROUP BY statut
  `).all();

  // Top clients (utilisateurs avec le plus de dépenses)
  const topClients = await db.prepare(`
    SELECT u.nom, u.role, u.pays, COUNT(t.id) nb_achats,
      SUM(t.montant) total_depense
    FROM transactions t JOIN users u ON u.id = t.user_id
    WHERE t.statut='reussi'
    GROUP BY t.user_id ORDER BY total_depense DESC LIMIT 5
  `).all();

  // Taux de conversion (abonnés / total utilisateurs)
  const totalUtilisateurs = (await db.prepare("SELECT COUNT(*) n FROM users WHERE role IN ('utilisateur','initiative')").get())?.n;
  const tauxConversion = totalUtilisateurs > 0 ? ((abonnesActifs / totalUtilisateurs) * 100).toFixed(1) : "0.0";

  // Ventes du jour
  const venteJour = await db.prepare(`
    SELECT COUNT(*) nb, COALESCE(SUM(montant),0) total
    FROM transactions WHERE statut='reussi' AND date(date_transaction)=date('now')
  `).get();

  // Plans — performance
  const parPlan = await db.prepare(`
    SELECT p.nom, p.prix_mensuel, p.prix_annuel,
      COUNT(t.id) AS nb_ventes,
      COALESCE(SUM(CASE WHEN t.statut='reussi' THEN t.montant ELSE 0 END),0) AS revenu
    FROM plans_abonnement p
    LEFT JOIN transactions t ON t.plan_id = p.id AND t.date_transaction >= datetime('now','-30 days')
    GROUP BY p.id ORDER BY revenu DESC
  `).all();

  sendJSON(res, 200, {
    simulation: true,
    abonnes_actifs: abonnesActifs,
    mrr, arr,
    taux_conversion: tauxConversion,
    par_source: parSource,
    tendance_30j: tendance30j,
    paiements_statuts: paiementsStatuts,
    top_clients: topClients,
    vente_jour: venteJour,
    par_plan: parPlan
  });
});

/* ===== MODULE PAIEMENTS (Lot 1) — tableau de bord agrégé en lecture seule + moyens de paiement =====
   Ne touche à aucune table de paiement existante (wallet_transactions, commandes_vitrine,
   adhesion_paiements, transactions) : lecture seule, agrégation. Limité pour l'instant à
   carte bancaire / PayPal / virement bancaire. */

route("GET", "/api/admin/paiements/methodes", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });
  let methodes = await db.prepare("SELECT * FROM payment_methods_config ORDER BY code").all();
  if (!methodes.length) {
    methodes = [
      { code: 'carte', libelle: 'Carte bancaire', actif: 1 },
      { code: 'paypal', libelle: 'PayPal', actif: 1 },
      { code: 'virement', libelle: 'Virement bancaire', actif: 1 },
    ];
  }
  sendJSON(res, 200, { methodes });
});

route("PUT", "/api/admin/paiements/methodes/:code", async (req, res, params, body) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });
  if (!['carte', 'paypal', 'virement'].includes(params.code)) return sendJSON(res, 400, { error: "Moyen de paiement inconnu." });
  const libelles = { carte: 'Carte bancaire', paypal: 'PayPal', virement: 'Virement bancaire' };
  const actif = body.actif ? 1 : 0;
  const existe = await db.prepare("SELECT code FROM payment_methods_config WHERE code=?").get(params.code);
  if (existe) await db.prepare("UPDATE payment_methods_config SET actif=?, updated_at=datetime('now') WHERE code=?").run(actif, params.code);
  else await db.prepare("INSERT INTO payment_methods_config (code, libelle, actif) VALUES (?,?,?)").run(params.code, libelles[params.code], actif);
  sendJSON(res, 200, { ok: true });
});

route("GET", "/api/admin/paiements/dashboard", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  const auj = "date('now')", debutSemaine = "datetime('now','-7 days')", debutMois = "datetime('now','-30 days')";

  // Boutique (commandes_vitrine)
  let boutique = { revenu:0, reussis:0, en_attente:0, refuses:0, revenu_jour:0, revenu_semaine:0, revenu_mois:0 };
  try {
    boutique = await db.prepare(`
      SELECT
        COALESCE(SUM(CASE WHEN statut='traitee' THEN montant_total ELSE 0 END),0) AS revenu,
        COUNT(CASE WHEN statut='traitee' THEN 1 END) AS reussis,
        COUNT(CASE WHEN statut='en_attente' THEN 1 END) AS en_attente,
        COUNT(CASE WHEN statut='annulee' THEN 1 END) AS refuses,
        COALESCE(SUM(CASE WHEN statut='traitee' AND date(created_at)=${auj} THEN montant_total ELSE 0 END),0) AS revenu_jour,
        COALESCE(SUM(CASE WHEN statut='traitee' AND created_at>=${debutSemaine} THEN montant_total ELSE 0 END),0) AS revenu_semaine,
        COALESCE(SUM(CASE WHEN statut='traitee' AND created_at>=${debutMois} THEN montant_total ELSE 0 END),0) AS revenu_mois
      FROM commandes_vitrine
    `).get();
  } catch (_) {}

  // Adhésions
  let adhesions = { revenu:0, reussis:0, en_attente:0, refuses:0, rembourses:0, revenu_jour:0, revenu_semaine:0, revenu_mois:0 };
  let parDevise = [];
  try {
    adhesions = await db.prepare(`
      SELECT
        COALESCE(SUM(CASE WHEN statut='paye' THEN montant ELSE 0 END),0) AS revenu,
        COUNT(CASE WHEN statut='paye' THEN 1 END) AS reussis,
        COUNT(CASE WHEN statut='en_attente' THEN 1 END) AS en_attente,
        COUNT(CASE WHEN statut='echoue' THEN 1 END) AS refuses,
        COUNT(CASE WHEN statut='rembourse' THEN 1 END) AS rembourses,
        COALESCE(SUM(CASE WHEN statut='paye' AND date(date_paiement)=${auj} THEN montant ELSE 0 END),0) AS revenu_jour,
        COALESCE(SUM(CASE WHEN statut='paye' AND date_paiement>=${debutSemaine} THEN montant ELSE 0 END),0) AS revenu_semaine,
        COALESCE(SUM(CASE WHEN statut='paye' AND date_paiement>=${debutMois} THEN montant ELSE 0 END),0) AS revenu_mois
      FROM adhesion_paiements
    `).get();
    parDevise = await db.prepare(`
      SELECT devise, COALESCE(SUM(montant),0) AS total FROM adhesion_paiements WHERE statut='paye' GROUP BY devise
    `).all();
  } catch (_) {}

  // Billetterie + abonnements (wallet_transactions — ledger immuable, insert-only donc tout y est "réussi")
  let billetterie = { commission:0, revenu_organisateurs:0, nb:0, commission_jour:0, commission_semaine:0, commission_mois:0 };
  try {
    billetterie = await db.prepare(`
      SELECT
        COALESCE(SUM(platform_fee),0) AS commission,
        COALESCE(SUM(organizer_amount),0) AS revenu_organisateurs,
        COUNT(*) AS nb,
        COALESCE(SUM(CASE WHEN date(timestamp)=${auj} THEN platform_fee ELSE 0 END),0) AS commission_jour,
        COALESCE(SUM(CASE WHEN timestamp>=${debutSemaine} THEN platform_fee ELSE 0 END),0) AS commission_semaine,
        COALESCE(SUM(CASE WHEN timestamp>=${debutMois} THEN platform_fee ELSE 0 END),0) AS commission_mois
      FROM wallet_transactions
    `).get();
  } catch (_) {}

  // Solde des commissions Diaspo'Actif
  let wallet = { total_commissions: 0, total_transactions: 0 };
  try { wallet = await db.prepare("SELECT * FROM platform_wallet WHERE id=1").get() || wallet; } catch (_) {}

  const revenu_total = (boutique.revenu||0) + (adhesions.revenu||0) + (billetterie.revenu_organisateurs||0);
  const paiements_aujourdhui = (boutique.revenu_jour||0) + (adhesions.revenu_jour||0) + (billetterie.commission_jour||0);
  const paiements_semaine = (boutique.revenu_semaine||0) + (adhesions.revenu_semaine||0) + (billetterie.commission_semaine||0);
  const paiements_mois = (boutique.revenu_mois||0) + (adhesions.revenu_mois||0) + (billetterie.commission_mois||0);

  sendJSON(res, 200, {
    revenu_total,
    paiements_aujourdhui,
    paiements_semaine,
    paiements_mois,
    paiements_reussis: (boutique.reussis||0) + (adhesions.reussis||0) + (billetterie.nb||0),
    paiements_en_attente: (boutique.en_attente||0) + (adhesions.en_attente||0),
    paiements_refuses: (boutique.refuses||0) + (adhesions.refuses||0),
    remboursements: adhesions.rembourses||0,
    solde_commissions: wallet.total_commissions||0,
    par_devise: parDevise,
    detail: { boutique, adhesions, billetterie }
  });
});

