  /* Identité territoriale de la collectivité connectée (Registre unique). */
  route("GET", "/api/collectivite/identite", async (req, res) => {
    const user = await getCurrentUser(req);
    if (!user || user.role !== "collectivite") return sendJSON(res, 403, { error: "Réservé aux collectivités." });
    const coll = await db.prepare("SELECT * FROM users WHERE id=?").get(user.id);
    // Génère et persiste l'identifiant s'il n'existe pas encore.
    let identifiant = coll.identifiant_territorial;
    if (!identifiant) {
      identifiant = genererIdentifiantTerritorial(coll);
      db.prepare("UPDATE users SET identifiant_territorial=? WHERE id=?").run(identifiant, user.id);
      journalColl(user.id, "identifiant_genere", "Identifiant territorial attribué : " + identifiant);
    }
    // Administrateurs officiels : responsable principal + comptes rattachés (parent_institution_id).
    const rattaches = await db.prepare("SELECT id, nom, type_organisme, statut_etatique FROM users WHERE parent_institution_id=?").all(user.id);
    // Journal : événements enregistrés + jalons dérivés (création, validation).
    let journal = await db.prepare("SELECT action, detail, created_at FROM collectivite_journal WHERE collectivite_id=? ORDER BY id DESC").all(user.id);
    if (!journal.length) {
      journal = [{ action: "creation", detail: "Création du profil", created_at: coll.created_at }];
      if (coll.statut_etatique === "verifie" || coll.is_verified) journal.unshift({ action: "validation", detail: "Validation officielle", created_at: coll.created_at });
    }
    sendJSON(res, 200, {
      identifiant,
      nom: coll.nom,
      type_organisme: coll.type_organisme || coll.type_institution,
      localisation: [coll.ville_exercice || coll.ville, coll.pays_exercice || coll.pays].filter(Boolean).join(", "),
      verifiee: coll.statut_etatique === "verifie" || !!coll.is_verified,
      statut: coll.statut_etatique || (coll.is_verified ? "verifie" : "en_attente"),
      responsable: [coll.prenom_responsable_etatique, coll.nom_responsable_etatique].filter(Boolean).join(" ") || null,
      fonction_responsable: coll.fonction_responsable_etatique || null,
      site_officiel: coll.site_officiel || null,
      administrateurs: rattaches,
      journal,
    });
  });

  /* Détection de doublons avant création (recherche de collectivités similaires). */
  route("GET", "/api/collectivites/verifier-doublon", async (req, res, params, body, query) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    const nom = (query.nom || "").trim();
    const pays = (query.pays || "").trim();
    const ville = (query.ville || "").trim();
    if (!nom) return sendJSON(res, 400, { error: "Nom requis." });
    // On restreint la comparaison aux collectivités (même pays si fourni).
    let rows;
    if (pays) rows = await db.prepare("SELECT id, nom, type_organisme, type_institution, pays, ville, statut_etatique, is_verified, identifiant_territorial FROM users WHERE role='collectivite' AND LOWER(pays)=LOWER(?)").all(pays);
    else rows = await db.prepare("SELECT id, nom, type_organisme, type_institution, pays, ville, statut_etatique, is_verified, identifiant_territorial FROM users WHERE role='collectivite'").all();
    const matches = rows.map(r => {
      let sim = similariteChaine(nom, r.nom);
      if (ville && r.ville && sansAccents(ville.toLowerCase()) === sansAccents(r.ville.toLowerCase())) sim = Math.min(1, sim + 0.1);
      return { ...r, similarite: Math.round(sim * 100) };
    }).filter(r => r.id !== user.id && r.similarite >= 55)
      .sort((a, b) => b.similarite - a.similarite)
      .slice(0, 8);
    sendJSON(res, 200, { doublon_probable: matches.length > 0, matches });
  });

  route("POST", "/api/communications", async (req, res, params, body) => {
    const user = await getCurrentUser(req);
    if (!user || !["collectivite","administrateur"].includes(user.role)) return sendJSON(res, 403, { error: "Réservé aux collectivités et administrateurs." });
    const { titre, contenu, type, cible, photos_json, video_b64, audio_b64, liste_id } = body;
    if (!titre || !contenu) return sendJSON(res, 400, { error: "titre et contenu requis." });
    // Valider médias
    const photos = Array.isArray(photos_json) ? photos_json.slice(0, 4) : [];
    for (const p of photos) {
      if (typeof p !== "string" || !p.startsWith("data:image/")) return sendJSON(res, 400, { error: "Format photo invalide." });
    }
    if (video_b64 && !video_b64.startsWith("data:video/")) return sendJSON(res, 400, { error: "Format vidéo invalide." });
    if (audio_b64 && !audio_b64.startsWith("data:audio/")) return sendJSON(res, 400, { error: "Format audio invalide." });
    // Principe 4 : la diffusion est AUTOMATIQUEMENT limitée au périmètre de compétence.
    // Pas de ciblage individuel par nationalité/ville hors juridiction : le contenu
    // touche l'ensemble des membres du territoire. La cible envoyée par le client est
    // ignorée au profit du périmètre réel (on la remplace par le périmètre appliqué).
    let nb = 0;
    let perimetre = null;
    // Liste de diffusion optionnelle : restreint l'audience à une liste possédée par l'émetteur,
    // toujours intersectée avec le périmètre de compétence (jamais un élargissement, principe 4).
    let liste = null;
    if (liste_id) {
      liste = await db.prepare("SELECT id,nom FROM listes_diffusion WHERE id=? AND proprietaire_id=?").get(liste_id, user.id);
      if (!liste) return sendJSON(res, 404, { error: "Liste de diffusion introuvable." });
    }
    if (user.role === "collectivite") {
      const coll = await db.prepare("SELECT type_organisme,type_institution,pays_exercice,region_exercice,departement_exercice,ville_exercice,pays,region,departement,ville FROM users WHERE id=?").get(user.id);
      perimetre = getPerimetre(coll);
      const { where: pw, params: pp } = perimetreWhere(perimetre, "u");
      let sql = `SELECT COUNT(*) AS n FROM users u WHERE u.role IN ('utilisateur','initiative') AND (${pw})`;
      const args = [...pp];
      if (liste) { sql += ` AND u.id IN (SELECT user_id FROM listes_diffusion_contacts WHERE liste_id=? AND user_id IS NOT NULL)`; args.push(liste.id); }
      try { nb = (await db.prepare(sql).get(...args))?.n || 0; } catch(e) { nb = 0; }
    } else {
      // Administrateur : diffusion globale (optionnellement restreinte à une liste)
      let sql = `SELECT COUNT(*) AS n FROM users WHERE role IN ('utilisateur','initiative')`;
      const args = [];
      if (liste) { sql += ` AND id IN (SELECT user_id FROM listes_diffusion_contacts WHERE liste_id=? AND user_id IS NOT NULL)`; args.push(liste.id); }
      try { nb = (await db.prepare(sql).get(...args))?.n || 0; } catch(e) { nb = 0; }
    }
    // La cible stockée reflète le périmètre réellement appliqué (transparence).
    const cibleAppliquee = { ...(perimetre ? { perimetre, libelle: libellePerimetre(perimetre) } : { portee: "globale" }), ...(liste ? { liste_id: liste.id, liste_nom: liste.nom } : {}) };
    // Alter table si colonnes manquantes (migration SQLite)
    try {
      await db.prepare("ALTER TABLE communications_institutionnelles ADD COLUMN photos_json TEXT DEFAULT '[]'").run();
      await db.prepare("ALTER TABLE communications_institutionnelles ADD COLUMN video_b64 TEXT DEFAULT NULL").run();
      await db.prepare("ALTER TABLE communications_institutionnelles ADD COLUMN audio_b64 TEXT DEFAULT NULL").run();
    } catch(e) {} // colonnes déjà présentes
    const id = db.prepare(
      "INSERT INTO communications_institutionnelles (emetteur_id,titre,contenu,type,cible_json,nb_destinataires,photos_json,video_b64,audio_b64) VALUES (?,?,?,?,?,?,?,?,?)"
    ).run(user.id, titre, contenu, type||"info", JSON.stringify(cibleAppliquee), nb,
          JSON.stringify(photos), video_b64||null, audio_b64||null).lastInsertRowid;
    // Publication sur le fil (sans médias lourds)
    try {
      db.prepare("INSERT INTO fil_posts (auteur_id,auteur_nom,type,categorie,contenu) VALUES (?,?,?,?,?)")
        .run(user.id, user.nom, "institutionnel", type||"info", `**${titre}**\n\n${contenu}`);
    } catch(e) {}
    sendJSON(res, 201, { id, nb_destinataires: nb });
  });

  route("GET", "/api/communications", async (req, res) => {
    const user = await getCurrentUser(req);
    if (!user || !["collectivite","administrateur"].includes(user.role)) return sendJSON(res, 403, { error: "Réservé aux collectivités." });
    const rows = await db.prepare("SELECT id,emetteur_id,titre,contenu,type,cible_json,nb_destinataires,statut,photos_json,video_b64,audio_b64,created_at FROM communications_institutionnelles WHERE emetteur_id=? ORDER BY created_at DESC LIMIT 50").all(user.id);
    sendJSON(res, 200, { communications: rows.map(r => ({
      ...r,
      photos_json: (() => { try { return JSON.parse(r.photos_json||"[]"); } catch(e){ return []; } })()
    })) });
  });

  route("GET", "/api/communications/recues", async (req, res) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    // Toutes communications qui ne sont pas bloquées par l'utilisateur
    const desabo = (await db.prepare("SELECT institution_id FROM comm_desabonnements WHERE user_id=?").all(user.id)).map(r=>r.institution_id);
    let rows = await db.prepare(`
      SELECT ci.*, u.nom AS emetteur_nom, u.role AS emetteur_role,
             u.type_organisme, u.type_institution, u.pays_exercice, u.region_exercice,
             u.departement_exercice, u.ville_exercice, u.pays AS e_pays, u.region AS e_region,
             u.departement AS e_departement, u.ville AS e_ville
      FROM communications_institutionnelles ci JOIN users u ON u.id=ci.emetteur_id
      ORDER BY ci.created_at DESC LIMIT 100`).all();
    // Principe 4 : diffusion limitée à la juridiction de l'émetteur.
    // Les collectivités ne touchent que les membres de leur périmètre ; l'admin diffuse à tous.
    rows = rows.filter(r => {
      if (r.emetteur_role === "administrateur") return true;
      const coll = {
        type_organisme: r.type_organisme, type_institution: r.type_institution,
        pays_exercice: r.pays_exercice, region_exercice: r.region_exercice,
        departement_exercice: r.departement_exercice, ville_exercice: r.ville_exercice,
        pays: r.e_pays, region: r.e_region, departement: r.e_departement, ville: r.e_ville,
      };
      return membreDansPerimetre(coll, user);
    });
    if (desabo.length) rows = rows.filter(r => !desabo.includes(null) && !desabo.includes(r.emetteur_id));
    sendJSON(res, 200, { communications: rows.slice(0, 30) });
  });

  route("POST", "/api/communications/:id/desabonner", async (req, res, params) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    const comm = await db.prepare("SELECT emetteur_id FROM communications_institutionnelles WHERE id=?").get(params.id);
    if (!comm) return sendJSON(res, 404, { error: "Communication introuvable." });
    try {
      db.prepare("INSERT OR IGNORE INTO comm_desabonnements (user_id,institution_id) VALUES (?,?)").run(user.id, comm.emetteur_id);
    } catch(e) {}
    sendJSON(res, 200, { ok: true });
  });

  /* ===========================
     CONSULTATIONS ET SONDAGES
  =========================== */
  route("POST", "/api/consultations", async (req, res, params, body) => {
    const user = await getCurrentUser(req);
    if (!user || !["collectivite","administrateur"].includes(user.role)) return sendJSON(res, 403, { error: "Réservé aux collectivités." });
    const { titre, description, type, date_cloture, cible, questions, statut } = body;
    if (!titre) return sendJSON(res, 400, { error: "titre requis." });
    const id = db.prepare("INSERT INTO consultations (emetteur_id,titre,description,type,statut,date_cloture,cible_json) VALUES (?,?,?,?,?,?,?)")
      .run(user.id, titre, description||null, type||"sondage", statut||"ouverte", date_cloture||null, JSON.stringify(cible||{})).lastInsertRowid;
    if (questions?.length) {
      const ins = db.prepare("INSERT INTO consultation_questions (consultation_id,texte,type,options_json,ordre) VALUES (?,?,?,?,?)");
      questions.forEach((q, i) => ins.run(id, q.texte, q.type||"texte_libre", JSON.stringify(q.options||[]), i));
    }
    sendJSON(res, 201, { id });
  });

  route("GET", "/api/consultations", async (req, res) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    let rows;
    if (["collectivite","administrateur"].includes(user.role)) {
      rows = await db.prepare("SELECT c.*,(SELECT COUNT(*) FROM consultation_reponses WHERE consultation_id=c.id) AS nb_reponses FROM consultations c WHERE emetteur_id=? ORDER BY created_at DESC").all(user.id);
    } else {
      rows = await db.prepare(`
        SELECT c.*, u.nom AS emetteur_nom, u.role AS emetteur_role,
               u.type_organisme, u.type_institution, u.pays_exercice, u.region_exercice,
               u.departement_exercice, u.ville_exercice, u.pays AS e_pays, u.region AS e_region,
               u.departement AS e_departement, u.ville AS e_ville,
               (SELECT COUNT(*) FROM consultation_reponses WHERE consultation_id=c.id) AS nb_reponses
        FROM consultations c JOIN users u ON u.id=c.emetteur_id
        WHERE c.statut='ouverte' ORDER BY c.created_at DESC LIMIT 60`).all();
      // Principe 4 : un membre ne voit que les consultations émanant de collectivités dont il relève.
      rows = rows.filter(r => {
        if (r.emetteur_role === "administrateur") return true;
        const coll = {
          type_organisme: r.type_organisme, type_institution: r.type_institution,
          pays_exercice: r.pays_exercice, region_exercice: r.region_exercice,
          departement_exercice: r.departement_exercice, ville_exercice: r.ville_exercice,
          pays: r.e_pays, region: r.e_region, departement: r.e_departement, ville: r.e_ville,
        };
        return membreDansPerimetre(coll, user);
      }).slice(0, 20);
    }
    sendJSON(res, 200, { consultations: rows });
  });

  route("GET", "/api/consultations/:id", async (req, res, params) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    const c = await db.prepare("SELECT c.*,u.nom AS emetteur_nom FROM consultations c JOIN users u ON u.id=c.emetteur_id WHERE c.id=?").get(params.id);
    if (!c) return sendJSON(res, 404, { error: "Consultation introuvable." });
    const questions = await db.prepare("SELECT * FROM consultation_questions WHERE consultation_id=? ORDER BY ordre").all(params.id);
    const dejaRepondu = user ? !!await db.prepare("SELECT 1 FROM consultation_reponses WHERE consultation_id=? AND user_id=?").get(params.id, user.id) : false;
    sendJSON(res, 200, { consultation: c, questions, deja_repondu: dejaRepondu });
  });

  route("POST", "/api/consultations/:id/repondre", async (req, res, params, body) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    const c = await db.prepare("SELECT * FROM consultations WHERE id=? AND statut='ouverte'").get(params.id);
    if (!c) return sendJSON(res, 404, { error: "Consultation fermée ou introuvable." });
    const already = await db.prepare("SELECT 1 FROM consultation_reponses WHERE consultation_id=? AND user_id=?").get(params.id, user.id);
    if (already) return sendJSON(res, 409, { error: "Vous avez déjà répondu à cette consultation." });
    const ins = db.prepare("INSERT INTO consultation_reponses (consultation_id,question_id,user_id,reponse) VALUES (?,?,?,?)");
    (body.reponses || []).forEach(r => ins.run(params.id, r.question_id, user.id, r.reponse || ""));
    sendJSON(res, 200, { ok: true });
  });

  route("GET", "/api/consultations/:id/resultats", async (req, res, params) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    const c = await db.prepare("SELECT * FROM consultations WHERE id=?").get(params.id);
    if (!c) return sendJSON(res, 404, { error: "Consultation introuvable." });
    if (c.emetteur_id !== user.id && user.role !== "administrateur") return sendJSON(res, 403, { error: "Accès réservé à l'émetteur." });
    const questions = await db.prepare("SELECT * FROM consultation_questions WHERE consultation_id=? ORDER BY ordre").all(params.id);
    const nb_repondants = (await db.prepare("SELECT COUNT(DISTINCT user_id) AS n FROM consultation_reponses WHERE consultation_id=?").get(params.id))?.n;
    const resultats = await Promise.all(questions.map(async q => {
      const reps = await db.prepare("SELECT reponse, COUNT(*) AS n FROM consultation_reponses WHERE question_id=? GROUP BY reponse ORDER BY n DESC").all(q.id);
      return { question: q, nb_reponses: reps.reduce((a,r)=>a+r.n,0), repartition: reps };
    }));
    sendJSON(res, 200, { consultation: c, nb_repondants, resultats });
  });

  route("POST", "/api/consultations/:id/cloturer", async (req, res, params) => {
    const user = await getCurrentUser(req);
    if (!user) return sendJSON(res, 401, { error: "Connexion requise." });
    const c = await db.prepare("SELECT * FROM consultations WHERE id=?").get(params.id);
    if (!c) return sendJSON(res, 404, { error: "Introuvable." });
    if (c.emetteur_id !== user.id && user.role !== "administrateur") return sendJSON(res, 403, { error: "Non autorisé." });
    await db.prepare("UPDATE consultations SET statut='cloturee' WHERE id=?").run(params.id);
    sendJSON(res, 200, { ok: true });
  });

/* ============================================================
   MODULE AMBASSADE / COLLECTIVITÉ
   ============================================================ */

async function requireCollectivite(req, res) {
  const user = await getCurrentUser(req);
  if (!user) { sendJSON(res, 401, { error: "Connexion requise." }); return null; }
  if (user.role !== "collectivite") { sendJSON(res, 403, { error: "Réservé aux collectivités." }); return null; }
  return user;
}

/* ── Profil ambassade ── */
route("GET", "/api/collectivite/profil-ambassade", async (req, res) => {
  const user = requireCollectivite(req, res); if (!user) return;
  let profil = await db.prepare("SELECT * FROM ambassade_profil WHERE user_id=?").get(user.id);
  if (!profil) profil = { user_id: user.id, nom_officiel: user.nom || "", pays_represente: user.pays || "" };
  sendJSON(res, 200, profil);
});

route("PUT", "/api/collectivite/profil-ambassade", async (req, res, params, body) => {
  const user = requireCollectivite(req, res); if (!user) return;
  const j = v => { try { return JSON.stringify(Array.isArray(v) ? v : JSON.parse(v || "[]")); } catch { return "[]"; } };
  const exists = await db.prepare("SELECT user_id FROM ambassade_profil WHERE user_id=?").get(user.id);
  const data = {
    nom_officiel: body.nom_officiel || null,
    pays_represente: body.pays_represente || null,
    ambassadeur: body.ambassadeur || null,
    adresse: body.adresse || null,
    telephone: body.telephone || null,
    email_officiel: body.email_officiel || null,
    site_web: body.site_web || null,
    horaires: body.horaires || null,
    zone_pays: j(body.zone_pays),
    zone_regions: j(body.zone_regions),
    zone_villes: j(body.zone_villes),
    consulats: j(body.consulats),
    logo_url: body.logo_url || null,
    photo_couverture: body.photo_couverture || null,
    description: body.description || null,
  };
  if (exists) {
    db.prepare(`UPDATE ambassade_profil SET nom_officiel=?,pays_represente=?,ambassadeur=?,adresse=?,telephone=?,email_officiel=?,site_web=?,horaires=?,zone_pays=?,zone_regions=?,zone_villes=?,consulats=?,logo_url=?,photo_couverture=?,description=?,updated_at=datetime('now') WHERE user_id=?`).run(...Object.values(data), user.id);
  } else {
    db.prepare(`INSERT INTO ambassade_profil(nom_officiel,pays_represente,ambassadeur,adresse,telephone,email_officiel,site_web,horaires,zone_pays,zone_regions,zone_villes,consulats,logo_url,photo_couverture,description,user_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`).run(...Object.values(data), user.id);
  }
  sendJSON(res, 200, { ok: true });
});

/* ── Stats diaspora (agrégées, selon pays_represente) ── */
route("GET", "/api/collectivite/stats-diaspora", async (req, res) => {
  const user = requireCollectivite(req, res); if (!user) return;
  const profil = await db.prepare("SELECT * FROM ambassade_profil WHERE user_id=?").get(user.id);
  const pays = profil?.pays_represente || user.pays;
  const SEUIL = 10;
  const mask = n => n >= SEUIL ? n : null;
  const ressortissants = (await db.prepare("SELECT COUNT(*) AS n FROM users WHERE role='utilisateur' AND (nationalite1=? OR nationalite2=?)").get(pays, pays))?.n;
  const parVille = (await db.prepare("SELECT ville, COUNT(*) AS n FROM users WHERE role='utilisateur' AND ville IS NOT NULL AND (nationalite1=? OR nationalite2=?) GROUP BY ville ORDER BY n DESC LIMIT 20").all(pays, pays)).map(r=>({...r, n: mask(r.n)})).filter(r=>r.n);
  const parRegion = (await db.prepare("SELECT pays AS region, COUNT(*) AS n FROM users WHERE role='utilisateur' AND (nationalite1=? OR nationalite2=?) AND pays IS NOT NULL GROUP BY pays ORDER BY n DESC LIMIT 15").all(pays, pays)).map(r=>({...r, n: mask(r.n)})).filter(r=>r.n);
  const initiatives = (await db.prepare("SELECT COUNT(*) AS n FROM initiatives WHERE nationalite1=? OR nationalite2=?").get(pays, pays))?.n;
  const associations = (await db.prepare("SELECT COUNT(*) AS n FROM initiatives WHERE (nationalite1=? OR nationalite2=?) AND domaine='associatif'").get(pays, pays))?.n;
  const entreprises = (await db.prepare("SELECT COUNT(*) AS n FROM initiatives WHERE (nationalite1=? OR nationalite2=?) AND domaine IN ('commerce','finance','tech','industrie')").get(pays, pays))?.n;
  const experts = (await db.prepare("SELECT COUNT(*) AS n FROM users WHERE role='utilisateur' AND (nationalite1=? OR nationalite2=?) AND titre_pro IS NOT NULL").get(pays, pays))?.n;
  sendJSON(res, 200, {
    pays, seuil: SEUIL,
    ressortissants: mask(ressortissants),
    initiatives: mask(initiatives),
    associations: mask(associations),
    entreprises: mask(entreprises),
    experts: mask(experts),
    par_ville: parVille,
    par_region: parRegion,
  });
});

/* ── Espace Diaspora (initiatives filtrées) ── */
route("GET", "/api/collectivite/diaspora-membres", async (req, res, params, body, query) => {
  const user = requireCollectivite(req, res); if (!user) return;
  const profil = await db.prepare("SELECT * FROM ambassade_profil WHERE user_id=?").get(user.id);
  const pays = profil?.pays_represente || user.pays;
  const { ville, secteur, type } = query;
  let where = "(nationalite1=? OR nationalite2=?)"; const p = [pays, pays];
  if (ville) { where += " AND ville=?"; p.push(ville); }
  if (secteur) { where += " AND domaine=?"; p.push(secteur); }
  const rows = await db.prepare(`SELECT id,nom,domaine,ville,pays,logo_url,site_web,membres,abonnes,type_structure,nb_vues FROM initiatives WHERE ${where} ORDER BY membres DESC LIMIT 50`).all(...p);
  sendJSON(res, 200, { initiatives: rows, pays });
});

