/* ══ OBSERVATOIRE INSTITUTIONNEL (Admin) ══ */

route("GET", "/api/admin/observatoire-institutionnel", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });

  // Données réelles
  const allColl = await db.prepare("SELECT id, nom, prenom, type_organisme, pays, pays_exercice, statut_verification, nb_connexions, last_active, created_at FROM users WHERE role='collectivite'").all();
  const nbTotal  = allColl.length;
  const nbVerif  = allColl.filter(c => c.statut_verification === 'verifie').length;
  const nbActifs = allColl.filter(c => c.nb_connexions > 0).length;
  const nbInactifs = nbTotal - nbActifs;

  const evByOrg = await db.prepare("SELECT organisateur_id, COUNT(*) as n FROM events GROUP BY organisateur_id").all();
  const postsByUser = await db.prepare("SELECT auteur_id, COUNT(*) as n FROM fil_posts GROUP BY auteur_id").all();
  const recrutByUser = await db.prepare("SELECT recruteur_id, COUNT(*) as n FROM recrutement_campagnes GROUP BY recruteur_id").all();

  const evMap={}, postMap={}, recrutMap={};
  evByOrg.forEach(r => evMap[r.organisateur_id]=r.n);
  postsByUser.forEach(r => postMap[r.auteur_id]=r.n);
  recrutByUser.forEach(r => recrutMap[r.recruteur_id]=r.n);

  /* ── DONNÉES RÉELLES uniquement (aucune simulation) ── */
  // Répartition types
  const typeCount={};
  allColl.forEach(c => { const t=c.type_organisme||'Autre'; typeCount[t]=(typeCount[t]||0)+1; });
  const par_type = Object.entries(typeCount).map(([type,n])=>({type,n})).sort((a,b)=>b.n-a.n);

  // Répartition pays
  const paysCount={};
  allColl.forEach(c => { const p=c.pays||c.pays_exercice||'Inconnu'; paysCount[p]=(paysCount[p]||0)+1; });
  const par_pays = Object.entries(paysCount).map(([pays,n])=>({pays,n})).sort((a,b)=>b.n-a.n);

  // Institutions : uniquement des indicateurs réels (aucun enrichissement inventé).
  const institutions = allColl.map((c) => ({
    id: c.id,
    nom: c.nom,
    type: c.type_organisme||'Institution',
    pays: c.pays||c.pays_exercice||'—',
    statut: c.statut_verification,
    connexions: c.nb_connexions||0,
    events: evMap[c.id]||0,
    publications: postMap[c.id]||0,
    recrutements: recrutMap[c.id]||0,
    abonnes: 0, vues_profil: 0, sondages: 0, deals: 0, partenariats: 0,
    reactions: 0, commentaires: 0, repub: 0,
    taux_engagement: 0, evol_abonnes: 0, score: 0
  }));

  // Classements (sur données réelles disponibles)
  const top_actives      = [...institutions].sort((a,b)=>b.connexions-a.connexions).slice(0,10);
  const top_communicantes= [...institutions].sort((a,b)=>(b.publications+b.events+b.recrutements)-(a.publications+a.events+a.recrutements)).slice(0,10);
  const top_consultees   = [];
  const top_suivies      = [];
  const top_reactives    = [];

  // Communications : totaux réels ; réactions/commentaires non ventilés par institution → 0 ; thèmes vides.
  const comms = {
    total_publications: institutions.reduce((s,i)=>s+i.publications,0),
    total_events: institutions.reduce((s,i)=>s+i.events,0),
    total_reactions: 0,
    total_commentaires: 0,
    total_repub: 0,
    themes: []
  };

  const sondages = { total: 0, taux_participation_moy: 0, themes_pop: [], nb_reponses_moy: 0, evol: 0 };

  const events_stats = {
    total: institutions.reduce((s,i)=>s+i.events,0),
    participants_total: 0, taux_presence: 0, taux_remplissage: 0, engagement: 0
  };

  const recruit_stats = {
    campagnes: institutions.reduce((s,i)=>s+i.recrutements,0),
    candidatures: 0, recrutements: 0, taux_reussite: 0
  };

  const coop_stats = { deals: 0, partenariats_national: 0, partenariats_intl: 0, projets_cours: 0, projets_realises: 0, top_coop: [] };

  const indices = { ici: 0, iei: 0, ico: 0, iri: 0, iii: 0, igpi: 0 };

  const ai = { dynamiques: [], progression: [], domaines: [], emergents: [], meilleures_pratiques: [] };

  sendJSON(res, 200, {
    overview: { nbTotal, nbVerif, nbActifs, nbInactifs, par_type, par_pays, continents:[
      { continent:"Europe", n:allColl.filter(c=>(c.pays||'').match(/France|Belgique|Suisse|Allemagne|Italie|Espagne|UK/)).length },
      { continent:"Afrique", n:allColl.filter(c=>(c.pays||'').match(/Sénégal|Côte d'Ivoire|Cameroun|Mali|Maroc/)).length },
      { continent:"Amériques", n:allColl.filter(c=>(c.pays||'').match(/Canada|USA|Haïti/)).length },
      { continent:"Asie-Océanie", n:0 },
    ]},
    classements: { top_actives, top_communicantes, top_consultees, top_suivies, top_reactives },
    comms, sondages, events_stats, recruit_stats, coop_stats, indices, ai,
    institutions // liste complète pour comparaisons
  });
});

/* Export données admin (téléchargement) */
route("GET", "/api/admin/export-data", async (req, res) => {
  const user = await getCurrentUser(req);
  if (!user || user.role !== "administrateur") return sendJSON(res, 403, { error: "Réservé." });
  const url = new URL("http://x" + req.url);
  const module = url.searchParams.get("module") || "all";
  const format = url.searchParams.get("format") || "json";

  // Données agrégées anonymisées uniquement
  const stats = {
    export_date: new Date().toISOString(),
    module,
    platform: "Diaspo'Actif",
    users: { total: (await db.prepare("SELECT COUNT(*) as n FROM users").get())?.n },
    initiatives: { total: (await db.prepare("SELECT COUNT(*) as n FROM initiatives").get())?.n },
    events: { total: (await db.prepare("SELECT COUNT(*) as n FROM events").get())?.n },
    collectivites: { total: (await db.prepare("SELECT COUNT(*) as n FROM users WHERE role='collectivite'").get())?.n },
    publications: { total: (await db.prepare("SELECT COUNT(*) as n FROM fil_posts").get())?.n },
    recrutements: { total: (await db.prepare("SELECT COUNT(*) as n FROM recrutement_campagnes").get())?.n },
    projets: { total: (await db.prepare("SELECT COUNT(*) as n FROM projets").get())?.n },
    deals: { total: (await db.prepare("SELECT COUNT(*) as n FROM deals").get())?.n },
    note: "Données agrégées et anonymisées - Diaspo'Actif"
  };

  if (format === "csv") {
    const csv = Object.entries(stats).filter(([k])=>k!=='note').map(([k,v])=>`${k},${typeof v==='object'?v.total||JSON.stringify(v):v}`).join("\n");
    res.setHeader ? res.setHeader("Content-Type","text/csv") : null;
    res.writeHead(200, {"Content-Type":"text/csv","Content-Disposition":`attachment; filename="diaspoactif-export-${Date.now()}.csv"`});
    res.end("Indicateur,Valeur\n" + csv);
    return;
  }
  sendJSON(res, 200, stats);
});

